// =====================================================================
// SECTION 3: RBAC — getAllowedMenus(user)
// คืนค่า { dashboards: [keys], manage: [keys] } ตาม role + department
// =====================================================================
function mergeCustomPermissions(base, user) {
  const extra = { dashboards: user._extraDashboards || [], manage: user._extraManage || [] };
  if (!extra.dashboards.length && !extra.manage.length) return base;
  return {
    dashboards: [...new Set([...base.dashboards, ...extra.dashboards])],
    manage:     [...new Set([...base.manage,     ...extra.manage])],
  };
}

function getAllowedMenus(user) {
  if (!user) return { dashboards: [], manage: [] };
  const base = _getAllowedMenusBase(user);
  return mergeCustomPermissions(base, user);
}

function _getAllowedMenusBase(user) {
  const { role } = user;
  // admin: สิทธิ์เต็มทุกอย่าง
  if (role === 'admin') {
    return {
      dashboards: DASHBOARD_MENUS.map(m => m.key),
      manage: MANAGE_MENUS.map(m => m.key),
    };
  }
  // managing_md: ดูได้ทุก dashboard (ไม่มี manage) — system role ตายตัว
  if (role === 'managing_md') {
    return { dashboards: DASHBOARD_MENUS.map(m => m.key), manage: [] };
  }
  // role อื่นทั้งหมด: ไม่มีสิทธิ์เริ่มต้น — ใช้ role_permissions + user_permissions ที่โหลดมาตอน login
  return { dashboards: [], manage: [] };
}

function menuLabel(key, list) {
  const found = list.find(m => m.key === key);
  return found ? found.label : key;
}
function menuIcon(key, list) {
  const found = list.find(m => m.key === key);
  return found ? found.icon : 'circle';
}

// =====================================================================
// SECTION 4: UTILS
// =====================================================================
function fmtNum(n, decimals = 2) {
  if (n === null || n === undefined || isNaN(n)) return '0';
  return Number(n).toLocaleString('th-TH', { minimumFractionDigits: 0, maximumFractionDigits: decimals });
}
function fmtDate(d) {
  if (!d) return '-';
  try {
    return new Date(d).toLocaleDateString('th-TH', { year:'numeric', month:'short', day:'numeric' });
  } catch(e) { return d; }
}
function pad2(n) { return String(n).padStart(2,'0'); }
function monthNameTH(m) {
  const names = ['มกราคม','กุมภาพันธ์','มีนาคม','เมษายน','พฤษภาคม','มิถุนายน','กรกฎาคม','สิงหาคม','กันยายน','ตุลาคม','พฤศจิกายน','ธันวาคม'];
  return names[m-1] || '-';
}
function escapeHtml(str) {
  if (str === null || str === undefined) return '';
  return String(str).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}
function qs(sel, parent) { return (parent||document).querySelector(sel); }
function qsa(sel, parent) { return Array.from((parent||document).querySelectorAll(sel)); }

// แปลงชื่อโรงงานให้เป็นรูปแบบมาตรฐานไม่มีเว้นวรรค ('Sanon 1' -> 'Sanon1') ตรงกับ
// ค่าที่ schema.sql check constraint ของ factory_name อนุญาต ('CDE','Propel','Sanon1','Sanon2')
function normalizeFactoryName(name) {
  if (!name) return null;
  const n = String(name).trim();
  const map = { 'Sanon 1': 'Sanon1', 'Sanon 2': 'Sanon2', 'sanon 1': 'Sanon1', 'sanon 2': 'Sanon2' };
  if (map[n]) return map[n];
  // กรณีพิมพ์มาแบบไม่มีเว้นวรรคอยู่แล้ว หรือเป็น CDE/Propel
  const lower = n.toLowerCase().replace(/\s+/g, '');
  if (lower === 'sanon1') return 'Sanon1';
  if (lower === 'sanon2') return 'Sanon2';
  if (lower === 'cde') return 'CDE';
  if (lower === 'propel') return 'Propel';
  return n;
}
// หา factory record จาก factory_name (ที่ผู้ใช้กรอกมาในไฟล์ Excel เช่น CDE/Propel/Sanon1/Sanon2)
// โดยเทียบกับ factories.name ในระบบที่อาจเก็บเป็น 'Sanon 1'/'Sanon 2' (มีเว้นวรรค)
function findFactoryByName(factoriesList, inputName) {
  const norm = normalizeFactoryName(inputName);
  if (!norm) return null;
  return (factoriesList || []).find(f => normalizeFactoryName(f.name) === norm) || null;
}

function refreshIcons() {
  if (window.lucide) window.lucide.createIcons();
}

// =====================================================================
// SECTION 5: TOAST NOTIFICATION (custom, ไม่ใช้ library)
// =====================================================================
function showToast(message, type = 'info', duration = 3500) {
  const container = document.getElementById('toast-container');
  const id = 'toast-' + Date.now() + Math.random().toString(36).slice(2,7);
  const colors = {
    success: { bg:'bg-emerald-50', border:'border-emerald-200', text:'text-emerald-700', icon:'check-circle-2' },
    error:   { bg:'bg-red-50',     border:'border-red-200',     text:'text-red-700',     icon:'x-circle' },
    info:    { bg:'bg-indigo-50',  border:'border-indigo-200',  text:'text-indigo-700',  icon:'info' },
    warning: { bg:'bg-amber-50',   border:'border-amber-200',   text:'text-amber-700',   icon:'alert-triangle' },
  };
  const c = colors[type] || colors.info;
  const el = document.createElement('div');
  el.id = id;
  el.className = `toast-enter ${c.bg} ${c.border} ${c.text} border rounded-2xl shadow-lg px-4 py-3 flex items-center gap-2 min-w-[260px] max-w-sm`;
  el.innerHTML = `<i data-lucide="${c.icon}" class="w-5 h-5 flex-shrink-0"></i><span class="text-sm flex-1">${escapeHtml(message)}</span>
    <button class="opacity-50 hover:opacity-100 flex-shrink-0" onclick="document.getElementById('${id}').remove()"><i data-lucide="x" class="w-4 h-4"></i></button>`;
  container.appendChild(el);
  refreshIcons();
  setTimeout(() => { const node = document.getElementById(id); if (node) node.remove(); }, duration);
}

// =====================================================================
// SECTION 6: MODAL DIALOG (reusable)
// =====================================================================
function showModal({ title, bodyHtml, confirmText = 'ยืนยัน', cancelText = 'ยกเลิก', onConfirm = null, hideCancel = false, hideConfirm = false, wide = false }) {
  const root = document.getElementById('modal-root');
  root.innerHTML = `
    <div class="fixed inset-0 z-[9000] flex items-center justify-center p-4 modal-backdrop fade-in" id="modal-backdrop">
      <div class="bg-white rounded-2xl shadow-2xl w-full ${wide ? 'max-w-2xl' : 'max-w-md'} overflow-hidden fade-in">
        <div class="px-5 py-4 border-b border-secondary-100 flex items-center justify-between">
          <h3 class="font-semibold text-secondary-800">${escapeHtml(title)}</h3>
          <button id="modal-close-x" class="text-secondary-400 hover:text-secondary-700"><i data-lucide="x" class="w-5 h-5"></i></button>
        </div>
        <div class="px-5 py-4 text-sm text-secondary-600">${bodyHtml}</div>
        <div class="px-5 py-3 bg-secondary-50 flex justify-end gap-2">
          ${hideCancel ? '' : `<button id="modal-cancel-btn" class="px-4 py-2 rounded-xl text-sm font-medium text-secondary-600 hover:bg-secondary-100 transition">${escapeHtml(cancelText)}</button>`}
          ${hideConfirm ? '' : `<button id="modal-confirm-btn" class="px-4 py-2 rounded-xl text-sm font-medium bg-primary-600 text-white hover:bg-primary-700 transition">${escapeHtml(confirmText)}</button>`}
        </div>
      </div>
    </div>`;
  refreshIcons();
  const close = () => { root.innerHTML = ''; };
  qs('#modal-close-x', root).addEventListener('click', close);
  const cancelBtn = qs('#modal-cancel-btn', root);
  if (cancelBtn) cancelBtn.addEventListener('click', close);
  const confirmBtn = qs('#modal-confirm-btn', root);
  if (confirmBtn) confirmBtn.addEventListener('click', () => { if (onConfirm) onConfirm(); close(); });
  qs('#modal-backdrop', root).addEventListener('click', (e) => { if (e.target.id === 'modal-backdrop') close(); });
}
function closeModal() { document.getElementById('modal-root').innerHTML = ''; }

// =====================================================================
// SECTION 7: AUTH (custom, query ตรง app_users — ไม่ใช้ Supabase Auth)
// =====================================================================
async function doLogin(username, password) {
  const loginBtn = document.getElementById('login-submit-btn');
  const errBox = document.getElementById('login-error');
  if (errBox) errBox.classList.add('hidden');
  if (!username || !password) {
    if (errBox) { errBox.textContent = 'กรุณากรอกชื่อผู้ใช้และรหัสผ่าน'; errBox.classList.remove('hidden'); }
    return;
  }
  if (loginBtn) {
    loginBtn.disabled = true;
    loginBtn.innerHTML = `<i data-lucide="loader-2" class="w-4 h-4 animate-spin"></i><span>กำลังเข้าสู่ระบบ...</span>`;
    refreshIcons();
  }
  try {
    const { data, error } = await db
      .from('app_users')
      .select('*')
      .eq('username', username)
      .eq('password', password)
      .maybeSingle();

    if (error) throw error;

    if (!data) {
      if (errBox) { errBox.textContent = 'ชื่อผู้ใช้หรือรหัสผ่านไม่ถูกต้อง'; errBox.classList.remove('hidden'); }
      return;
    }
    if (data.status !== 'active') {
      const msg = data.status === 'pending' ? 'บัญชีนี้รออนุมัติ กรุณาติดต่อผู้ดูแลระบบ'
                : data.status === 'rejected' ? 'บัญชีนี้ถูกปฏิเสธการใช้งาน'
                : 'บัญชีนี้ถูกระงับการใช้งาน';
      if (errBox) { errBox.textContent = msg; errBox.classList.remove('hidden'); }
      return;
    }

    currentUser = data;
    // โหลด role-level permissions (default) + user-specific overrides แล้ว merge กัน
    try {
      const [permRes, rolePermRes] = await Promise.all([
        db.from('user_permissions').select('extra_dashboards, extra_manage').eq('user_id', data.id).maybeSingle(),
        db.from('role_permissions').select('extra_dashboards, extra_manage').eq('role_name', data.role).maybeSingle(),
      ]);
      const userDash    = (permRes.data    && permRes.data.extra_dashboards)    || [];
      const userManage  = (permRes.data    && permRes.data.extra_manage)        || [];
      const roleDash    = (rolePermRes.data && rolePermRes.data.extra_dashboards) || [];
      const roleManage  = (rolePermRes.data && rolePermRes.data.extra_manage)    || [];
      // role = base, user = override (union) → user สามารถมีสิทธิ์เพิ่มเติมจาก role
      currentUser._extraDashboards = [...new Set([...roleDash, ...userDash])];
      currentUser._extraManage     = [...new Set([...roleManage, ...userManage])];
    } catch (_) {
      currentUser._extraDashboards = [];
      currentUser._extraManage = [];
    }
    closeModal();
    showToast(`ยินดีต้อนรับ ${data.full_name || data.username}`, 'success');
    await fetchPendingApprovalCount();
    navigateTo(defaultPageForUser(currentUser));
    startSessionTimer();
    startApprovalCountPolling();
    try { sessionStorage.setItem('_sn_sess', JSON.stringify({ user: currentUser, page: defaultPageForUser(currentUser), loginAt: Date.now() })); } catch (_) {}
  } catch (err) {
    console.error(err);
    if (errBox) { errBox.textContent = 'เกิดข้อผิดพลาดในการเชื่อมต่อระบบ กรุณาลองใหม่'; errBox.classList.remove('hidden'); }
  } finally {
    if (loginBtn) {
      loginBtn.disabled = false;
      loginBtn.innerHTML = `<i data-lucide="log-in" class="w-4 h-4"></i><span>เข้าสู่ระบบ</span>`;
      refreshIcons();
    }
  }
}

function defaultPageForUser(user) {
  const allowed = getAllowedMenus(user);
  return allowed.dashboards.length > 0 ? allowed.dashboards[0] : 'landing';
}

function confirmLogout() {
  showModal({
    title: 'ออกจากระบบ',
    bodyHtml: 'คุณต้องการออกจากระบบใช่หรือไม่?',
    confirmText: 'ออกจากระบบ',
    cancelText: 'ยกเลิก',
    onConfirm: doLogout,
  });
}
function doLogout() {
  stopSessionTimer();
  stopApprovalCountPolling();
  currentUser = null;
  pendingApprovalCount = 0;
  isMobileSheetOpen = false;
  isManageSheetOpen = false;
  try { sessionStorage.removeItem('_sn_sess'); } catch (_) {}
  showToast('ออกจากระบบเรียบร้อย', 'info');
  navigateTo('landing');
}

// =====================================================================
// SECTION 7C: SESSION TIMEOUT (2 ชั่วโมง, ยกเว้น role admin)
// =====================================================================
const SESSION_TIMEOUT_SECONDS = 7200; // 2 ชั่วโมง
const SESSION_WARNING_AT_SECONDS = 60; // เตือนเมื่อเหลือ 60 วินาที

function startSessionTimer(initialSeconds) {
  stopSessionTimer();
  if (!currentUser || currentUser.role === 'admin') {
    updateSessionTimerDisplay();
    return; // admin ไม่จำกัดเวลา ไม่ต้องนับถอยหลัง
  }
  sessionSecondsLeft = (initialSeconds && initialSeconds > 0) ? initialSeconds : SESSION_TIMEOUT_SECONDS;
  sessionWarnShown = false;
  updateSessionTimerDisplay();
  sessionTimerInterval = setInterval(() => {
    sessionSecondsLeft -= 1;
    if (sessionSecondsLeft === SESSION_WARNING_AT_SECONDS && !sessionWarnShown) {
      sessionWarnShown = true;
      showToast('เซสชันจะหมดอายุในอีก 1 นาที กรุณาบันทึกข้อมูลที่ทำอยู่', 'warning', 6000);
    }
    if (sessionSecondsLeft <= 0) {
      handleSessionExpired();
      return;
    }
    updateSessionTimerDisplay();
  }, 1000);
}

function stopSessionTimer() {
  if (sessionTimerInterval) {
    clearInterval(sessionTimerInterval);
    sessionTimerInterval = null;
  }
  sessionSecondsLeft = 0;
  sessionWarnShown = false;
}

function updateSessionTimerDisplay() {
  const el = document.getElementById('session-countdown');
  if (!el) return;
  if (!currentUser || currentUser.role === 'admin') {
    el.classList.add('hidden');
    el.textContent = '';
    return;
  }
  el.classList.remove('hidden');
  const h = Math.floor(sessionSecondsLeft / 3600);
  const m = Math.floor((sessionSecondsLeft % 3600) / 60);
  el.textContent = `${pad2(h)}:${pad2(m)}`;
}

async function handleSessionExpired() {
  clearInterval(sessionTimerInterval);
  sessionTimerInterval = null;
  let savedSomething = false;
  try {
    savedSomething = await trySaveActiveForm();
  } catch (err) {
    console.error('trySaveActiveForm error', err);
    savedSomething = false;
  }
  stopApprovalCountPolling();
  currentUser = null;
  pendingApprovalCount = 0;
  isMobileSheetOpen = false;
  isManageSheetOpen = false;
  sessionSecondsLeft = 0;
  sessionWarnShown = false;
  try { sessionStorage.removeItem('_sn_sess'); } catch (_) {}
  showToast(
    savedSomething
      ? 'เซสชันหมดอายุ ระบบบันทึกข้อมูลที่ค้างไว้แล้ว (ถ้ามี) กรุณาเข้าสู่ระบบใหม่'
      : 'เซสชันหมดอายุ กรุณาเข้าสู่ระบบใหม่',
    'warning', 6000
  );
  navigateTo('landing');
}

// พยายาม auto-save ฟอร์มที่กำลังกรอกอยู่ใน DOM ก่อน logout เนื่องจาก session timeout
// รองรับฟอร์มยอดผลิต (manage-prod-*) ซึ่งเป็นฟอร์มหลักที่ mount อยู่ในหน้า page-content โดยตรง
// บันทึกด้วย status='pending' เสมอ (บันทึกฉุกเฉิน ไม่ว่า role ใด)
async function trySaveActiveForm() {
  // หาฟอร์มยอดผลิตที่ mount อยู่บนหน้าปัจจุบัน (manage-prod-cde/propel/sanon1/sanon2)
  for (const plantKey of Object.keys(PRODUCTION_PLANT_CONFIG)) {
    const form = document.getElementById(`mp-${plantKey}-form`);
    if (!form || !document.body.contains(form)) continue;
    const dateInput = document.getElementById('pf-date');
    if (!dateInput || !dateInput.value) continue; // required field ว่าง ไม่ save

    const cfg = PRODUCTION_PLANT_CONFIG[plantKey];
    const payload = {
      production_date: dateInput.value,
      raw_material: (document.getElementById('pf-rawmat')?.value || '').trim() || null,
      start_hour: numOrNull(document.getElementById('pf-start-hour')?.value),
      start_minute: numOrNull(document.getElementById('pf-start-minute')?.value),
      stop_hour: numOrNull(document.getElementById('pf-stop-hour')?.value),
      stop_minute: numOrNull(document.getElementById('pf-stop-minute')?.value),
      feed_ton: numOrNull(document.getElementById('pf-feed-ton')?.value),
      breakdown_detail: (document.getElementById('pf-breakdown')?.value || '').trim() || null,
      note: (document.getElementById('pf-note')?.value || '').trim() || null,
    };
    cfg.productColumns.forEach(c => {
      payload[c.key] = numOrNull(document.getElementById(`pf-prod-${c.key}`)?.value);
    });
    payload.status = 'pending'; // บันทึกฉุกเฉินจาก session timeout เสมอเป็น pending
    payload.created_by = currentUser ? currentUser.id : null;

    try {
      const { error } = await db.from(cfg.table).insert([payload]);
      if (error) throw error;
      return true;
    } catch (err) {
      console.error('trySaveActiveForm insert error', err);
      return false;
    }
  }
  return false;
}

// =====================================================================
// SECTION 8: PENDING APPROVAL COUNT (ข้อมูลจริง รวม 4 ตาราง production_*)
// =====================================================================
// คืนรายชื่อ department ที่ user คนนี้มีสิทธิ์อนุมัติ (admin = null หมายถึงทุกแผนก)
function approvalDepartmentsForUser(user) {
  if (!user) return [];
  if (user.role === 'admin') return null; // null = ไม่กรอง เห็นทุกแผนก
  if (user.role === 'manager' || user.role === 'supervisor') {
    if (user.department === 'CDE' || user.department === 'Propel') return ['CDE','Propel'];
    if (user.department === 'Sanon1' || user.department === 'Sanon2') return ['Sanon1','Sanon2'];
    return [];
  }
  return [];
}

async function fetchPendingApprovalCount() {
  if (!currentUser) { pendingApprovalCount = 0; return; }
  try {
    const depts = approvalDepartmentsForUser(currentUser);
    const prodTables = [
      { table: 'production_cde', dept: 'CDE' },
      { table: 'production_propel', dept: 'Propel' },
      { table: 'production_sanon1', dept: 'Sanon1' },
      { table: 'production_sanon2', dept: 'Sanon2' },
    ].filter(t => !depts || depts.includes(t.dept));
    const prodCounts = await Promise.all(prodTables.map(t =>
      db.from(t.table).select('id', { count: 'exact', head: true }).eq('status', 'pending')
    ));
    let total = prodCounts.reduce((sum, r) => sum + (r.count || 0), 0);

    // รถตักไฟฟ้า: มีคอลัมน์ factory_name ตรงๆ กรองได้ทันที
    let loaderQuery = db.from('electric_loader').select('id', { count: 'exact', head: true }).eq('status', 'pending');
    if (depts) loaderQuery = loaderQuery.in('factory_name', depts);
    const loaderRes = await loaderQuery;
    total += (loaderRes.count || 0);

    // น้ำบาดาล: ไม่มีคอลัมน์ factory_name ตรง มีแค่ factory_id (FK) — กรองโดยหา factory ids ที่ตรงแผนกก่อน
    if (depts) {
      const { data: deptFactories } = await db.from('factories').select('id, name');
      const matchIds = (deptFactories || [])
        .filter(f => depts.some(d => normalizeFactoryName(f.name) === d))
        .map(f => f.id);
      if (matchIds.length) {
        const { count } = await db.from('groundwater_usage').select('id', { count: 'exact', head: true }).eq('status', 'pending').in('factory_id', matchIds);
        total += (count || 0);
      }
    } else {
      const { count } = await db.from('groundwater_usage').select('id', { count: 'exact', head: true }).eq('status', 'pending');
      total += (count || 0);
    }

    pendingApprovalCount = total;
  } catch (err) {
    console.error('fetchPendingApprovalCount error', err);
    pendingApprovalCount = 0;
  }
  const _cnt = pendingApprovalCount > 99 ? '99+' : pendingApprovalCount;
  const badge = document.getElementById('approval-badge');
  if (badge) {
    if (pendingApprovalCount > 0) { badge.textContent = _cnt; badge.classList.remove('hidden'); }
    else { badge.classList.add('hidden'); }
  }
  const sbBadge = document.getElementById('sidebar-approval-badge');
  if (sbBadge) {
    if (pendingApprovalCount > 0) { sbBadge.textContent = _cnt; sbBadge.classList.remove('hidden'); }
    else { sbBadge.classList.add('hidden'); }
  }
}

function startApprovalCountPolling() {
  stopApprovalCountPolling();
  if (!currentUser) return;
  approvalCountInterval = setInterval(async () => {
    if (!currentUser) { stopApprovalCountPolling(); return; }
    await fetchPendingApprovalCount();
  }, 5000);
}
function stopApprovalCountPolling() {
  if (approvalCountInterval) { clearInterval(approvalCountInterval); approvalCountInterval = null; }
}

// =====================================================================
// SECTION 9: ROUTER
// เพิ่ม dashboard ใหม่: เพิ่ม case ใน renderPageContent() + เพิ่ม entry ใน DASHBOARD_MENUS
// หมวดหมู่ 2 (จัดการข้อมูล) ครบ 13 เมนูแล้ว — ดู case 'manage-*' ด้านล่าง
// =====================================================================
function navigateTo(pageKey, forceFullRender) {
  // guard: ถ้ายังไม่ login และพยายามเข้าหน้าอื่นที่ไม่ใช่ landing → กลับ landing
  if (!currentUser && pageKey !== 'landing') {
    pageKey = 'landing';
  }
  // guard RBAC: ตรวจว่า user มีสิทธิ์เข้า pageKey หรือไม่ (หน้า dashboard และหน้า manage)
  if (currentUser && pageKey.startsWith('dash-')) {
    const allowed = getAllowedMenus(currentUser);
    if (!allowed.dashboards.includes(pageKey)) {
      pageKey = defaultPageForUser(currentUser);
    }
  }
  if (currentUser && pageKey.startsWith('manage-')) {
    const allowed = getAllowedMenus(currentUser);
    if (!allowed.manage.includes(pageKey)) {
      pageKey = defaultPageForUser(currentUser);
    }
  }
  currentPage = pageKey;
  isMobileSheetOpen = false;
  isManageSheetOpen = false;
  if (pageKey !== 'landing') {
    try {
      const _ss = sessionStorage.getItem('_sn_sess');
      if (_ss) { const _sd = JSON.parse(_ss); _sd.page = pageKey; sessionStorage.setItem('_sn_sess', JSON.stringify(_sd)); }
    } catch (_) {}
  }

  // Soft navigate: ถ้า shell render แล้วและไม่ได้ force full render
  // → swap เฉพาะ page-content + อัปเดต active class ไม่ rebuild ทั้งหน้า (ไม่เด่งกลับบน)
  const pageContentEl = document.getElementById('page-content');
  if (!forceFullRender && currentUser && pageContentEl) {
    // อัปเดต active state ของ nav-link ทุกปุ่มใน sidebar/bottomnav
    qsa('.nav-link').forEach(btn => {
      const k = btn.getAttribute('data-nav');
      if (k === pageKey) {
        btn.classList.add('nav-active');
      } else {
        btn.classList.remove('nav-active');
      }
    });
    renderPageContent(pageKey);
    return;
  }

  render();
}

function render() {
  const app = document.getElementById('app');
  if (!currentUser) {
    app.innerHTML = renderLanding();
    refreshIcons();
    attachLandingEvents();
    loadLandingPublicStats();
    return;
  }
  app.innerHTML = renderAppShell();
  refreshIcons();
  attachShellEvents();
  updateSessionTimerDisplay();
  renderPageContent(currentPage);
}

function renderPageContent(pageKey) {
  const container = document.getElementById('page-content');
  if (!container) return;
  switch (pageKey) {
    case 'dash-cde':
      renderDashboardCdePropel(container, 'cde');
      break;
    case 'dash-propel':
      renderDashboardCdePropel(container, 'propel');
      break;
    case 'dash-sanon1':
      renderDashboardSanon(container, 'sanon1');
      break;
    case 'dash-sanon2':
      renderDashboardSanon(container, 'sanon2');
      break;
    case 'dash-drone':
      renderDashboardDrone(container);
      break;
    case 'dash-sales':
      renderDashboardSales(container);
      break;
    case 'dash-loader':
      renderDashboardLoader(container);
      break;
    case 'dash-water':
      renderDashboardWater(container);
      break;
    // ===========================================================
    // หมวดหมู่ 2: จัดการข้อมูล (13 เมนู)
    // ===========================================================
    case 'manage-materials':
      renderManageMaterials(container);
      break;
    case 'manage-reports':
      renderManageReports(container);
      break;
    case 'manage-users':
      renderManageUsers(container);
      break;
    case 'manage-factories':
      renderManageFactories(container);
      break;
    case 'manage-machines':
      renderManageMachines(container);
      break;
    case 'manage-water-sources':
      renderManageWaterSources(container);
      break;
    case 'manage-drone-stock':
      renderManageDroneStock(container);
      break;
    case 'manage-prod-cde':
      renderManageProduction(container, 'cde');
      break;
    case 'manage-prod-propel':
      renderManageProduction(container, 'propel');
      break;
    case 'manage-prod-sanon1':
      renderManageProduction(container, 'sanon1');
      break;
    case 'manage-prod-sanon2':
      renderManageProduction(container, 'sanon2');
      break;
    case 'manage-electric-loader':
      renderManageElectricLoader(container);
      break;
    case 'manage-sales':
      renderManageSales(container);
      break;
    case 'manage-groundwater':
      renderManageGroundwater(container);
      break;
    case 'manage-approvals':
      renderManageApprovals(container);
      break;
    case 'manage-settings':
      renderManageSettings(container);
      break;
    default: {
      const fallback = defaultPageForUser(currentUser);
      if (fallback !== pageKey) { navigateTo(fallback); return; }
      container.innerHTML = `<div class="p-8 text-center text-secondary-400">ไม่พบหน้านี้</div>`;
    }
  }
}

