function roleLabel(role) {
  const map = { admin:'ผู้ดูแลระบบ', managing_md:'กรรมการผู้จัดการ', manager:'ผู้จัดการ', supervisor:'หัวหน้างาน', operator:'ผู้ควบคุมเครื่องจักร', clerk:'เสมียน' };
  return map[role] || role;
}

function attachShellEvents() {
  qsa('.nav-link').forEach(btn => {
    btn.addEventListener('click', () => {
      const key = btn.getAttribute('data-nav');
      isMobileSheetOpen = false;
      isManageSheetOpen = false;
      navigateTo(key);
    });
  });
  const logoutBtn = document.getElementById('logout-btn');
  if (logoutBtn) logoutBtn.addEventListener('click', confirmLogout);

  const bellBtn = document.getElementById('approval-bell-btn');
  if (bellBtn) bellBtn.addEventListener('click', () => {
    showToast(pendingApprovalCount > 0 ? `มีรายการรออนุมัติ ${pendingApprovalCount} รายการ` : 'ไม่มีรายการรออนุมัติ', 'info');
  });

  const moreBtn = document.getElementById('mobile-more-btn');
  if (moreBtn) moreBtn.addEventListener('click', () => { isMobileSheetOpen = true; render(); });
  const sheetBackdrop = document.getElementById('mobile-sheet-backdrop');
  if (sheetBackdrop) sheetBackdrop.addEventListener('click', () => { isMobileSheetOpen = false; render(); });

  const manageBtn = document.getElementById('mobile-manage-btn');
  if (manageBtn) manageBtn.addEventListener('click', () => { isManageSheetOpen = true; render(); });
  const manageSheetBackdrop = document.getElementById('mobile-manage-sheet-backdrop');
  if (manageSheetBackdrop) manageSheetBackdrop.addEventListener('click', () => { isManageSheetOpen = false; render(); });

  fetchPendingApprovalCount();
}

