// ช่วงเวลาเริ่มต้น: เดือนปัจจุบัน
function defaultRangeState() {
  const now = new Date();
  return { mode: 'month', year: now.getFullYear(), month: now.getMonth() + 1, date: now.toISOString().slice(0,10), _initialized: false };
}

// ดึงเดือน/ปีล่าสุดที่มีข้อมูลใน table (dateField เป็น YYYY-MM-DD)
async function detectLatestDataMonth(table, dateField) {
  try {
    const { data, error } = await db.from(table).select(dateField).order(dateField, { ascending: false }).limit(1);
    if (error || !data || !data.length || !data[0][dateField]) return null;
    const d = new Date(data[0][dateField]);
    if (isNaN(d.getTime())) return null;
    return { year: d.getFullYear(), month: d.getMonth() + 1 };
  } catch { return null; }
}

// อัปเดต rangeState + ซิงค์ DOM month/year select
function applyLatestMonthToState(rangeState, idPrefix, latest) {
  if (!latest) return;
  rangeState.mode = 'month';
  rangeState.month = latest.month;
  rangeState.year = latest.year;
  const mSel = document.getElementById(`${idPrefix}-month-select`);
  const ySel = document.getElementById(`${idPrefix}-year-select`);
  if (mSel) mSel.value = String(latest.month);
  if (ySel) ySel.value = String(latest.year);
}

// คำนวณ from/to date string (YYYY-MM-DD) จาก range state
function rangeToDates(rangeState) {
  const { mode, year, month, date } = rangeState;
  if (mode === 'day') {
    return { from: date, to: date };
  }
  if (mode === 'year') {
    return { from: `${year}-01-01`, to: `${year}-12-31` };
  }
  // month
  const lastDay = new Date(year, month, 0).getDate();
  return { from: `${year}-${pad2(month)}-01`, to: `${year}-${pad2(month)}-${pad2(lastDay)}` };
}

function rangeControlHtml(idPrefix, rangeState) {
  const years = [];
  const curY = new Date().getFullYear();
  for (let y = curY; y >= curY - 4; y--) years.push(y);
  return `
  <div class="flex flex-wrap items-center gap-2" id="${idPrefix}-range-controls">
    <div class="flex dash-dark-pill-wrap rounded-xl p-1" style="background:#0A192F; border:1px solid #1d3a5f;">
      ${['day','month','year'].map(m => `
        <button data-range-mode="${m}" class="range-mode-btn px-3 py-1.5 rounded-lg text-xs font-medium transition ${rangeState.mode === m ? 'dash-dark-pill-active' : 'dash-dark-text-muted'}">${m === 'day' ? 'รายวัน' : m === 'month' ? 'รายเดือน' : 'รายปี'}</button>
      `).join('')}
    </div>
    ${rangeState.mode === 'day' ? `
      <input type="date" id="${idPrefix}-date-input" value="${rangeState.date}" class="dash-dark-input rounded-xl px-3 py-1.5 text-xs">
    ` : ''}
    ${rangeState.mode === 'month' ? `
      <select id="${idPrefix}-month-select" class="dash-dark-input rounded-xl px-3 py-1.5 text-xs">
        ${Array.from({length:12},(_, i) => i+1).map(m => `<option value="${m}" ${m===rangeState.month?'selected':''}>${monthNameTH(m)}</option>`).join('')}
      </select>
      <select id="${idPrefix}-year-select" class="dash-dark-input rounded-xl px-3 py-1.5 text-xs">
        ${years.map(y => `<option value="${y}" ${y===rangeState.year?'selected':''}>${y}</option>`).join('')}
      </select>
    ` : ''}
    ${rangeState.mode === 'year' ? `
      <select id="${idPrefix}-year-only-select" class="dash-dark-input rounded-xl px-3 py-1.5 text-xs">
        ${years.map(y => `<option value="${y}" ${y===rangeState.year?'selected':''}>${y}</option>`).join('')}
      </select>
    ` : ''}
  </div>`;
}

function attachRangeControlEvents(idPrefix, rangeState, onChange) {
  qsa(`#${idPrefix}-range-controls .range-mode-btn`).forEach(btn => {
    btn.addEventListener('click', () => {
      rangeState.mode = btn.getAttribute('data-range-mode');
      onChange();
    });
  });
  const dateInput = document.getElementById(`${idPrefix}-date-input`);
  if (dateInput) dateInput.addEventListener('change', () => { rangeState.date = dateInput.value; onChange(); });
  const monthSel = document.getElementById(`${idPrefix}-month-select`);
  if (monthSel) monthSel.addEventListener('change', () => { rangeState.month = Number(monthSel.value); onChange(); });
  const yearSel = document.getElementById(`${idPrefix}-year-select`);
  if (yearSel) yearSel.addEventListener('change', () => { rangeState.year = Number(yearSel.value); onChange(); });
  const yearOnlySel = document.getElementById(`${idPrefix}-year-only-select`);
  if (yearOnlySel) yearOnlySel.addEventListener('change', () => { rangeState.year = Number(yearOnlySel.value); onChange(); });
}

function destroyChart(key) {
  if (chartRegistry[key]) { chartRegistry[key].destroy(); delete chartRegistry[key]; }
}

const CHART_COLORS = ['#39FF14','#00FFFF','#FF00FF','#FFD700','#FF6B35','#00D9FF','#BC13FE','#FF1493','#14F1D9'];

const _cdePropelRangeState = { cde: defaultRangeState(), propel: defaultRangeState() };

// ---------------------------------------------------------------------
// Shared helpers สำหรับ CDE/Propel/Sanon1/Sanon2 (OEE gauge, Pareto, Yield datalabels, Feed/Throughput combo, KPI traffic-light)
// ---------------------------------------------------------------------

// สัญญาณไฟจราจรตาม % เทียบเป้า/ประสิทธิภาพ
function trafficLightColor(pct) {
  if (pct >= 85) return { bg: '#34d399', text: 'text-emerald-400', bar: 'bg-emerald-400' };
  if (pct >= 60) return { bg: '#fbbf24', text: 'text-amber-400', bar: 'bg-amber-400' };
  return { bg: '#f87171', text: 'text-red-400', bar: 'bg-red-400' };
}

// custom Chart.js plugin: วาด % ตรงกลางตัวเองของแต่ละ slice ของ doughnut (ไม่พึ่ง CDN ภายนอก)
const yieldDataLabelsPlugin = {
  id: 'yieldDataLabelsPlugin',
  afterDraw(chart) {
    if (chart.config._yieldLabelsOff) return;
    const { ctx } = chart;
    const meta = chart.getDatasetMeta(0);
    const dataset = chart.data.datasets[0];
    const total = dataset.data.reduce((a, b) => a + (Number(b) || 0), 0);
    if (!total) return;
    ctx.save();
    ctx.font = '600 11px Kanit, sans-serif';
    ctx.fillStyle = '#0A192F';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    meta.data.forEach((arc, i) => {
      const val = Number(dataset.data[i]) || 0;
      if (!val) return;
      const pct = (val / total) * 100;
      if (pct < 3) return; // slice เล็กเกินไปไม่ใส่ label กันทับ
      const { x, y } = arc.tooltipPosition();
      ctx.fillStyle = '#fff';
      ctx.fillText(`${pct.toFixed(1)}%`, x, y);
    });
    ctx.restore();
  }
};

// custom Chart.js plugin: วาดตัวเลขปริมาณบนแท่ง bar chart (ใช้ในหลาย dashboard)
const barValueLabelsPlugin = {
  id: 'barValueLabelsPlugin',
  afterDatasetsDraw(chart) {
    if (chart.config._barLabelsOff) return;
    const { ctx } = chart;
    chart.data.datasets.forEach((dataset, dsIndex) => {
      if (dataset.type && dataset.type !== 'bar') return;
      const meta = chart.getDatasetMeta(dsIndex);
      if (meta.type && meta.type !== 'bar') return;
      ctx.save();
      ctx.font = '600 10px Kanit, sans-serif';
      ctx.fillStyle = '#e2e8f0';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'bottom';
      meta.data.forEach((bar, i) => {
        const val = Number(dataset.data[i]) || 0;
        if (!val) return;
        const pos = bar.tooltipPosition ? bar.tooltipPosition() : { x: bar.x, y: bar.y };
        if (chart.options.indexAxis === 'y') {
          ctx.textAlign = 'left';
          ctx.textBaseline = 'middle';
          ctx.fillText(fmtNum(val, 1), pos.x + 6, pos.y);
        } else {
          ctx.fillText(fmtNum(val, 1), pos.x, pos.y - 4);
        }
      });
      ctx.restore();
    });
  }
};

// custom Chart.js plugin: วาดยอดรวมบนยอดแท่ง stacked bar (1 ตัวเลขต่อ 1 แท่ง)
const stackedBarTotalPlugin = {
  id: 'stackedBarTotalPlugin',
  afterDatasetsDraw(chart) {
    const { ctx, data } = chart;
    if (!data.datasets.length) return;
    const numBars = data.labels.length;
    // คำนวณ total แต่ละ index
    const totals = Array(numBars).fill(0);
    data.datasets.forEach(ds => {
      ds.data.forEach((v, i) => { totals[i] += Number(v) || 0; });
    });
    // หา dataset สุดท้ายที่ไม่ hidden เพื่อดึง x position + y ด้านบนสุด
    let topMeta = null;
    for (let d = data.datasets.length - 1; d >= 0; d--) {
      const m = chart.getDatasetMeta(d);
      if (!m.hidden) { topMeta = m; break; }
    }
    if (!topMeta) return;
    // หา y ต่ำสุด (บนสุดของกราฟ) ของแต่ละแท่งจากทุก dataset
    const topY = Array(numBars).fill(Infinity);
    data.datasets.forEach((ds, di) => {
      const m = chart.getDatasetMeta(di);
      if (m.hidden) return;
      m.data.forEach((bar, i) => { if (bar.y < topY[i]) topY[i] = bar.y; });
    });
    ctx.save();
    ctx.font = 'bold 11px Kanit,sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'bottom';
    ctx.fillStyle = '#e2e8f0';
    ctx.shadowColor = 'rgba(0,0,0,0.8)';
    ctx.shadowBlur = 3;
    topMeta.data.forEach((bar, i) => {
      const total = totals[i];
      if (!total) return;
      const label = total >= 10000 ? fmtNum(total/1000,1)+'K ตัน' : fmtNum(total,0)+' ตัน';
      ctx.fillText(label, bar.x, topY[i] - 4);
    });
    ctx.shadowBlur = 0;
    ctx.restore();
  }
};

// วาด half-gauge progress ring ด้วย SVG arc — คืน HTML string
function gaugeSvg(pct, label, idSuffix) {
  const clamped = Math.max(0, Math.min(100, pct || 0));
  const color = trafficLightColor(clamped);
  const r = 54;
  const cx = 64, cy = 64;
  const circumference = Math.PI * r; // ครึ่งวงกลม
  const offset = circumference - (circumference * clamped / 100);
  return `
    <div class="flex flex-col items-center">
      <svg width="128" height="74" viewBox="0 0 128 74" class="overflow-visible">
        <path d="M ${cx-r} ${cy} A ${r} ${r} 0 0 1 ${cx+r} ${cy}" fill="none" stroke="#1d3a5f" stroke-width="12" stroke-linecap="round"/>
        <path id="gauge-arc-${idSuffix}" d="M ${cx-r} ${cy} A ${r} ${r} 0 0 1 ${cx+r} ${cy}" fill="none" stroke="${color.bg}" stroke-width="12" stroke-linecap="round"
          stroke-dasharray="${circumference}" stroke-dashoffset="${offset}" style="transition: stroke-dashoffset .5s ease;"/>
      </svg>
      <div class="text-2xl font-bold -mt-7 ${color.text}">${fmtNum(clamped,1)}%</div>
      <div class="text-xs dash-dark-text-muted mt-1">${escapeHtml(label)}</div>
    </div>`;
}

// นับ "วันทำงาน" เฉพาะวันที่มี runtime จริง (runtime_hour + runtime_minute > 0)
// วันที่มี record แต่ไม่มีเวลาเดินเครื่องเลย (เช่น วันหยุด/ไม่ได้ผลิต) จะไม่ถูกนับเป็นวันทำงาน
function countWorkingDays(rows) {
  const workingDates = new Set();
  rows.forEach(r => {
    const runtimeMinutes = (Number(r.runtime_hour)||0) * 60 + (Number(r.runtime_minute)||0);
    if (runtimeMinutes > 0) workingDates.add(r.production_date);
  });
  return workingDates.size;
}

// คำนวณ Availability% และ Performance% จากแถวข้อมูลจริงในช่วงที่เลือก
// Availability = runtime จริงรวม / (จำนวนวันทำงาน x ชั่วโมงกะมาตรฐาน 9 ชม.) x 100
// Performance  = avg_ton_per_hour เฉลี่ยจริง / target_throughput x 100
function computeOee(rows, targetThroughput) {
  const SHIFT_HOURS = 9; // ชั่วโมงกะมาตรฐานต่อวัน
  const days = countWorkingDays(rows);
  const runtimeTotal = rows.reduce((s,r) => s + (Number(r.runtime_hour)||0) + (Number(r.runtime_minute)||0)/60, 0);
  const standardHours = days * SHIFT_HOURS;
  const availabilityPct = standardHours > 0 ? Math.min(100, (runtimeTotal / standardHours) * 100) : 0;
  const avgThroughput = rows.length ? rows.reduce((s,r) => s + (Number(r.avg_ton_per_hour)||0), 0) / rows.length : 0;
  const performancePct = (targetThroughput && targetThroughput > 0) ? Math.min(150, (avgThroughput / targetThroughput) * 100) : 0;
  return { availabilityPct, performancePct, runtimeTotal, standardHours, avgThroughput, days };
}

function renderOeeGaugeBlock(type, rows, targetThroughput) {
  const el = document.getElementById(`${type}-oee-block`);
  if (!el) return;
  const oee = computeOee(rows, targetThroughput);
  el.innerHTML = `
    <div class="dash-dark-card rounded-2xl p-5">
      <h3 class="text-sm font-medium dash-dark-text-muted mb-3 flex items-center gap-2"><i data-lucide="activity" class="w-4 h-4 text-cyan-400"></i>OEE Gauge (Availability / Performance)</h3>
      <div class="grid grid-cols-2 gap-2">
        ${gaugeSvg(oee.availabilityPct, 'Availability', `${type}-avail`)}
        ${gaugeSvg(oee.performancePct, 'Performance', `${type}-perf`)}
      </div>
      <p class="text-xs dash-dark-text-muted mt-2 text-center">Runtime ${fmtNum(oee.runtimeTotal,1)}/${fmtNum(oee.standardHours,0)} ชม. • Throughput เฉลี่ย ${fmtNum(oee.avgThroughput,1)} / เป้า ${fmtNum(targetThroughput||0,1)} ตัน/ชม.</p>
    </div>`;
  refreshIcons();
}

// Breakdown analysis: group by breakdown_detail — แสดงครั้งละ 5 แถว + pagination
const _breakdownPage = {};
const _breakdownData = {};
const BREAKDOWN_PAGE_SIZE = 5;

window._breakdownChangePage = function(type, delta) {
  if (!_breakdownData[type]) return;
  const totalPages = Math.ceil(_breakdownData[type].entries.length / BREAKDOWN_PAGE_SIZE);
  _breakdownPage[type] = Math.max(0, Math.min(totalPages - 1, (_breakdownPage[type] || 0) + delta));
  renderBreakdownTable(type);
};

function renderParetoBlock(type, rows) {
  const counts = {};
  rows.forEach(r => {
    const detail = (r.breakdown_detail || '').trim();
    if (detail) counts[detail] = (counts[detail] || 0) + 1;
  });
  const entries = Object.entries(counts).sort((a,b) => b[1]-a[1]);
  const total = entries.reduce((s,e) => s + e[1], 0);
  _breakdownData[type] = { entries, total };
  _breakdownPage[type] = 0; // reset เมื่อโหลดข้อมูลใหม่
  renderBreakdownTable(type);
}

function renderBreakdownTable(type) {
  const el = document.getElementById(`${type}-breakdown-block`);
  if (!el) return;
  const stored = _breakdownData[type];
  if (!stored || !stored.entries.length) {
    el.innerHTML = `
      <div class="dash-dark-card rounded-2xl p-5">
        <h3 class="text-sm font-medium dash-dark-text-muted mb-3">สาเหตุหยุดเครื่อง (Breakdown)</h3>
        <p class="text-center dash-dark-text-muted text-sm py-12">ไม่มีข้อมูล breakdown ในช่วงเวลานี้</p>
      </div>`;
    refreshIcons();
    return;
  }
  const { entries, total } = stored;
  const page = _breakdownPage[type] || 0;
  const totalPages = Math.ceil(entries.length / BREAKDOWN_PAGE_SIZE);
  const pageEntries = entries.slice(page * BREAKDOWN_PAGE_SIZE, (page + 1) * BREAKDOWN_PAGE_SIZE);
  // คำนวณ cumulative ตั้งแต่แถวแรก ไม่ใช่แค่ในหน้า
  let cumBase = entries.slice(0, page * BREAKDOWN_PAGE_SIZE).reduce((s,e) => s + e[1], 0);
  let cum = cumBase;
  const rowsHtml = pageEntries.map(([detail, count]) => {
    const pct = (count / total) * 100;
    cum += count;
    const cumPct = (cum / total) * 100;
    return `
      <tr class="border-b dash-dark-border dash-dark-row-hover dash-dark-text">
        <td class="py-2 pr-3">${escapeHtml(detail)}</td>
        <td class="py-2 pr-3 text-right">${fmtNum(count,0)}</td>
        <td class="py-2 pr-3 text-right">${fmtNum(pct,1)}%</td>
        <td class="py-2 pr-3 text-right">${fmtNum(cumPct,1)}%</td>
      </tr>`;
  }).join('');

  el.innerHTML = `
    <div class="dash-dark-card rounded-2xl p-5 overflow-x-auto">
      <div class="flex items-center justify-between mb-3">
        <h3 class="text-sm font-medium dash-dark-text-muted">สาเหตุหยุดเครื่อง (Breakdown)</h3>
        <span class="text-xs dash-dark-text-muted">${entries.length} รายการ</span>
      </div>
      <table class="w-full text-sm">
        <thead><tr class="text-left dash-dark-text-muted border-b dash-dark-border">
          <th class="py-2 pr-3">รายละเอียดสาเหตุ</th>
          <th class="py-2 pr-3 text-right">จำนวนครั้ง</th>
          <th class="py-2 pr-3 text-right">% ของรวม</th>
          <th class="py-2 pr-3 text-right">% สะสม</th>
        </tr></thead>
        <tbody>${rowsHtml}</tbody>
        <tfoot><tr class="dash-dark-text font-semibold border-t dash-dark-border">
          <td class="py-2 pr-3">รวม</td>
          <td class="py-2 pr-3 text-right">${fmtNum(total,0)}</td>
          <td class="py-2 pr-3 text-right">100%</td>
          <td class="py-2 pr-3 text-right">-</td>
        </tr></tfoot>
      </table>
      ${totalPages > 1 ? `
      <div class="flex items-center justify-between mt-3 pt-3 border-t dash-dark-border">
        <button onclick="_breakdownChangePage('${type}',-1)" class="text-xs px-3 py-1.5 rounded-lg dash-dark-card border dash-dark-border dash-dark-text-muted hover:dash-dark-text transition disabled:opacity-30" ${page === 0 ? 'disabled' : ''}>← ก่อนหน้า</button>
        <span class="text-xs dash-dark-text-muted">หน้า ${page+1} / ${totalPages}</span>
        <button onclick="_breakdownChangePage('${type}',1)" class="text-xs px-3 py-1.5 rounded-lg dash-dark-card border dash-dark-border dash-dark-text-muted hover:dash-dark-text transition disabled:opacity-30" ${page === totalPages-1 ? 'disabled' : ''}>ถัดไป →</button>
      </div>` : ''}
    </div>`;
  refreshIcons();
}

// Yield Mix Donut พร้อม custom afterDraw datalabels plugin (ไม่พึ่ง CDN ภายนอก)
function renderYieldDonutBlock(type, sums) {
  const el = document.getElementById(`${type}-yield-chart-block`);
  if (!el) return;
  const labels = Object.keys(sums);
  const values = Object.values(sums);
  const total = values.reduce((a,b)=>a+b,0);

  el.innerHTML = `
    <div class="dash-dark-card rounded-2xl p-5">
      <h3 class="text-sm font-medium dash-dark-text-muted mb-3">Product Yield Mix</h3>
      ${total > 0 ? `<div class="relative h-64"><canvas id="${type}-yield-canvas"></canvas></div>` : `<p class="text-center dash-dark-text-muted text-sm py-12">ไม่มีข้อมูลในช่วงเวลานี้</p>`}
    </div>`;
  refreshIcons();
  if (total > 0) {
    const ctx = document.getElementById(`${type}-yield-canvas`);
    destroyChart(`${type}-yield`);
    chartRegistry[`${type}-yield`] = new Chart(ctx, {
      type: 'doughnut',
      data: { labels, datasets: [{ data: values, backgroundColor: CHART_COLORS, borderWidth: 2, borderColor: '#112240' }] },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { boxWidth: 12, font: { size: 11 }, color: '#cbd5e1' } } } },
      plugins: [yieldDataLabelsPlugin]
    });
  }
}

// All-Plants Production Donut — แสดงยอดผลิตรวม(ตัน)ของ 4 โรงงานในช่วงวันเดียวกัน
const _allPlantsProdCache = {}; // "from|to" -> { cde, propel, sanon1, sanon2 }

async function loadAndRenderAllPlantsProductionDonut(parentType, from, to) {
  const el = document.getElementById(`${parentType}-all-plants-block`);
  if (!el) return;
  el.innerHTML = `<div class="dash-dark-card rounded-2xl p-5">${skeletonBlockDark('h-48')}</div>`;

  const cacheKey = `${from}|${to}`;
  let totals = _allPlantsProdCache[cacheKey];
  if (!totals) {
    try {
      // query productColumns ของแต่ละโรงงาน (approved เท่านั้น)
      const plantQueries = [
        db.from('production_cde').select('os_ton,stone_3_4_ton,stone_screening_3_8_ton,msand_ton,silk_sediment_ton').eq('status','approved').gte('production_date',from).lte('production_date',to),
        db.from('production_propel').select('os_ton,stone_3_4_ton,stone_screening_3_8_ton,msand_ton,silk_sediment_ton,stone_1_2_ton').eq('status','approved').gte('production_date',from).lte('production_date',to),
        db.from('production_sanon1').select('stone_6_8_ton,stone_3_4_ton,stone_kluk_ton,stone_dust_ton').eq('status','approved').gte('production_date',from).lte('production_date',to),
        db.from('production_sanon2').select('stone_6_8_ton,stone_3_4_ton,stone_kluk_ton,stone_dust_ton,stone_3_8_ton,stone_special2_ton').eq('status','approved').gte('production_date',from).lte('production_date',to),
      ];
      const [r0,r1,r2,r3] = await Promise.all(plantQueries);
      const sumRows = (rows, keys) => (rows||[]).reduce((s,r) => s + keys.reduce((acc,k) => acc + (Number(r[k])||0), 0), 0);
      totals = {
        CDE:    sumRows(r0.data, ['os_ton','stone_3_4_ton','stone_screening_3_8_ton','msand_ton','silk_sediment_ton']),
        Propel: sumRows(r1.data, ['os_ton','stone_3_4_ton','stone_screening_3_8_ton','msand_ton','silk_sediment_ton','stone_1_2_ton']),
        Sanon1: sumRows(r2.data, ['stone_6_8_ton','stone_3_4_ton','stone_kluk_ton','stone_dust_ton']),
        Sanon2: sumRows(r3.data, ['stone_6_8_ton','stone_3_4_ton','stone_kluk_ton','stone_dust_ton','stone_3_8_ton','stone_special2_ton']),
      };
      _allPlantsProdCache[cacheKey] = totals;
    } catch (err) {
      console.error('allPlants', err);
      el.innerHTML = `<div class="dash-dark-card rounded-2xl p-5">${errorBlockDark()}</div>`;
      refreshIcons(); return;
    }
  }

  const labels = Object.keys(totals);
  const values = Object.values(totals);
  const grandTotal = values.reduce((a,b)=>a+b,0);
  const PLANT_COLORS = ['#22d3ee','#a78bfa','#fb923c','#4ade80'];

  el.innerHTML = `
    <div class="dash-dark-card rounded-2xl p-5">
      <div class="flex items-center justify-between mb-3">
        <h3 class="text-sm font-medium dash-dark-text-muted">ยอดผลิตรวม 4 โรงงาน</h3>
        <span class="text-xs dash-dark-text-muted">${fmtNum(grandTotal,1)} ตัน</span>
      </div>
      ${grandTotal > 0
        ? `<div class="relative h-56"><canvas id="${parentType}-all-plants-canvas"></canvas></div>
           <div class="mt-3 grid grid-cols-2 gap-x-4 gap-y-1">
             ${labels.map((l,i) => `
               <div class="flex items-center gap-2 text-xs">
                 <span class="inline-block w-2.5 h-2.5 rounded-sm flex-shrink-0" style="background:${PLANT_COLORS[i]}"></span>
                 <span class="dash-dark-text-muted">${l}:</span>
                 <span class="dash-dark-text font-medium">${fmtNum(values[i],1)} ต.</span>
                 <span class="dash-dark-text-muted">(${grandTotal>0?fmtNum(values[i]/grandTotal*100,1):0}%)</span>
               </div>`).join('')}
           </div>`
        : `<p class="text-center dash-dark-text-muted text-sm py-12">ไม่มีข้อมูลในช่วงเวลานี้</p>`}
    </div>`;
  refreshIcons();

  if (grandTotal > 0) {
    const ctx = document.getElementById(`${parentType}-all-plants-canvas`);
    destroyChart(`${parentType}-all-plants`);
    chartRegistry[`${parentType}-all-plants`] = new Chart(ctx, {
      type: 'doughnut',
      data: { labels, datasets: [{ data: values, backgroundColor: PLANT_COLORS, borderWidth: 2, borderColor: '#112240' }] },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: { callbacks: { label: (ctx) => ` ${ctx.label}: ${fmtNum(ctx.raw,1)} ตัน (${fmtNum(ctx.raw/(ctx.dataset.data.reduce((a,b)=>a+b,0)||1)*100,1)}%)` } }
        }
      },
      plugins: [yieldDataLabelsPlugin]
    });
  }
}

// สรุปยอดผลิต (ตัน) แยกชนิดหินของโรงงานตัวเอง — แสดงด้านล่าง Yield Donut
function renderProdTonsBlock(type, sums) {
  const el = document.getElementById(`${type}-prod-tons-block`);
  if (!el) return;
  const entries = Object.entries(sums).filter(([,v]) => v > 0);
  const grandTotal = entries.reduce((s,[,v]) => s + v, 0);
  if (!entries.length || !grandTotal) {
    el.innerHTML = `<div class="dash-dark-card rounded-2xl p-5"><p class="text-center dash-dark-text-muted text-sm py-4">ไม่มีข้อมูล</p></div>`;
    return;
  }
  const maxVal = Math.max(...entries.map(([,v]) => v));
  const rowsHtml = entries.map(([label, val], i) => {
    const pct = grandTotal > 0 ? (val / grandTotal * 100) : 0;
    const barPct = maxVal > 0 ? (val / maxVal * 100) : 0;
    const color = CHART_COLORS[i % CHART_COLORS.length];
    return `
      <div class="mb-2">
        <div class="flex items-center justify-between text-xs mb-0.5">
          <span class="dash-dark-text-muted flex items-center gap-1.5">
            <span class="inline-block w-2 h-2 rounded-sm" style="background:${color}"></span>${escapeHtml(label)}
          </span>
          <span class="dash-dark-text font-semibold">${fmtNum(val,1)} <span class="font-normal text-[10px] dash-dark-text-muted">ต. (${fmtNum(pct,1)}%)</span></span>
        </div>
        <div class="w-full rounded-full h-1.5" style="background:rgba(255,255,255,0.08)">
          <div class="h-1.5 rounded-full transition-all" style="width:${barPct.toFixed(1)}%;background:${color}"></div>
        </div>
      </div>`;
  }).join('');
  el.innerHTML = `
    <div class="dash-dark-card rounded-2xl p-5">
      <div class="flex items-center justify-between mb-3">
        <h3 class="text-sm font-medium dash-dark-text-muted">ยอดผลิต (ตัน)</h3>
        <span class="text-xs dash-dark-text-muted font-semibold">${fmtNum(grandTotal,1)} ตัน</span>
      </div>
      ${rowsHtml}
    </div>`;
}

// custom Chart.js plugin: วาดตัวเลข Feed (ตัน) บนแท่ง และ Throughput (ตัน/ชม.) บนจุดของเส้น สำหรับ Feed/Throughput combo chart
const feedThroughputDataLabelsPlugin = {
  id: 'feedThroughputDataLabelsPlugin',
  afterDatasetsDraw(chart) {
    const { ctx } = chart;
    ctx.save();
    ctx.font = '600 10px Kanit, sans-serif';
    ctx.textAlign = 'center';
    chart.data.datasets.forEach((dataset, dsIndex) => {
      const meta = chart.getDatasetMeta(dsIndex);
      if (meta.hidden) return;
      meta.data.forEach((point, i) => {
        const val = Number(dataset.data[i]) || 0;
        if (!val) return;
        const pos = point.tooltipPosition ? point.tooltipPosition() : { x: point.x, y: point.y };
        ctx.shadowColor = 'rgba(0,0,0,0.8)';
        ctx.shadowBlur = 3;
        if (dataset.type === 'bar') {
          ctx.fillStyle = '#ffffff';
          ctx.textBaseline = 'bottom';
          ctx.fillText(fmtNum(val, 0), pos.x, pos.y - 4);
        } else {
          ctx.fillStyle = '#fde68a';
          ctx.textBaseline = 'bottom';
          ctx.fillText(fmtNum(val, 1), pos.x, pos.y - 8);
        }
        ctx.shadowBlur = 0;
      });
    });
    ctx.restore();
  }
};

// Feed/Throughput combo chart: bar=feed_ton (แกนซ้าย), line=avg_ton_per_hour (แกนขวา)
// mode=year → aggregate by month (ยอดตันรวม + ตัน/ชม. weighted), mode=month/day → รายวัน
function renderFeedThroughputComboBlock(type, rows, rangeState) {
  const el = document.getElementById(`${type}-trend-chart-block`);
  if (!el) return;

  let labels, feedData, throughputData, chartTitle;
  const isYearMode = rangeState && rangeState.mode === 'year';

  if (isYearMode) {
    chartTitle = 'Feed / Throughput รายเดือน';
    const monthlyMap = {};
    rows.forEach(r => {
      const key = r.production_date ? String(r.production_date).slice(0, 7) : null;
      if (!key) return;
      if (!monthlyMap[key]) monthlyMap[key] = { feedSum: 0, runtimeSum: 0 };
      monthlyMap[key].feedSum += Number(r.feed_ton) || 0;
      const rth = (Number(r.runtime_hour) || 0) + (Number(r.runtime_minute) || 0) / 60;
      monthlyMap[key].runtimeSum += rth;
    });
    const keys = Object.keys(monthlyMap).sort();
    labels = keys.map(k => { const [,m] = k.split('-'); return monthNameTH(Number(m)); });
    feedData = keys.map(k => monthlyMap[k].feedSum);
    throughputData = keys.map(k => monthlyMap[k].runtimeSum > 0 ? monthlyMap[k].feedSum / monthlyMap[k].runtimeSum : 0);
  } else {
    chartTitle = 'Feed / Throughput รายวัน';
    labels = rows.map(r => fmtDate(r.production_date));
    feedData = rows.map(r => Number(r.feed_ton) || 0);
    throughputData = rows.map(r => Number(r.avg_ton_per_hour) || 0);
  }

  el.innerHTML = `
    <div class="dash-dark-card rounded-2xl p-5">
      <h3 class="text-sm font-medium dash-dark-text-muted mb-3">${chartTitle}</h3>
      ${labels.length ? `<div class="relative h-72"><canvas id="${type}-trend-canvas"></canvas></div>` : `<p class="text-center dash-dark-text-muted text-sm py-12">ไม่มีข้อมูลในช่วงเวลานี้</p>`}
    </div>`;
  refreshIcons();
  if (labels.length) {
    const ctx = document.getElementById(`${type}-trend-canvas`);
    destroyChart(`${type}-trend`);
    chartRegistry[`${type}-trend`] = new Chart(ctx, {
      data: {
        labels,
        datasets: [
          { type: 'bar', label: 'Feed (ตัน)', data: feedData, backgroundColor: '#4ade80', yAxisID: 'y', borderRadius: 4 },
          { type: 'line', label: 'Throughput (ตัน/ชม.)', data: throughputData, borderColor: '#f59e0b', backgroundColor: '#f59e0b', pointBackgroundColor: '#f59e0b', pointRadius: 4, yAxisID: 'y1', tension: 0.3 },
        ]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        layout: { padding: { top: 22 } },
        plugins: { legend: { labels: { color: '#cbd5e1' } } },
        scales: {
          y: { type: 'linear', position: 'left', title: { display: true, text: 'ตัน', color: '#94a3b8' }, ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' }, suggestedMax: Math.max(...feedData) * 1.2 || undefined },
          y1: { type: 'linear', position: 'right', title: { display: true, text: 'ตัน/ชม.', color: '#94a3b8' }, ticks: { color: '#94a3b8' }, grid: { drawOnChartArea: false }, suggestedMax: Math.max(...throughputData) * 1.3 || undefined },
          x: { ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } },
        }
      },
      plugins: [feedThroughputDataLabelsPlugin]
    });
  }
}

// คำนวณเป้า KPI Gap ตามโหมดช่วงเวลา (rayState.mode): รายเดือน/รายปี ใช้เป้าตรงตาม cfg, รายวัน prorate จากเป้ารายเดือน/จำนวนวันในเดือนนั้น
function resolveKpiTarget(cfg, rangeState) {
  if (rangeState.mode === 'year') return cfg.targetYear;
  if (rangeState.mode === 'day') {
    const d = new Date(rangeState.date);
    const daysInMonth = new Date(d.getFullYear(), d.getMonth() + 1, 0).getDate();
    return cfg.targetMonth / daysInMonth;
  }
  return cfg.targetMonth; // month (default)
}

// KPI Gap progress bar พร้อมสัญญาณไฟจราจร
function renderKpiGapBlock(type, cfg, rows, rangeState) {
  const el = document.getElementById(`${type}-kpi-block`);
  if (!el) return;
  const feedTotal = rows.reduce((s,r) => s + (Number(r.feed_ton)||0), 0);
  const target = resolveKpiTarget(cfg, rangeState);
  const pct = target > 0 ? Math.min(100, (feedTotal / target) * 100) : 0;
  const color = trafficLightColor(pct);
  const periodLabel = rangeState.mode === 'day' ? fmtDate(rangeState.date)
    : rangeState.mode === 'year' ? `ปี ${rangeState.year}`
    : `${monthNameTH(rangeState.month)} ${rangeState.year}`;
  el.innerHTML = `
    <div class="dash-dark-card rounded-2xl p-5">
      <div class="flex items-center justify-between mb-2">
        <span class="text-sm font-medium dash-dark-text-muted flex items-center gap-2"><i data-lucide="target" class="w-4 h-4 text-cyan-400"></i>KPI Gap เทียบเป้า (${escapeHtml(periodLabel)})</span>
        <span class="text-sm font-semibold ${color.text}">${fmtNum(pct,1)}%</span>
      </div>
      <div class="w-full h-3 rounded-full overflow-hidden" style="background:#1d3a5f">
        <div class="h-full ${color.bar} rounded-full transition-all" style="width:${pct}%"></div>
      </div>
      <p class="text-xs dash-dark-text-muted mt-2">${fmtNum(feedTotal,1)} / ${fmtNum(target,0)} ตัน</p>
    </div>`;
  refreshIcons();
}

// =====================================================================
// SECTION 13: DASHBOARD CDE / PROPEL (component ใช้ร่วมกัน)
