function renderDashboardCdePropel(container, type) {
  const cfg = type === 'cde'
    ? { table: 'production_cde', title: 'Dashboard CDE', targetMonth: 30000, targetYear: 360000, hasHalf: false, factoryName: 'CDE' }
    : { table: 'production_propel', title: 'Dashboard Propel', targetMonth: 45000, targetYear: 540000, hasHalf: true, factoryName: 'Propel' };
  const rangeState = _cdePropelRangeState[type];

  container.innerHTML = `
    <div class="dash-dark-bg -m-4 sm:-m-6 p-4 sm:p-6 min-h-full">
    <div class="space-y-6 fade-in">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <h2 class="text-lg font-semibold dash-dark-text flex items-center gap-2"><i data-lucide="waves" class="w-5 h-5 text-cyan-400"></i>${cfg.title}</h2>
        ${rangeControlHtml(type, rangeState)}
      </div>
      <div id="${type}-stat-cards" class="grid grid-cols-2 sm:grid-cols-4 gap-4">${[1,2,3,4].map(skeletonCardDark).join('')}</div>
      <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div id="${type}-oee-block">${skeletonBlockDark('h-48')}</div>
        <div id="${type}-kpi-block">${skeletonBlockDark('h-48')}</div>
      </div>
      <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div class="space-y-4">
          <div id="${type}-yield-chart-block">${skeletonBlockDark()}</div>
          <div id="${type}-prod-tons-block">${skeletonBlockDark('h-40')}</div>
        </div>
        <div id="${type}-breakdown-block">${skeletonBlockDark()}</div>
      </div>
      <div id="${type}-trend-chart-block">${skeletonBlockDark()}</div>
    </div>
    </div>`;
  refreshIcons();
  attachRangeControlEvents(type, rangeState, () => renderDashboardCdePropel(container, type));
  loadCdePropelData(type, cfg, rangeState);
}

async function loadCdePropelData(type, cfg, rangeState) {
  try {
    if (!rangeState._initialized) {
      const latest = await detectLatestDataMonth(cfg.table, 'production_date');
      applyLatestMonthToState(rangeState, type, latest);
      rangeState._initialized = true;
    }
    const { from, to } = rangeToDates(rangeState);
    const [{ data, error }, { data: factoryRows, error: factoryErr }] = await Promise.all([
      db.from(cfg.table).select('*').eq('status', 'approved').gte('production_date', from).lte('production_date', to).order('production_date', { ascending: true }),
      db.from('factories').select('id, name, target_throughput').eq('name', cfg.factoryName)
    ]);
    if (error) throw error;
    if (factoryErr) throw factoryErr;
    const rows = data || [];
    const targetThroughputDB = (factoryRows && factoryRows[0]) ? Number(factoryRows[0].target_throughput) || 0 : 0;
    // fallback: ถ้า DB ไม่มีค่า ให้คำนวณจาก targetMonth / (22 วัน × 9 ชม.) = ค่าประมาณ
    const targetThroughput = targetThroughputDB > 0 ? targetThroughputDB : (cfg.targetMonth > 0 ? Math.round(cfg.targetMonth / (22 * 9) * 10) / 10 : 0);

    renderCdePropelStats(type, cfg, rows);
    renderOeeGaugeBlock(type, rows, targetThroughput);
    renderKpiGapBlock(type, cfg, rows, rangeState);
    renderCdePropelYieldChart(type, cfg, rows);
    renderParetoBlock(type, rows);
    renderFeedThroughputComboBlock(type, rows, rangeState);
  } catch (err) {
    console.error(err);
    ['stat-cards','oee-block','kpi-block','yield-chart-block','prod-tons-block','breakdown-block','trend-chart-block'].forEach(s => {
      const el = document.getElementById(`${type}-${s}`);
      if (el) el.innerHTML = errorBlockDark();
    });
    refreshIcons();
  }
}

function renderCdePropelStats(type, cfg, rows) {
  const el = document.getElementById(`${type}-stat-cards`);
  if (!el) return;
  const days = countWorkingDays(rows);
  const feedTotal = rows.reduce((s,r) => s + (Number(r.feed_ton)||0), 0);
  const runtimeTotal = rows.reduce((s,r) => s + (Number(r.runtime_hour)||0) + (Number(r.runtime_minute)||0)/60, 0);
  const avgThroughput = rows.length ? rows.reduce((s,r) => s + (Number(r.avg_ton_per_hour)||0), 0) / rows.length : 0;
  el.innerHTML = [
    statCard('calendar-days','วันทำงาน', fmtNum(days,0), 'วัน'),
    statCard('package','หินป้อนรวม', fmtNum(feedTotal,1), 'ตัน'),
    statCard('timer','Runtime รวม', fmtNum(runtimeTotal,1), 'ชม.'),
    statCard('gauge','Throughput เฉลี่ย', fmtNum(avgThroughput,1), 'ตัน/ชม.'),
  ].join('');
  refreshIcons();
}

function renderCdePropelYieldChart(type, cfg, rows) {
  const sums = {
    'O/S': rows.reduce((s,r)=>s+(Number(r.os_ton)||0),0),
    'หิน 3/4': rows.reduce((s,r)=>s+(Number(r.stone_3_4_ton)||0),0),
    'หินเกล็ด 3/8': rows.reduce((s,r)=>s+(Number(r.stone_screening_3_8_ton)||0),0),
    'M-Sand': rows.reduce((s,r)=>s+(Number(r.msand_ton)||0),0),
    'ตะกอน Silk': rows.reduce((s,r)=>s+(Number(r.silk_sediment_ton)||0),0),
  };
  if (cfg.hasHalf) sums['หิน 1/2'] = rows.reduce((s,r)=>s+(Number(r.stone_1_2_ton)||0),0);
  renderYieldDonutBlock(type, sums);
  renderProdTonsBlock(type, sums);
}

