async function loadSanonData(type, cfg, rangeState) {
  try {
    if (!rangeState._initialized) {
      const latest = await detectLatestDataMonth(cfg.table, 'production_date');
      applyLatestMonthToState(rangeState, type, latest);
      rangeState._initialized = true;
    }
    const { from, to } = rangeToDates(rangeState);
    const [{ data, error }, { data: factoryRows, error: factoryErr }] = await Promise.all([
      db.from(cfg.table).select('*').eq('status', 'approved').gte('production_date', from).lte('production_date', to).order('production_date', { ascending: true }),
      db.from('factories').select('id, name, target_throughput').eq('name', cfg.factoryName)
    ]);
    if (error) throw error;
    if (factoryErr) throw factoryErr;
    const rows = data || [];
    const targetThroughputDB = (factoryRows && factoryRows[0]) ? Number(factoryRows[0].target_throughput) || 0 : 0;
    const targetThroughput = targetThroughputDB > 0 ? targetThroughputDB : (cfg.targetMonth > 0 ? Math.round(cfg.targetMonth / (22 * 9) * 10) / 10 : 0);

    renderSanonStats(type, rows);
    renderOeeGaugeBlock(type, rows, targetThroughput);
    renderKpiGapBlock(type, cfg, rows, rangeState);
    renderSanonYieldChart(type, cfg, rows);
    renderParetoBlock(type, rows);
    renderFeedThroughputComboBlock(type, rows, rangeState);
  } catch (err) {
    console.error(err);
    ['stat-cards','oee-block','kpi-block','yield-chart-block','prod-tons-block','breakdown-block','trend-chart-block'].forEach(s => {
      const el = document.getElementById(`${type}-${s}`);
      if (el) el.innerHTML = errorBlockDark();
    });
    refreshIcons();
  }
}

function renderSanonStats(type, rows) {
  const el = document.getElementById(`${type}-stat-cards`);
  if (!el) return;
  const days = countWorkingDays(rows);
  const feedTotal = rows.reduce((s,r) => s + (Number(r.feed_ton)||0), 0);
  const runtimeTotal = rows.reduce((s,r) => s + (Number(r.runtime_hour)||0) + (Number(r.runtime_minute)||0)/60, 0);
  const avgThroughput = rows.length ? rows.reduce((s,r) => s + (Number(r.avg_ton_per_hour)||0), 0) / rows.length : 0;
  el.innerHTML = [
    statCard('calendar-days','วันทำงาน', fmtNum(days,0), 'วัน'),
    statCard('package','หินป้อนรวม', fmtNum(feedTotal,1), 'ตัน'),
    statCard('timer','Runtime รวม', fmtNum(runtimeTotal,1), 'ชม.'),
    statCard('gauge','Throughput เฉลี่ย', fmtNum(avgThroughput,1), 'ตัน/ชม.'),
  ].join('');
  refreshIcons();
}

function renderSanonYieldChart(type, cfg, rows) {
  const sums = {
    'หิน 6/8': rows.reduce((s,r)=>s+(Number(r.stone_6_8_ton)||0),0),
    'หิน 3/4': rows.reduce((s,r)=>s+(Number(r.stone_3_4_ton)||0),0),
    'หินคลุก': rows.reduce((s,r)=>s+(Number(r.stone_kluk_ton)||0),0),
    'หินฝุ่น': rows.reduce((s,r)=>s+(Number(r.stone_dust_ton)||0),0),
  };
  if (cfg.hasExtra) {
    sums['หิน 3/8'] = rows.reduce((s,r)=>s+(Number(r.stone_3_8_ton)||0),0);
    sums['หิน 2 พิเศษ'] = rows.reduce((s,r)=>s+(Number(r.stone_special2_ton)||0),0);
  }
  renderYieldDonutBlock(type, sums);
  renderProdTonsBlock(type, sums);
}

