let _droneFactoriesCache = null;
let _droneState = { month: new Date().getMonth() + 1, year: new Date().getFullYear(), factoryId: 'all' };
function renderDashboardDrone(container) {
  container.innerHTML = `
    <div class="dash-dark-bg -m-4 sm:-m-6 p-4 sm:p-6 min-h-full">
    <div class="space-y-6 fade-in">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <h2 class="text-lg font-semibold dash-dark-text flex items-center gap-2"><i data-lucide="plane" class="w-5 h-5 text-cyan-400"></i>สต็อคหินบินโดรนประจำเดือน</h2>
        <div class="flex flex-wrap items-center gap-2" id="drone-filters">
          <select id="drone-month-select" class="dash-dark-input rounded-xl px-3 py-1.5 text-xs">
            ${Array.from({length:12},(_, i) => i+1).map(m => `<option value="${m}" ${m===_droneState.month?'selected':''}>${monthNameTH(m)}</option>`).join('')}
          </select>
          <select id="drone-year-select" class="dash-dark-input rounded-xl px-3 py-1.5 text-xs">
            ${Array.from({length:5},(_, i) => new Date().getFullYear()-i).map(y => `<option value="${y}" ${y===_droneState.year?'selected':''}>${y}</option>`).join('')}
          </select>
          <div class="flex dash-dark-pill-wrap rounded-xl p-1" style="background:#0A192F; border:1px solid #1d3a5f;" id="drone-factory-toggle"></div>
        </div>
      </div>
      <div id="drone-chart-block">${skeletonBlockDark()}</div>
      <div id="drone-table-block">${skeletonBlockDark('h-56')}</div>
    </div>
    </div>`;
  refreshIcons();

  document.getElementById('drone-month-select').addEventListener('change', e => { _droneState.month = Number(e.target.value); loadDroneData(); });
  document.getElementById('drone-year-select').addEventListener('change', e => { _droneState.year = Number(e.target.value); loadDroneData(); });

  loadDroneFactories().then(loadDroneData);
}

async function loadDroneFactories() {
  if (_droneFactoriesCache) { populateDroneFactorySelect(); return; }
  try {
    const { data, error } = await db.from('factories').select('id, name').eq('status','active');
    if (error) throw error;
    // dedupe ด้วย Map ตาม id กันกรณีข้อมูลซ้ำจาก join/insert ซ้ำ
    const map = new Map();
    (data || []).forEach(f => { if (!map.has(f.id)) map.set(f.id, f); });
    _droneFactoriesCache = Array.from(map.values());
  } catch (err) {
    console.error(err);
    _droneFactoriesCache = [];
  }
  populateDroneFactorySelect();
}
function populateDroneFactorySelect() {
  const wrap = document.getElementById('drone-factory-toggle');
  if (!wrap) return;
  // ถ้ายังไม่เลือกโรงงานเลย ให้ default เป็นโรงงานแรกในรายการ (ไม่มีตัวเลือก "ทุกโรงงาน" ตามที่ระบุ)
  if (_droneState.factoryId === 'all' && _droneFactoriesCache.length) _droneState.factoryId = _droneFactoriesCache[0].id;
  wrap.innerHTML = _droneFactoriesCache.map(f => `
    <button data-factory-id="${f.id}" class="drone-factory-btn px-3 py-1.5 rounded-lg text-xs font-medium transition ${f.id===_droneState.factoryId?'dash-dark-pill-active':'dash-dark-text-muted'}">${escapeHtml(f.name)}</button>
  `).join('');
  qsa('.drone-factory-btn', wrap).forEach(btn => {
    btn.addEventListener('click', () => {
      _droneState.factoryId = btn.getAttribute('data-factory-id');
      populateDroneFactorySelect();
      loadDroneData();
    });
  });
}

async function loadDroneData() {
  const chartBlock = document.getElementById('drone-chart-block');
  const tableBlock = document.getElementById('drone-table-block');
  try {
    if (!_droneState._initialized) {
      const { data: latestDrone } = await db.from('drone_stock').select('stock_year, stock_month').order('stock_year', { ascending: false }).order('stock_month', { ascending: false }).limit(1);
      if (latestDrone && latestDrone.length) {
        _droneState.year = latestDrone[0].stock_year;
        _droneState.month = latestDrone[0].stock_month;
        const mSel = document.getElementById('drone-month-select');
        const ySel = document.getElementById('drone-year-select');
        if (mSel) mSel.value = String(_droneState.month);
        if (ySel) ySel.value = String(_droneState.year);
      }
      _droneState._initialized = true;
    }
    let query = db.from('drone_stock').select('*, factories(name)').eq('stock_month', _droneState.month).eq('stock_year', _droneState.year);
    if (_droneState.factoryId !== 'all') query = query.eq('factory_id', _droneState.factoryId);
    const { data, error } = await query;
    if (error) throw error;
    const rows = data || [];

    if (!rows.length) {
      chartBlock.innerHTML = `<div class="dash-dark-card rounded-2xl p-8 text-center dash-dark-text-muted text-sm">ไม่มีข้อมูลสต็อกในเดือน/ปีที่เลือก</div>`;
      tableBlock.innerHTML = '';
      refreshIcons();
      return;
    }

    const byType = {};
    rows.forEach(r => { byType[r.stone_type || 'ไม่ระบุ'] = (byType[r.stone_type || 'ไม่ระบุ'] || 0) + (Number(r.ton_amount)||0); });
    chartBlock.innerHTML = `<div class="dash-dark-card rounded-2xl p-5"><h3 class="text-sm font-medium dash-dark-text-muted mb-3">สต็อกตามประเภทหิน (ตัน)</h3><div class="relative h-72"><canvas id="drone-canvas"></canvas></div></div>`;
    refreshIcons();
    const ctx = document.getElementById('drone-canvas');
    destroyChart('drone');
    chartRegistry['drone'] = new Chart(ctx, {
      type: 'bar',
      data: { labels: Object.keys(byType), datasets: [{ label: 'ตัน', data: Object.values(byType), backgroundColor: '#39FF14', borderRadius: 8 }] },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true, ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } }, x: { ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } } }, layout: { padding: { top: 18 } } },
      plugins: [barValueLabelsPlugin]
    });

    // ตาราง "รายละเอียดสต็อก" — filter จริงตามโรงงานที่เลือกจาก dropdown (rows มาจาก query ที่ filter ด้วย _droneState.factoryId แล้ว)
    tableBlock.innerHTML = `
      <div class="dash-dark-card rounded-2xl p-5 overflow-x-auto">
        <h3 class="text-sm font-medium dash-dark-text-muted mb-3">รายละเอียดสต็อก${_droneState.factoryId !== 'all' && _droneFactoriesCache ? ' — ' + escapeHtml((_droneFactoriesCache.find(f=>f.id===_droneState.factoryId)||{}).name || '') : ''}</h3>
        <table class="w-full text-sm">
          <thead><tr class="text-left dash-dark-text-muted border-b dash-dark-border">
            <th class="py-2 pr-3">โรงงาน</th><th class="py-2 pr-3">ประเภทหิน</th><th class="py-2 pr-3">ปริมาตร (ลบ.ม.)</th><th class="py-2 pr-3">ถพ.</th><th class="py-2 pr-3">น้ำหนัก (ตัน)</th>
          </tr></thead>
          <tbody>
            ${rows.map(r => `
              <tr class="border-b dash-dark-border dash-dark-row-hover dash-dark-text">
                <td class="py-2 pr-3">${escapeHtml(r.factories ? r.factories.name : '-')}</td>
                <td class="py-2 pr-3">${escapeHtml(r.stone_type || '-')}</td>
                <td class="py-2 pr-3">${fmtNum(r.volume_cum,2)}</td>
                <td class="py-2 pr-3">${fmtNum(r.bulk_density,2)}</td>
                <td class="py-2 pr-3 font-medium">${fmtNum(r.ton_amount,2)}</td>
              </tr>`).join('')}
          </tbody>
        </table>
      </div>`;
    refreshIcons();
  } catch (err) {
    console.error(err);
    chartBlock.innerHTML = errorBlockDark();
    tableBlock.innerHTML = '';
    refreshIcons();
  }
}

