async function loadSalesFactories() {
  if (_salesFactoriesCache) { populateSalesFactorySelect(); return; }
  try {
    const { data, error } = await db.from('factories').select('id, name').eq('status', 'active');
    if (error) throw error;
    const map = new Map();
    (data || []).forEach(f => { if (!map.has(f.id)) map.set(f.id, f); });
    _salesFactoriesCache = Array.from(map.values());
  } catch (err) {
    console.error(err);
    _salesFactoriesCache = [];
  }
  populateSalesFactorySelect();
}
function populateSalesFactorySelect() {
  const wrap = document.getElementById('sales-factory-toggle');
  if (!wrap) return;
  wrap.innerHTML = `<button data-factory-id="all" class="sales-factory-btn px-3 py-1.5 rounded-lg text-xs font-medium transition ${_salesState.factoryId==='all'?'dash-dark-pill-active':'dash-dark-text-muted'}">ทุกโรงงาน</button>` +
    _salesFactoriesCache.map(f => `
    <button data-factory-id="${f.id}" class="sales-factory-btn px-3 py-1.5 rounded-lg text-xs font-medium transition ${f.id===_salesState.factoryId?'dash-dark-pill-active':'dash-dark-text-muted'}">${escapeHtml(f.name)}</button>
  `).join('');
  qsa('.sales-factory-btn', wrap).forEach(btn => {
    btn.addEventListener('click', () => {
      _salesState.factoryId = btn.getAttribute('data-factory-id');
      populateSalesFactorySelect();
      loadSalesData();
    });
  });
}

async function loadSalesData() {
  const statsEl = document.getElementById('sales-stat-cards');
  const chartEl = document.getElementById('sales-chart-block');
  const monthlyChartEl = document.getElementById('sales-monthly-chart-block');
  const tableEl = document.getElementById('sales-table-block');
  try {
    if (!_salesRangeState._initialized) {
      const latest = await detectLatestDataMonth('sales', 'sale_date');
      applyLatestMonthToState(_salesRangeState, 'sales', latest);
      _salesRangeState._initialized = true;
    }
    const { from, to } = rangeToDates(_salesRangeState);
    let query = db
      .from('sales')
      .select('*, factories(name)')
      .gte('sale_date', from)
      .lte('sale_date', to)
      .order('sale_date', { ascending: false });
    if (_salesState.factoryId !== 'all') query = query.eq('factory_id', _salesState.factoryId);
    const { data, error } = await query;
    if (error) throw error;
    const rows = data || [];

    // --- previous period fetch (for MoM comparison) ---
    let byFactoryPrev = {}, totalQtyPrev = 0;
    try {
      const { mode, year, month, date } = _salesRangeState;
      let prevFrom, prevTo;
      if (mode === 'day') {
        const d = new Date(date); d.setDate(d.getDate() - 1);
        prevFrom = prevTo = d.toISOString().slice(0,10);
      } else if (mode === 'year') {
        prevFrom = `${year-1}-01-01`; prevTo = `${year-1}-12-31`;
      } else {
        const pm = month === 1 ? 12 : month - 1;
        const py = month === 1 ? year - 1 : year;
        prevFrom = `${py}-${pad2(pm)}-01`;
        prevTo = `${py}-${pad2(pm)}-${pad2(new Date(py, pm, 0).getDate())}`;
      }
      let prevQ = db.from('sales').select('*, factories(name)').gte('sale_date', prevFrom).lte('sale_date', prevTo);
      if (_salesState.factoryId !== 'all') prevQ = prevQ.eq('factory_id', _salesState.factoryId);
      const { data: pData } = await prevQ;
      (pData || []).forEach(r => {
        const fn = r.factories ? r.factories.name : (r.factory_code || 'ไม่ระบุ');
        byFactoryPrev[fn] = (byFactoryPrev[fn] || 0) + (Number(r.quantity_ton) || 0);
        totalQtyPrev += (Number(r.quantity_ton) || 0);
      });
    } catch(e) { console.error(e); }

    // --- aggregations ---
    const totalQty = rows.reduce((s,r) => s + (Number(r.quantity_ton)||0), 0);
    const hasPrice = rows.some(r => r.price_per_ton != null && Number(r.price_per_ton) > 0);
    const totalValue = rows.reduce((s,r) => s + (Number(r.total_value)||0), 0);
    const byFactory = {};
    const byStoneType = {};
    rows.forEach(r => {
      const fname = r.factories ? r.factories.name : (r.factory_code || 'ไม่ระบุ');
      byFactory[fname] = (byFactory[fname] || 0) + (Number(r.quantity_ton)||0);
      const st = r.stone_type || 'ไม่ระบุ';
      byStoneType[st] = (byStoneType[st] || 0) + (Number(r.quantity_ton)||0);
    });
    const topFactory = Object.entries(byFactory).sort((a,b)=>b[1]-a[1])[0];
    const topStone = Object.entries(byStoneType).sort((a,b)=>b[1]-a[1])[0];

    // --- stat cards ---
    statsEl.innerHTML = [
      statCard('package','ยอดขายรวม', fmtNum(totalQty,1), 'ตัน'),
      statCard('gem','ประเภทหินขายดีสุด', topStone ? escapeHtml(topStone[0]) : '-', topStone ? fmtNum(topStone[1],1)+' ตัน' : ''),
      statCard('factory','โรงงานขายมากสุด', topFactory ? escapeHtml(topFactory[0]) : '-', topFactory ? fmtNum(topFactory[1],1)+' ตัน' : ''),
      hasPrice
        ? statCard('banknote','มูลค่าขายรวม', fmtNum(totalValue,0), 'บาท')
        : statCard('banknote','มูลค่าขายรวม', '-', 'ยังไม่มีข้อมูลราคา'),
    ].join('');
    refreshIcons();

    if (!rows.length) {
      const emptyHtml = `<div class="dash-dark-card rounded-2xl p-8 text-center dash-dark-text-muted text-sm">ไม่มีข้อมูลยอดขายในช่วงเวลานี้</div>`;
      chartEl.innerHTML = monthlyChartEl.innerHTML = tableEl.innerHTML = emptyHtml;
      refreshIcons();
      return;
    }

    // --- chart 1: Stacked bar — ยอดขายแยกโรงงาน สีตามประเภทหิน ---
    const factories = Object.keys(byFactory).sort();
    const allStoneTypes = Object.keys(byStoneType).sort((a,b) => byStoneType[b] - byStoneType[a]);
    const byFactoryStone = {};
    factories.forEach(f => { byFactoryStone[f] = {}; });
    rows.forEach(r => {
      const fname = r.factories ? r.factories.name : (r.factory_code || 'ไม่ระบุ');
      const st = r.stone_type || 'ไม่ระบุ';
      if (!byFactoryStone[fname]) byFactoryStone[fname] = {};
      byFactoryStone[fname][st] = (byFactoryStone[fname][st] || 0) + (Number(r.quantity_ton)||0);
    });
    const stackedColors = ['#378ADD','#1D9E75','#BA7517','#D85A30','#D4537E','#7F77DD','#39FF14','#888780'];
    // Grouped chart: แสดงเฉพาะ top stone types ที่มีข้อมูล (ไม่เกิน 6 ชนิด เพื่อไม่ให้แน่นเกิน)
    const displayStoneTypes = allStoneTypes.slice(0, 6);
    const groupedDatasets = displayStoneTypes.map((st, i) => ({
      label: st,
      data: factories.map(f => byFactoryStone[f][st] || 0),
      backgroundColor: stackedColors[i % stackedColors.length],
      borderRadius: 4,
      borderSkipped: false,
    }));
    chartEl.innerHTML = `<div class="dash-dark-card rounded-2xl p-5"><h3 class="text-sm font-medium dash-dark-text-muted mb-3">ยอดขายแยกโรงงาน (ตัน) — เปรียบเทียบชนิดหิน</h3><div class="relative" style="height:320px"><canvas id="sales-canvas"></canvas></div></div>`;
    refreshIcons();
    destroyChart('sales');
    chartRegistry['sales'] = new Chart(document.getElementById('sales-canvas'), {
      type: 'bar',
      data: { labels: factories, datasets: groupedDatasets },
      options: {
        responsive: true, maintainAspectRatio: false,
        layout: { padding: { top: 22 } },
        plugins: { legend: { position: 'bottom', labels: { color: '#94a3b8', font: { size: 11 }, padding: 8, boxWidth: 12 } } },
        scales: {
          x: { ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.06)' } },
          y: { beginAtZero: true, ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } }
        }
      },
      plugins: [barValueLabelsPlugin]
    });

    // --- chart 2: Donut — สัดส่วนประเภทหิน + factory breakdown ---
    const topStones = Object.entries(byStoneType).sort((a,b) => b[1]-a[1]).slice(0, 8);
    const donutTotal = topStones.reduce((s,[,v]) => s+v, 0);
    const factoryBreakdownHtml = Object.entries(byFactory).sort((a,b)=>b[1]-a[1]).map(([fname,fval]) => {
      const pct = totalQty ? fval/totalQty*100 : 0;
      return `<div class="mb-2.5">
        <div class="flex justify-between items-center text-xs mb-1">
          <span class="dash-dark-text font-medium">${escapeHtml(fname)}</span>
          <span style="color:#38bdf8" class="font-semibold">${fmtNum(pct,1)}%</span>
        </div>
        <div class="h-1.5 rounded-full overflow-hidden" style="background:rgba(255,255,255,0.1)">
          <div class="h-1.5 rounded-full" style="background:#378ADD;width:${Math.min(Math.round(pct),100)}%"></div>
        </div>
        <div class="text-xs dash-dark-text-muted mt-0.5">${fmtNum(fval,1)} ตัน</div>
      </div>`;
    }).join('');
    monthlyChartEl.innerHTML = `<div class="dash-dark-card rounded-2xl p-5">
      <h3 class="text-sm font-medium dash-dark-text-muted mb-4">สัดส่วนประเภทหิน</h3>
      <div class="flex flex-col sm:flex-row items-start gap-4">
        <div class="relative flex-shrink-0" style="height:200px;width:190px"><canvas id="sales-donut-canvas"></canvas></div>
        <div class="flex flex-col gap-1.5 flex-1 min-w-0 self-center">
          ${topStones.map(([st,v],i)=>`<div class="flex items-center gap-2 text-xs">
            <span class="w-2.5 h-2.5 rounded-full flex-shrink-0" style="background:${stackedColors[i%stackedColors.length]}"></span>
            <span class="dash-dark-text truncate flex-1">${escapeHtml(st)}</span>
            <span class="dash-dark-text-muted whitespace-nowrap">${fmtNum(v,1)} ตัน</span>
            <span class="whitespace-nowrap w-11 text-right font-semibold" style="color:#38bdf8">${donutTotal?fmtNum(v/donutTotal*100,1):0}%</span>
          </div>`).join('')}
        </div>
        <div class="flex-shrink-0 border-l dash-dark-border pl-4 self-stretch" style="min-width:160px">
          <div class="text-xs dash-dark-text-muted mb-3 font-semibold tracking-wider uppercase">สัดส่วนตามโรงงาน</div>
          ${factoryBreakdownHtml}
        </div>
      </div>
    </div>`;
    refreshIcons();
    destroyChart('sales-monthly');
    chartRegistry['sales-monthly'] = new Chart(document.getElementById('sales-donut-canvas'), {
      type: 'doughnut',
      data: {
        labels: topStones.map(([st]) => st),
        datasets: [{ data: topStones.map(([,v]) => v), backgroundColor: stackedColors.slice(0, topStones.length), borderWidth: 2, borderColor: '#0A192F' }]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: { callbacks: { label: ctx => ` ${fmtNum(ctx.raw,1)} ตัน (${donutTotal?fmtNum(ctx.raw/donutTotal*100,1):0}%)` } }
        },
        cutout: '62%'
      }
    });

    // --- chart 3: Line trend แยกโรงงาน + pivot table ใน tableEl ---
    const isYearMode = _salesRangeState && _salesRangeState.mode === 'year';
    const trendTitle = isYearMode ? 'แนวโน้มยอดขายรายเดือน แยกโรงงาน (ตัน)' : 'แนวโน้มยอดขายรายวัน แยกโรงงาน (ตัน)';
    const factoryLineColors = ['#38bdf8','#34d399','#fb923c','#a78bfa','#f472b6','#facc15'];
    // group by date key + factory
    const byKeyFactory = {};
    rows.forEach(r => {
      const fname = r.factories ? r.factories.name : (r.factory_code || 'ไม่ระบุ');
      const k = isYearMode ? String(r.sale_date).slice(0,7) : String(r.sale_date).slice(0,10);
      if (!byKeyFactory[k]) byKeyFactory[k] = {};
      byKeyFactory[k][fname] = (byKeyFactory[k][fname] || 0) + (Number(r.quantity_ton) || 0);
    });
    const allTrendKeys = Object.keys(byKeyFactory).sort();
    const trendLabels = isYearMode
      ? allTrendKeys.map(k => monthNameTH(Number(k.slice(5,7))).slice(0,3))
      : allTrendKeys.map(k => fmtDate(k));
    const trendDatasets = factories.map((fname, i) => ({
      label: fname,
      data: allTrendKeys.map(k => byKeyFactory[k][fname] || 0),
      borderColor: factoryLineColors[i % factoryLineColors.length],
      backgroundColor: factoryLineColors[i % factoryLineColors.length] + '22',
      borderWidth: 2,
      pointRadius: allTrendKeys.length > 25 ? 2 : 4,
      pointHoverRadius: 6,
      tension: 0.3,
      fill: false,
    }));
    tableEl.innerHTML = `
      <div class="grid grid-cols-1 sm:grid-cols-2 gap-4">
        ${factories.map((fname, fi) => {
          const fColor = factoryLineColors[fi % factoryLineColors.length];
          const fTotal = byFactory[fname] || 0;
          const periodLabel = isYearMode ? 'รายเดือน' : 'รายวัน';
          return `<div class="dash-dark-card rounded-2xl p-4">
            <div class="flex items-center justify-between mb-1">
              <div class="flex items-center gap-2">
                <span class="w-3 h-3 rounded-full" style="background:${fColor}"></span>
                <span class="text-sm font-semibold" style="color:${fColor}">${escapeHtml(fname)}</span>
              </div>
              <span class="text-xs dash-dark-text-muted font-medium">รวม ${fmtNum(fTotal,1)} ตัน</span>
            </div>
            <div class="text-xs dash-dark-text-muted mb-3">แนวโน้มยอดขาย${periodLabel} ${escapeHtml(fname)} (ตัน)</div>
            <div class="relative" style="height:160px"><canvas id="sales-ftrend-${fi}"></canvas></div>
          </div>`;
        }).join('')}
      </div>
      <div class="dash-dark-card rounded-2xl p-5 overflow-x-auto">
        <h3 class="text-sm font-medium dash-dark-text-muted mb-3">ยอดขาย — โรงงาน × ประเภทหิน (ตัน)</h3>
        <table class="w-full text-sm">
          <thead><tr class="text-left dash-dark-text-muted border-b dash-dark-border">
            <th class="py-2 pr-3">โรงงาน</th>
            ${allStoneTypes.map(st=>`<th class="py-2 pr-3 text-right">${escapeHtml(st)}</th>`).join('')}
            <th class="py-2 pr-3 text-right">รวม (ตัน)</th>
            ${hasPrice ? '<th class="py-2 pr-3 text-right">มูลค่า (บาท)</th>' : ''}
          </tr></thead>
          <tbody>
            ${factories.map(f => {
              const fVal = rows.filter(r2 => (r2.factories?r2.factories.name:(r2.factory_code||''))=== f).reduce((s,r2)=>s+(Number(r2.total_value)||0),0);
              return `<tr class="border-b dash-dark-border dash-dark-row-hover dash-dark-text">
                <td class="py-2 pr-3 font-medium">${escapeHtml(f)}</td>
                ${allStoneTypes.map(st=>`<td class="py-2 pr-3 text-right">${byFactoryStone[f][st]?fmtNum(byFactoryStone[f][st],1):'-'}</td>`).join('')}
                <td class="py-2 pr-3 text-right font-semibold">${fmtNum(byFactory[f],1)}</td>
                ${hasPrice ? `<td class="py-2 pr-3 text-right">${fVal>0?fmtNum(fVal,0):'-'}</td>` : ''}
              </tr>`;
            }).join('')}
            <tr class="dash-dark-text font-semibold" style="border-top:2px solid #1d3a5f">
              <td class="py-2 pr-3">รวม</td>
              ${allStoneTypes.map(st=>`<td class="py-2 pr-3 text-right">${fmtNum(byStoneType[st]||0,1)}</td>`).join('')}
              <td class="py-2 pr-3 text-right">${fmtNum(totalQty,1)}</td>
              ${hasPrice ? `<td class="py-2 pr-3 text-right">${fmtNum(totalValue,0)}</td>` : ''}
            </tr>
          </tbody>
        </table>
        ${(() => {
          const hasPrev = totalQtyPrev > 0 || Object.keys(byFactoryPrev).length > 0;
          if (!hasPrev) return '';
          const periodLabel = _salesRangeState.mode === 'day' ? 'วันก่อน' : _salesRangeState.mode === 'year' ? 'ปีก่อน' : 'เดือนก่อน';
          const totalDiff = totalQty - totalQtyPrev;
          const mkDiff = (cur, prev) => {
            if (prev === 0) return `<span class="dash-dark-text-muted">-</span>`;
            const d = cur - prev;
            const pct = prev ? (d/prev*100) : 0;
            const col = d > 0 ? '#34d399' : d < 0 ? '#f87171' : '#94a3b8';
            const arrow = d > 0 ? '↑' : d < 0 ? '↓' : '=';
            return `<span style="color:${col}" class="font-semibold">${arrow} ${fmtNum(Math.abs(d),0)}</span> <span class="dash-dark-text-muted text-xs">(${d>=0?'+':''}${fmtNum(pct,1)}%)</span>`;
          };
          return `
          <div class="mt-4 pt-3 border-t dash-dark-border">
            <div class="text-xs font-semibold dash-dark-text-muted mb-3 tracking-wider uppercase">เทียบ${periodLabel}</div>
            <div class="grid grid-cols-2 sm:grid-cols-${Math.min(factories.length+1,6)} gap-3">
              <div class="dash-dark-card-inner rounded-xl p-2.5 text-xs" style="background:rgba(255,255,255,0.04)">
                <div class="dash-dark-text-muted mb-1">รวมทั้งหมด</div>
                <div>${mkDiff(totalQty, totalQtyPrev)}</div>
              </div>
              ${factories.map(f => `
              <div class="dash-dark-card-inner rounded-xl p-2.5 text-xs" style="background:rgba(255,255,255,0.04)">
                <div class="dash-dark-text-muted mb-1 truncate">${escapeHtml(f)}</div>
                <div>${mkDiff(byFactory[f]||0, byFactoryPrev[f]||0)}</div>
              </div>`).join('')}
            </div>
          </div>`;
        })()}
      </div>`;
    refreshIcons();
    destroyChart('sales-trend');
    // สร้าง chart แยกของแต่ละโรงงาน
    factories.forEach((fname, fi) => {
      destroyChart(`sales-ftrend-${fi}`);
      const fColor = factoryLineColors[fi % factoryLineColors.length];
      const fData = allTrendKeys.map(k => (byKeyFactory[k] && byKeyFactory[k][fname]) || 0);
      chartRegistry[`sales-ftrend-${fi}`] = new Chart(document.getElementById(`sales-ftrend-${fi}`), {
        type: 'bar',
        data: {
          labels: trendLabels,
          datasets: [{ label: fname, data: fData, backgroundColor: fColor + 'aa', borderColor: fColor, borderWidth: 1, borderRadius: 3 }]
        },
        options: {
          responsive: true, maintainAspectRatio: false,
          plugins: {
            legend: { display: false },
            tooltip: { callbacks: { label: ctx => ` ${fmtNum(ctx.raw, 1)} ตัน` } }
          },
          scales: {
            y: { beginAtZero: true, ticks: { color: '#94a3b8', font: { size: 10 } }, grid: { color: 'rgba(255,255,255,0.07)' } },
            x: { ticks: { color: '#94a3b8', font: { size: 10 }, autoSkip: true, maxRotation: 35, maxTicksLimit: 12 }, grid: { display: false } }
          }
        },
        plugins: [barValueLabelsPlugin]
      });
    });

  } catch (err) {
    console.error(err);
    statsEl.innerHTML = [1,2,3,4].map(() => errorBlockDark()).join('');
    chartEl.innerHTML = monthlyChartEl.innerHTML = tableEl.innerHTML = '';
    refreshIcons();
  }
}

// =====================================================================
// SECTION 17: DASHBOARD รถตักไฟฟ้า
// =====================================================================
const _loaderRangeState = defaultRangeState();
const _loaderDashState = { loaderName: 'all' };
let _loaderNamesCache = null;

function renderDashboardLoader(container) {
  container.innerHTML = `
    <div class="dash-dark-bg -m-4 sm:-m-6 p-4 sm:p-6 min-h-full">
    <div class="space-y-6 fade-in">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <h2 class="text-lg font-semibold dash-dark-text flex items-center gap-2"><i data-lucide="truck" class="w-5 h-5 text-cyan-400"></i>รถตักไฟฟ้า</h2>
        <div class="flex flex-wrap items-center gap-2">
          <select id="loader-name-select" class="dash-dark-input rounded-xl px-3 py-1.5 text-xs">
            <option value="all">ทุกคัน</option>
          </select>
          ${rangeControlHtml('loader', _loaderRangeState)}
        </div>
      </div>
      <div id="loader-stat-cards" class="grid grid-cols-2 sm:grid-cols-4 gap-4">${[1,2,3,4].map(skeletonCardDark).join('')}</div>
      <div id="loader-ratio-block"></div>
      <div id="loader-chart-block">${skeletonBlockDark()}</div>
      <div class="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <div id="loader-cmp-cost-block">${skeletonBlockDark()}</div>
        <div id="loader-cmp-charge-block">${skeletonBlockDark()}</div>
        <div id="loader-cmp-workhour-block">${skeletonBlockDark()}</div>
      </div>
      <div id="loader-breakdown-block">${skeletonBlockDark('h-56')}</div>
    </div>
    </div>`;
  refreshIcons();
  attachRangeControlEvents('loader', _loaderRangeState, () => renderDashboardLoader(container));
  document.getElementById('loader-name-select').addEventListener('change', e => {
    _loaderDashState.loaderName = e.target.value;
    loadLoaderData();
  });
  loadLoaderNames().then(loadLoaderData);
}

async function loadLoaderNames() {
  if (_loaderNamesCache) { populateLoaderNameSelect(); return; }
  try {
    const { data, error } = await db.from('electric_loader').select('loader_name');
    if (error) throw error;
    const set = new Set((data || []).map(r => r.loader_name).filter(Boolean));
    _loaderNamesCache = Array.from(set).sort();
  } catch (err) {
    console.error(err);
    _loaderNamesCache = [];
  }
  populateLoaderNameSelect();
}
function populateLoaderNameSelect() {
  const sel = document.getElementById('loader-name-select');
  if (!sel) return;
  sel.innerHTML = `<option value="all">ทุกคัน</option>` + _loaderNamesCache.map(n => `<option value="${escapeHtml(n)}" ${n===_loaderDashState.loaderName?'selected':''}>${escapeHtml(n)}</option>`).join('');
}

// custom Chart.js plugin: วาดตัวเลขชั่วโมงทำงาน (บนแท่ง) และค่าไฟรวม (บนจุดเส้น) สำหรับกราฟ "ชั่วโมงทำงาน เทียบ ค่าไฟรวม"
const loaderComboDataLabelsPlugin = {
  id: 'loaderComboDataLabelsPlugin',
  afterDatasetsDraw(chart) {
    const { ctx } = chart;
    ctx.save();
    ctx.font = '600 10px Kanit, sans-serif';
    ctx.textAlign = 'center';
    chart.data.datasets.forEach((dataset, dsIndex) => {
      const meta = chart.getDatasetMeta(dsIndex);
      if (meta.hidden) return;
      meta.data.forEach((point, i) => {
        const val = Number(dataset.data[i]) || 0;
        if (!val) return;
        const pos = point.tooltipPosition ? point.tooltipPosition() : { x: point.x, y: point.y };
        ctx.shadowColor = 'rgba(0,0,0,0.8)';
        ctx.shadowBlur = 3;
        if (dataset.type === 'bar') {
          ctx.fillStyle = '#ffffff';
          ctx.textBaseline = 'bottom';
          ctx.fillText(fmtNum(val, 1), pos.x, pos.y - 4);
        } else {
          ctx.fillStyle = '#fde68a';
          ctx.textBaseline = 'bottom';
          ctx.fillText(fmtNum(val, 0), pos.x, pos.y - 8);
        }
        ctx.shadowBlur = 0;
      });
    });
    ctx.restore();
  }
};

async function loadLoaderData() {
  const statsEl = document.getElementById('loader-stat-cards');
  const ratioEl = document.getElementById('loader-ratio-block');
  const chartEl = document.getElementById('loader-chart-block');
  const cmpCostEl = document.getElementById('loader-cmp-cost-block');
  const cmpChargeEl = document.getElementById('loader-cmp-charge-block');
  const cmpWorkhourEl = document.getElementById('loader-cmp-workhour-block');
  const breakdownEl = document.getElementById('loader-breakdown-block');
  try {
    if (!_loaderRangeState._initialized) {
      const latest = await detectLatestDataMonth('electric_loader', 'work_date');
      applyLatestMonthToState(_loaderRangeState, 'loader', latest);
      _loaderRangeState._initialized = true;
    }
    const { from, to } = rangeToDates(_loaderRangeState);
    let query = db
      .from('electric_loader')
      .select('*')
      .eq('status', 'approved')
      .gte('work_date', from)
      .lte('work_date', to)
      .order('work_date', { ascending: true });
    if (_loaderDashState.loaderName !== 'all') query = query.eq('loader_name', _loaderDashState.loaderName);
    const { data, error } = await query;
    if (error) throw error;
    const rows = data || [];
    // คำนวณ Machine Hours จริงต่อ record: ใช้ machine_hour_stop - machine_hour_start เป็นหลัก
    // fallback ไปที่ machine_hour_total → total_work_hour ตามลำดับ
    const getMH = r => {
      if (r.machine_hour_start != null && r.machine_hour_stop != null)
        return Math.max(0, r.machine_hour_stop - r.machine_hour_start);
      if (r.machine_hour_total != null) return Number(r.machine_hour_total) || 0;
      return Number(r.total_work_hour) || 0;
    };

    const totalWorkHour = rows.reduce((s,r) => s + getMH(r), 0);
    const totalChargeMin = rows.reduce((s,r) => s + (Number(r.charge_minutes)||0), 0);
    const totalCost = rows.reduce((s,r) => s + (Number(r.electric_cost_baht)||0), 0);
    const loaders = new Set(rows.map(r => r.loader_name).filter(Boolean));

    const costPerHour = totalWorkHour > 0 ? totalCost / totalWorkHour : 0;

    statsEl.innerHTML = [
      statCard('timer','ชั่วโมงทำงานรวม', fmtNum(totalWorkHour,1), 'ชม.'),
      statCard('battery-charging','เวลาชาร์จรวม', fmtNum(totalChargeMin,0), 'นาที'),
      statCard('coins','ค่าไฟรวม', fmtNum(totalCost,0), 'บาท'),
      statCard('truck','จำนวนรถตัก', fmtNum(loaders.size,0), 'คัน'),
    ].join('');
    refreshIcons();

    ratioEl.innerHTML = `
      <div class="dash-dark-card rounded-2xl p-5 flex items-center justify-between">
        <span class="text-sm font-medium dash-dark-text-muted flex items-center gap-2"><i data-lucide="calculator" class="w-4 h-4 text-cyan-400"></i>ค่าไฟรวม / ชั่วโมงทำงานรวม</span>
        <span class="text-lg font-semibold text-amber-400">${fmtNum(costPerHour,2)} บาท/ชม.</span>
      </div>`;
    refreshIcons();

    if (!rows.length) {
      chartEl.innerHTML = `<div class="dash-dark-card rounded-2xl p-8 text-center dash-dark-text-muted text-sm">ไม่มีข้อมูลรถตักไฟฟ้าในช่วงเวลานี้</div>`;
      cmpCostEl.innerHTML = ''; cmpChargeEl.innerHTML = ''; cmpWorkhourEl.innerHTML = '';
      breakdownEl.innerHTML = '';
      refreshIcons();
      return;
    }

    // กราฟ "ชั่วโมงทำงาน เทียบ ค่าไฟรวม" — รายวัน (month) หรือ รายเดือน (year)
    const isLoaderYearMode = _loaderRangeState && _loaderRangeState.mode === 'year';
    let loaderLabels, loaderWorkData, loaderCostData, loaderChartTitle;
    if (isLoaderYearMode) {
      loaderChartTitle = 'ชั่วโมงทำงาน เทียบ ค่าไฟรวม รายเดือน';
      const monthlyMap = {};
      rows.forEach(r => {
        const key = r.work_date ? String(r.work_date).slice(0, 7) : null;
        if (!key) return;
        if (!monthlyMap[key]) monthlyMap[key] = { workSum: 0, costSum: 0 };
        monthlyMap[key].workSum += getMH(r);
        monthlyMap[key].costSum += Number(r.electric_cost_baht) || 0;
      });
      const keys = Object.keys(monthlyMap).sort();
      loaderLabels = keys.map(k => { const [,m] = k.split('-'); return monthNameTH(Number(m)); });
      loaderWorkData = keys.map(k => Math.round(monthlyMap[k].workSum * 10) / 10);
      loaderCostData = keys.map(k => Math.round(monthlyMap[k].costSum));
    } else {
      loaderChartTitle = 'ชั่วโมงทำงาน เทียบ ค่าไฟรวม รายวัน';
      loaderLabels = rows.map(r => fmtDate(r.work_date));
      loaderWorkData = rows.map(r => Math.round(getMH(r) * 10) / 10);
      loaderCostData = rows.map(r => Number(r.electric_cost_baht) || 0);
    }
    const loaderSuffix = _loaderDashState.loaderName !== 'all' ? ' — ' + escapeHtml(_loaderDashState.loaderName) : '';
    chartEl.innerHTML = `<div class="dash-dark-card rounded-2xl p-5"><h3 class="text-sm font-medium dash-dark-text-muted mb-3">${loaderChartTitle}${loaderSuffix}</h3><div class="relative h-72"><canvas id="loader-canvas"></canvas></div></div>`;
    refreshIcons();
    const ctx = document.getElementById('loader-canvas');
    destroyChart('loader');
    chartRegistry['loader'] = new Chart(ctx, {
      data: {
        labels: loaderLabels,
        datasets: [
          { type: 'bar', label: 'ชั่วโมงทำงาน (ชม.)', data: loaderWorkData, backgroundColor: '#4ade80', yAxisID: 'y', borderRadius: 6 },
          { type: 'line', label: 'ค่าไฟรวม (บาท)', data: loaderCostData, borderColor: '#f59e0b', backgroundColor: '#f59e0b', pointBackgroundColor: '#f59e0b', pointRadius: 4, yAxisID: 'y1', tension: 0.3 },
        ]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        layout: { padding: { top: 22 } },
        plugins: { legend: { labels: { color: '#cbd5e1' } } },
        scales: {
          y: { type: 'linear', position: 'left', title: { display: true, text: 'ชม.', color: '#94a3b8' }, ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' }, suggestedMax: Math.max(...loaderWorkData) * 1.2 || undefined },
          y1: { type: 'linear', position: 'right', title: { display: true, text: 'บาท', color: '#94a3b8' }, ticks: { color: '#94a3b8' }, grid: { drawOnChartArea: false }, suggestedMax: Math.max(...loaderCostData) * 1.3 || undefined },
          x: { ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } },
        }
      },
      plugins: [loaderComboDataLabelsPlugin]
    });

    // 3 กราฟเปรียบเทียบระหว่างรถแต่ละคัน (group by loader_name): electric_cost_baht, charge_kw, total_work_hour
    const byLoaderCost = {};
    const byLoaderChargeKw = {};
    const byLoaderWorkHour = {};
    rows.forEach(r => {
      const name = r.loader_name || 'ไม่ระบุ';
      byLoaderCost[name] = (byLoaderCost[name] || 0) + (Number(r.electric_cost_baht)||0);
      byLoaderChargeKw[name] = (byLoaderChargeKw[name] || 0) + (Number(r.charge_kw)||0);
      byLoaderWorkHour[name] = (byLoaderWorkHour[name] || 0) + getMH(r);
    });
    const names = Object.keys(byLoaderWorkHour);

    cmpCostEl.innerHTML = `<div class="dash-dark-card rounded-2xl p-5"><h3 class="text-sm font-medium dash-dark-text-muted mb-3">ค่าไฟรวมต่อคัน (บาท)</h3><div class="relative h-56"><canvas id="loader-cmp-cost-canvas"></canvas></div></div>`;
    cmpChargeEl.innerHTML = `<div class="dash-dark-card rounded-2xl p-5"><h3 class="text-sm font-medium dash-dark-text-muted mb-3">พลังงานชาร์จรวมต่อคัน (kW)</h3><div class="relative h-56"><canvas id="loader-cmp-charge-canvas"></canvas></div></div>`;
    cmpWorkhourEl.innerHTML = `<div class="dash-dark-card rounded-2xl p-5"><h3 class="text-sm font-medium dash-dark-text-muted mb-3">ชั่วโมงทำงานรวมต่อคัน (ชม.)</h3><div class="relative h-56"><canvas id="loader-cmp-workhour-canvas"></canvas></div></div>`;
    refreshIcons();

    destroyChart('loader-cmp-cost');
    chartRegistry['loader-cmp-cost'] = new Chart(document.getElementById('loader-cmp-cost-canvas'), {
      type: 'bar',
      data: { labels: names, datasets: [{ label: 'บาท', data: names.map(n => byLoaderCost[n]), backgroundColor: '#FFD700', borderRadius: 6 }] },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, layout: { padding: { top: 18 } }, scales: { y: { beginAtZero: true, ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } }, x: { ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } } } },
      plugins: [barValueLabelsPlugin]
    });
    destroyChart('loader-cmp-charge');
    chartRegistry['loader-cmp-charge'] = new Chart(document.getElementById('loader-cmp-charge-canvas'), {
      type: 'bar',
      data: { labels: names, datasets: [{ label: 'kW', data: names.map(n => byLoaderChargeKw[n]), backgroundColor: '#00FFFF', borderRadius: 6 }] },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, layout: { padding: { top: 18 } }, scales: { y: { beginAtZero: true, ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } }, x: { ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } } } },
      plugins: [barValueLabelsPlugin]
    });
    destroyChart('loader-cmp-workhour');
    chartRegistry['loader-cmp-workhour'] = new Chart(document.getElementById('loader-cmp-workhour-canvas'), {
      type: 'bar',
      data: { labels: names, datasets: [{ label: 'ชม.', data: names.map(n => byLoaderWorkHour[n]), backgroundColor: '#39FF14', borderRadius: 6 }] },
      options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, layout: { padding: { top: 18 } }, scales: { y: { beginAtZero: true, ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } }, x: { ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } } } },
      plugins: [barValueLabelsPlugin]
    });

    const breakdownRows = rows.filter(r => (r.breakdown_detail||'').trim());
    breakdownEl.innerHTML = `
      <div class="dash-dark-card rounded-2xl p-5 overflow-x-auto">
        <h3 class="text-sm font-medium dash-dark-text-muted mb-3">รายการเสีย/Breakdown</h3>
        ${breakdownRows.length ? `
        <table class="w-full text-sm">
          <thead><tr class="text-left dash-dark-text-muted border-b dash-dark-border">
            <th class="py-2 pr-3">วันที่</th><th class="py-2 pr-3">รถตัก</th><th class="py-2 pr-3">รายละเอียด</th>
          </tr></thead>
          <tbody>
            ${breakdownRows.map(r => `
              <tr class="border-b dash-dark-border dash-dark-row-hover dash-dark-text">
                <td class="py-2 pr-3">${fmtDate(r.work_date)}</td>
                <td class="py-2 pr-3">${escapeHtml(r.loader_name || '-')}</td>
                <td class="py-2 pr-3">${escapeHtml(r.breakdown_detail)}</td>
              </tr>`).join('')}
          </tbody>
        </table>` : `<p class="text-center dash-dark-text-muted text-sm py-6">ไม่มีรายการเสียในช่วงเวลานี้</p>`}
      </div>`;
    refreshIcons();
  } catch (err) {
    console.error(err);
    statsEl.innerHTML = [1,2,3,4].map(() => errorBlockDark()).join('');
    ratioEl.innerHTML = '';
    chartEl.innerHTML = '';
    cmpCostEl.innerHTML = ''; cmpChargeEl.innerHTML = ''; cmpWorkhourEl.innerHTML = '';
    breakdownEl.innerHTML = '';
    refreshIcons();
  }
}

// =====================================================================
// SECTION 18: DASHBOARD น้ำบาดาล
// =====================================================================
const _waterRangeState = defaultRangeState();
const _waterDashState = { location: 'all' };
let _waterLocationsCache = null;

function renderDashboardWater(container) {
  container.innerHTML = `
    <div class="dash-dark-bg -m-4 sm:-m-6 p-4 sm:p-6 min-h-full">
    <div class="space-y-6 fade-in">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <h2 class="text-lg font-semibold dash-dark-text flex items-center gap-2"><i data-lucide="droplets" class="w-5 h-5 text-cyan-400"></i>น้ำบาดาล</h2>
        <div class="flex flex-wrap items-center gap-2">
          <select id="water-location-select" class="dash-dark-input rounded-xl px-3 py-1.5 text-xs">
            <option value="all">ทุกบ่อ</option>
          </select>
          ${rangeControlHtml('water', _waterRangeState)}
        </div>
      </div>
      <div id="water-stat-cards" class="grid grid-cols-2 sm:grid-cols-3 gap-4">${[1,2,3].map(skeletonCardDark).join('')}</div>
      <div id="water-chart-block">${skeletonBlockDark()}</div>
      <div id="water-table-block">${skeletonBlockDark('h-56')}</div>
    </div>
    </div>`;
  refreshIcons();
  attachRangeControlEvents('water', _waterRangeState, () => renderDashboardWater(container));
  document.getElementById('water-location-select').addEventListener('change', e => {
    _waterDashState.location = e.target.value;
    loadWaterData();
  });
  loadWaterLocations().then(loadWaterData);
}

async function loadWaterLocations() {
  if (_waterLocationsCache) { populateWaterLocationSelect(); return; }
  try {
    const { data, error } = await db.from('groundwater_usage').select('location');
    if (error) throw error;
    const normLoc = s => String(s || '').replace(/\(\s+/g, '(').replace(/\s+\)/g, ')').replace(/\s+/g, ' ').trim();
    const set = new Set((data || []).map(r => normLoc(r.location)).filter(Boolean));
    _waterLocationsCache = Array.from(set).sort();
  } catch (err) {
    console.error(err);
    _waterLocationsCache = [];
  }
  populateWaterLocationSelect();
}
function populateWaterLocationSelect() {
  const sel = document.getElementById('water-location-select');
  if (!sel) return;
  sel.innerHTML = `<option value="all">ทุกบ่อ</option>` + _waterLocationsCache.map(loc => `<option value="${escapeHtml(loc)}" ${loc===_waterDashState.location?'selected':''}>${escapeHtml(loc)}</option>`).join('');
}

async function loadWaterData() {
  const statsEl = document.getElementById('water-stat-cards');
  const chartEl = document.getElementById('water-chart-block');
  const tableEl = document.getElementById('water-table-block');
  try {
    if (!_waterRangeState._initialized) {
      const latest = await detectLatestDataMonth('groundwater_usage', 'usage_date');
      applyLatestMonthToState(_waterRangeState, 'water', latest);
      _waterRangeState._initialized = true;
    }
    const { from, to } = rangeToDates(_waterRangeState);
    let query = db
      .from('groundwater_usage')
      .select('*')
      .gte('usage_date', from)
      .lte('usage_date', to)
      .order('usage_date', { ascending: true });
    const { data, error } = await query;
    if (error) throw error;
    const _normLocDash = s => String(s || '').replace(/\(\s+/g, '(').replace(/\s+\)/g, ')').replace(/\s+/g, ' ').trim();
    const rows = _waterDashState.location === 'all'
      ? (data || [])
      : (data || []).filter(r => _normLocDash(r.location) === _waterDashState.location);

    const totalUsage = rows.reduce((s,r) => s + (Number(r.usage_cum)||0), 0);
    const normLoc0 = s => String(s||'ไม่ระบุ').replace(/\(\s+/g,'(').replace(/\s+\)/g,')').replace(/\s+/g,' ').trim();
    const uniqueWells = new Set(rows.map(r => normLoc0(r.location)));
    const wellCount = uniqueWells.size;
    const avgPerWell = wellCount ? totalUsage / wellCount : 0;
    // บ่อที่ใช้น้ำมากสุด
    const byWell = {};
    rows.forEach(r => { const l = normLoc0(r.location); byWell[l] = (byWell[l]||0) + (Number(r.usage_cum)||0); });
    const topWell = Object.entries(byWell).sort((a,b) => b[1]-a[1])[0];

    statsEl.innerHTML = [
      statCard('droplets','ปริมาณใช้รวม', fmtNum(totalUsage,1), 'ลบ.ม.'),
      statCard('map-pin','จำนวนบ่อที่บันทึก', fmtNum(wellCount,0), 'บ่อ'),
      statCard('gauge','เฉลี่ยต่อบ่อ', fmtNum(avgPerWell,1), 'ลบ.ม./บ่อ'),
    ].join('');
    refreshIcons();

    if (!rows.length) {
      chartEl.innerHTML = `<div class="dash-dark-card rounded-2xl p-8 text-center dash-dark-text-muted text-sm">ไม่มีข้อมูลการใช้น้ำในช่วงเวลานี้</div>`;
      tableEl.innerHTML = '';
      refreshIcons();
      return;
    }

    // normalize location name — ลบช่องว่างภายใน () และ collapse spaces
    const normLoc = s => String(s || 'ไม่ระบุ')
      .replace(/\(\s+/g, '(').replace(/\s+\)/g, ')')
      .replace(/\s+/g, ' ').trim();

    // กราฟเปรียบเทียบของแต่ละบ่อ (group by location) ตามเดือน — grouped bar
    const locations = Array.from(new Set(rows.map(r => normLoc(r.location)))).sort();
    const byLocMonth = {}; // { location: { 'YYYY-MM': total } }
    rows.forEach(r => {
      const loc = normLoc(r.location);
      const m = String(r.usage_date).slice(0,7);
      if (!byLocMonth[loc]) byLocMonth[loc] = {};
      byLocMonth[loc][m] = (byLocMonth[loc][m] || 0) + (Number(r.usage_cum)||0);
    });
    const monthKeys = Array.from(new Set(rows.map(r => String(r.usage_date).slice(0,7)))).sort();

    chartEl.innerHTML = `<div class="dash-dark-card rounded-2xl p-5"><h3 class="text-sm font-medium dash-dark-text-muted mb-3">เปรียบเทียบปริมาณการใช้น้ำของแต่ละบ่อ (ลบ.ม./เดือน)</h3><div class="relative h-72"><canvas id="water-canvas"></canvas></div></div>`;
    refreshIcons();
    const ctx = document.getElementById('water-canvas');
    destroyChart('water');
    chartRegistry['water'] = new Chart(ctx, {
      type: 'bar',
      data: {
        labels: monthKeys.map(k => `${monthNameTH(Number(k.slice(5,7))).slice(0,3)} ${k.slice(0,4)}`),
        datasets: locations.map((loc, idx) => ({
          label: loc,
          data: monthKeys.map(k => (byLocMonth[loc] && byLocMonth[loc][k]) || 0),
          backgroundColor: CHART_COLORS[idx % CHART_COLORS.length],
          borderRadius: 6
        }))
      },
      options: { responsive: true, maintainAspectRatio: false, layout: { padding: { top: 18 } }, plugins: { legend: { position: 'bottom', labels: { boxWidth: 12, font: { size: 11 }, color: '#cbd5e1' } } }, scales: { y: { beginAtZero: true, ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } }, x: { ticks: { color: '#94a3b8' }, grid: { color: 'rgba(255,255,255,0.08)' } } } },
      plugins: [barValueLabelsPlugin]
    });

    // ตาราง pivot รายเดือน (แถว=เดือน, คอลัมน์=แต่ละบ่อ) + ลูกศรเทียบเดือนก่อน (เทียบยอดรวมทุกบ่อ)
    const pivot = {}; // { monthKey: { location: total, __total } }
    monthKeys.forEach(m => { pivot[m] = { __total: 0 }; locations.forEach(loc => pivot[m][loc] = 0); });
    rows.forEach(r => {
      const loc = normLoc(r.location);
      const m = String(r.usage_date).slice(0,7);
      pivot[m][loc] = (pivot[m][loc] || 0) + (Number(r.usage_cum)||0);
      pivot[m].__total += (Number(r.usage_cum)||0);
    });

    tableEl.innerHTML = `
      <div class="dash-dark-card rounded-2xl p-5 overflow-x-auto">
        <h3 class="text-sm font-medium dash-dark-text-muted mb-3">การใช้น้ำรายเดือน (Pivot ตามบ่อ)</h3>
        <table class="w-full text-sm">
          <thead><tr class="text-left dash-dark-text-muted border-b dash-dark-border">
            <th class="py-2 pr-3">เดือน</th>
            ${locations.map(loc => `<th class="py-2 pr-3">${escapeHtml(loc)}</th>`).join('')}
            <th class="py-2 pr-3">รวม (ลบ.ม.)</th>
            <th class="py-2 pr-3">เทียบเดือนก่อน</th>
          </tr></thead>
          <tbody>
            ${monthKeys.map((m, idx) => {
              const cur = pivot[m].__total;
              const prevKey = monthKeys[idx-1];
              const prev = prevKey ? pivot[prevKey].__total : null;
              let trendHtml = '<span class="dash-dark-text-muted">-</span>';
              if (prev !== null) {
                if (cur > prev) trendHtml = `<span class="text-emerald-400 inline-flex items-center gap-1"><i data-lucide="arrow-up" class="w-4 h-4"></i>${fmtNum(cur-prev,1)}</span>`;
                else if (cur < prev) trendHtml = `<span class="text-red-400 inline-flex items-center gap-1"><i data-lucide="arrow-down" class="w-4 h-4"></i>${fmtNum(prev-cur,1)}</span>`;
                else trendHtml = `<span class="dash-dark-text-muted">เท่าเดิม</span>`;
              }
              return `
              <tr class="border-b dash-dark-border dash-dark-row-hover dash-dark-text">
                <td class="py-2 pr-3 font-medium">${monthNameTH(Number(m.slice(5,7)))} ${m.slice(0,4)}</td>
                ${locations.map(loc => `<td class="py-2 pr-3">${fmtNum(pivot[m][loc],2)}</td>`).join('')}
                <td class="py-2 pr-3 font-semibold">${fmtNum(cur,2)}</td>
                <td class="py-2 pr-3">${trendHtml}</td>
              </tr>`;
            }).join('')}
          </tbody>
        </table>
      </div>`;
    refreshIcons();
  } catch (err) {
    console.error(err);
    statsEl.innerHTML = [1,2,3].map(() => errorBlockDark()).join('');
    chartEl.innerHTML = '';
    tableEl.innerHTML = '';
    refreshIcons();
  }
}


// =====================================================================
// SECTION 20: MANAGE — ประเภทวัสดุ (material_types)
// =====================================================================
let _materialsCache = [];
let _materialsSearch = '';
let _materialsFactoryFilter = 'all';

function renderManageMaterials(container) {
  container.innerHTML = `
    <div class="space-y-4 fade-in">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <h2 class="text-lg font-semibold text-secondary-800 flex items-center gap-2"><i data-lucide="package" class="w-5 h-5 text-primary-600"></i>ประเภทวัสดุ</h2>
        <div class="flex items-center gap-2 flex-wrap">
          <button id="materials-add-btn" class="flex items-center gap-1.5 bg-primary-600 hover:bg-primary-700 text-white text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="plus" class="w-4 h-4"></i>เพิ่ม</button>
          <label class="flex items-center gap-1.5 bg-white border border-secondary-200 hover:bg-secondary-50 text-secondary-600 text-sm font-medium px-3 py-2 rounded-xl transition cursor-pointer" title="นำเข้าประเภทวัสดุจาก Excel/CSV — ถ้าชื่อ+โรงงานซ้ำ จะ update แทน">
            <i data-lucide="upload" class="w-4 h-4"></i>นำเข้า Excel/CSV
            <input id="materials-import-input" type="file" accept=".xlsx,.xls,.csv" class="hidden">
          </label>
          <button id="materials-refresh-btn" class="flex items-center gap-1.5 bg-white border border-secondary-200 hover:bg-secondary-50 text-secondary-600 text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="refresh-cw" class="w-4 h-4"></i>Refresh</button>
        </div>
      </div>
      <div class="bg-white rounded-2xl shadow-sm p-4 flex flex-wrap gap-3 items-center">
        <input id="materials-search" type="text" value="${escapeHtml(_materialsSearch)}" placeholder="ค้นหาชื่อวัสดุ..." class="flex-1 min-w-[160px] sm:w-72 border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        <select id="materials-factory-filter" class="border border-secondary-200 rounded-xl px-3 py-2 text-sm">
          <option value="all">ทุกโรงงาน</option>
        </select>
      </div>
      <div id="materials-table-block">${skeletonBlock('h-56')}</div>
    </div>`;
  refreshIcons();
  document.getElementById('materials-add-btn').addEventListener('click', () => openMaterialForm());
  document.getElementById('materials-refresh-btn').addEventListener('click', () => loadMaterials());
  document.getElementById('materials-import-input').addEventListener('change', (e) => importMaterialTypesExcel(e));
  const searchInput = document.getElementById('materials-search');
  searchInput.addEventListener('input', () => { _materialsSearch = searchInput.value; renderMaterialsTable(); });
  const factoryFilterSel = document.getElementById('materials-factory-filter');
  factoryFilterSel.addEventListener('change', () => { _materialsFactoryFilter = factoryFilterSel.value; renderMaterialsTable(); });
  loadMaterials();
}

async function loadMaterials() {
  const el = document.getElementById('materials-table-block');
  if (el) el.innerHTML = skeletonBlock('h-56');
  try {
    if (!_factoriesCache.length) {
      const { data: fData, error: fError } = await db.from('factories').select('*').order('name', { ascending: true });
      if (fError) throw fError;
      _factoriesCache = fData || [];
    }
    const { data, error } = await db.from('material_types').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    _materialsCache = data || [];
    renderMaterialsTable();
    populateMaterialsFactoryFilter();
  } catch (err) {
    console.error(err);
    if (el) el.innerHTML = errorBlock();
    refreshIcons();
  }
}

function populateMaterialsFactoryFilter() {
  const sel = document.getElementById('materials-factory-filter');
  if (!sel) return;
  sel.innerHTML = `<option value="all">ทุกโรงงาน</option>` + _factoriesCache.map(f => `<option value="${f.id}" ${_materialsFactoryFilter === f.id ? 'selected' : ''}>${escapeHtml(f.name)}</option>`).join('');
}

function renderMaterialsTable() {
  const el = document.getElementById('materials-table-block');
  if (!el) return;
  const kw = _materialsSearch.trim().toLowerCase();
  const rows = _materialsCache.filter(r => {
    if (kw && !(r.name || '').toLowerCase().includes(kw)) return false;
    if (_materialsFactoryFilter !== 'all' && r.factory_id !== _materialsFactoryFilter) return false;
    return true;
  });
  el.innerHTML = `
    <div class="bg-white rounded-2xl shadow-sm p-5 overflow-x-auto">
      <table class="w-full text-sm">
        <thead><tr class="text-left text-secondary-400 border-b border-secondary-100">
          <th class="py-2 pr-3">ลำดับ</th><th class="py-2 pr-3">ชื่อ</th><th class="py-2 pr-3">รายละเอียด</th><th class="py-2 pr-3">ถพ.</th><th class="py-2 pr-3">โรงงาน</th><th class="py-2 pr-3">สถานะ</th><th class="py-2 pr-3">จัดการ</th>
        </tr></thead>
        <tbody>
          ${rows.length ? rows.map((r,i) => `
            <tr class="border-b border-secondary-50 hover:bg-secondary-50">
              <td class="py-2 pr-3">${i+1}</td>
              <td class="py-2 pr-3 font-medium">${escapeHtml(r.name)}</td>
              <td class="py-2 pr-3 text-secondary-500">${escapeHtml(r.description || '-')}</td>
              <td class="py-2 pr-3">${r.bulk_density !== null && r.bulk_density !== undefined ? fmtNum(r.bulk_density, 2) : '-'}</td>
              <td class="py-2 pr-3 text-secondary-500">${escapeHtml((_factoriesCache.find(f => f.id === r.factory_id) || {}).name || '-')}</td>
              <td class="py-2 pr-3"><span class="px-2 py-0.5 rounded-full text-xs ${r.status==='active'?'bg-emerald-50 text-emerald-600':'bg-secondary-100 text-secondary-500'}">${escapeHtml(r.status)}</span></td>
              <td class="py-2 pr-3">
                <div class="flex items-center gap-1.5">
                  <button data-edit="${r.id}" class="p-1.5 rounded-lg hover:bg-secondary-100 text-secondary-500" title="แก้ไข"><i data-lucide="pencil" class="w-4 h-4"></i></button>
                  <button data-del="${r.id}" class="p-1.5 rounded-lg hover:bg-red-50 text-red-500" title="ลบ"><i data-lucide="trash-2" class="w-4 h-4"></i></button>
                </div>
              </td>
            </tr>`).join('') : `<tr><td colspan="7" class="py-8 text-center text-secondary-400">ไม่พบข้อมูล</td></tr>`}
        </tbody>
      </table>
    </div>`;
  refreshIcons();
  qsa('[data-edit]', el).forEach(btn => btn.addEventListener('click', () => openMaterialForm(btn.getAttribute('data-edit'))));
  qsa('[data-del]', el).forEach(btn => btn.addEventListener('click', () => confirmDeleteMaterial(btn.getAttribute('data-del'))));
}

function openMaterialForm(id) {
  const editing = id ? _materialsCache.find(r => r.id === id) : null;
  showModal({
    title: editing ? 'แก้ไขประเภทวัสดุ' : 'เพิ่มประเภทวัสดุ',
    hideConfirm: true, hideCancel: true,
    bodyHtml: `
      <form id="material-form" class="space-y-3">
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">ชื่อ *</label>
          <input id="mf-name" required type="text" value="${editing ? escapeHtml(editing.name) : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">รายละเอียด</label>
          <textarea id="mf-desc" rows="3" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">${editing ? escapeHtml(editing.description || '') : ''}</textarea>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">ถพ. (Bulk Density)</label>
          <input id="mf-bulk-density" type="number" step="0.01" value="${editing && editing.bulk_density !== null && editing.bulk_density !== undefined ? editing.bulk_density : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">โรงงาน</label>
          <select id="mf-factory" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
            <option value="">- ไม่ระบุ -</option>
            ${_factoriesCache.map(f => `<option value="${f.id}" ${editing && editing.factory_id===f.id?'selected':''}>${escapeHtml(f.name)}</option>`).join('')}
          </select>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">สถานะ</label>
          <select id="mf-status" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
            <option value="active" ${(!editing || editing.status==='active')?'selected':''}>active</option>
            <option value="inactive" ${(editing && editing.status==='inactive')?'selected':''}>inactive</option>
          </select>
        </div>
        <button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">${editing ? 'บันทึกการแก้ไข' : 'เพิ่มวัสดุ'}</button>
      </form>`,
  });
  const form = document.getElementById('material-form');
  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const payload = {
      name: document.getElementById('mf-name').value.trim(),
      description: document.getElementById('mf-desc').value.trim() || null,
      bulk_density: numOrNull(document.getElementById('mf-bulk-density').value),
      factory_id: document.getElementById('mf-factory').value || null,
      status: document.getElementById('mf-status').value,
    };
    try {
      if (editing) {
        const { error } = await db.from('material_types').update(payload).eq('id', editing.id);
        if (error) throw error;
        showToast('แก้ไขข้อมูลสำเร็จ', 'success');
      } else {
        const { error } = await db.from('material_types').insert([payload]);
        if (error) throw error;
        showToast('เพิ่มข้อมูลสำเร็จ', 'success');
      }
      closeModal();
      loadMaterials();
    } catch (err) {
      console.error(err);
      showToast('เกิดข้อผิดพลาด: ' + (err.message || ''), 'error');
    }
  });
}

function confirmDeleteMaterial(id) {
  const row = _materialsCache.find(r => r.id === id);
  showModal({
    title: 'ยืนยันการลบ',
    bodyHtml: `ต้องการลบประเภทวัสดุ "${escapeHtml(row ? row.name : '')}" ใช่หรือไม่?`,
    confirmText: 'ลบ', cancelText: 'ยกเลิก',
    onConfirm: async () => {
      try {
        const { error } = await db.from('material_types').delete().eq('id', id);
        if (error) throw error;
        showToast('ลบข้อมูลสำเร็จ', 'success');
        loadMaterials();
      } catch (err) {
        console.error(err);
        showToast('ลบไม่สำเร็จ: ' + (err.message || ''), 'error');
      }
    }
  });
}
// =====================================================================
// SECTION 21: MANAGE — เพิ่มโรงงาน (factories) — มี pagination จริง
// =====================================================================
let _factoriesCache = [];
let _factoriesSearch = '';
let _factoriesPage = 1;
const FACTORIES_PAGE_SIZE = 10;

function renderManageFactories(container) {
  container.innerHTML = `
    <div class="space-y-4 fade-in">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <h2 class="text-lg font-semibold text-secondary-800 flex items-center gap-2"><i data-lucide="building-2" class="w-5 h-5 text-primary-600"></i>เพิ่มโรงงาน</h2>
        <div class="flex items-center gap-2">
          <button id="factories-add-btn" class="flex items-center gap-1.5 bg-primary-600 hover:bg-primary-700 text-white text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="plus" class="w-4 h-4"></i>เพิ่ม</button>
          <button id="factories-refresh-btn" class="flex items-center gap-1.5 bg-white border border-secondary-200 hover:bg-secondary-50 text-secondary-600 text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="refresh-cw" class="w-4 h-4"></i>Refresh</button>
        </div>
      </div>
      <div class="bg-white rounded-2xl shadow-sm p-4">
        <input id="factories-search" type="text" value="${escapeHtml(_factoriesSearch)}" placeholder="ค้นหาชื่อโรงงาน..." class="w-full sm:w-80 border border-secondary-200 rounded-xl px-3 py-2 text-sm">
      </div>
      <div id="factories-table-block">${skeletonBlock('h-56')}</div>
    </div>`;
  refreshIcons();
  document.getElementById('factories-add-btn').addEventListener('click', () => openFactoryForm());
  document.getElementById('factories-refresh-btn').addEventListener('click', () => loadFactories());
  const searchInput = document.getElementById('factories-search');
  searchInput.addEventListener('input', () => { _factoriesSearch = searchInput.value; _factoriesPage = 1; renderFactoriesTable(); });
  loadFactories();
}

async function loadFactories() {
  const el = document.getElementById('factories-table-block');
  if (el) el.innerHTML = skeletonBlock('h-56');
  try {
    const { data, error } = await db.from('factories').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    _factoriesCache = data || [];
    _factoriesPage = 1;
    renderFactoriesTable();
  } catch (err) {
    console.error(err);
    if (el) el.innerHTML = errorBlock();
    refreshIcons();
  }
}

function renderFactoriesTable() {
  const el = document.getElementById('factories-table-block');
  if (!el) return;
  const kw = _factoriesSearch.trim().toLowerCase();
  const filtered = _factoriesCache.filter(r => !kw || (r.name || '').toLowerCase().includes(kw));
  const totalPages = Math.max(1, Math.ceil(filtered.length / FACTORIES_PAGE_SIZE));
  if (_factoriesPage > totalPages) _factoriesPage = totalPages;
  const startIdx = (_factoriesPage - 1) * FACTORIES_PAGE_SIZE;
  const pageRows = filtered.slice(startIdx, startIdx + FACTORIES_PAGE_SIZE);

  const pageButtons = [];
  for (let p = 1; p <= totalPages; p++) {
    pageButtons.push(`<button data-page="${p}" class="page-btn px-3 py-1.5 rounded-lg text-xs font-medium ${p === _factoriesPage ? 'bg-primary-600 text-white' : 'bg-white border border-secondary-200 text-secondary-600 hover:bg-secondary-50'}">${p}</button>`);
  }

  el.innerHTML = `
    <div class="bg-white rounded-2xl shadow-sm p-5 overflow-x-auto">
      <table class="w-full text-sm">
        <thead><tr class="text-left text-secondary-400 border-b border-secondary-100">
          <th class="py-2 pr-3">ลำดับ</th><th class="py-2 pr-3">ชื่อ</th><th class="py-2 pr-3">Target (ตัน/ชม.)</th><th class="py-2 pr-3">สถานะ</th><th class="py-2 pr-3">จัดการ</th>
        </tr></thead>
        <tbody>
          ${pageRows.length ? pageRows.map((r,i) => `
            <tr class="border-b border-secondary-50 hover:bg-secondary-50">
              <td class="py-2 pr-3">${startIdx + i + 1}</td>
              <td class="py-2 pr-3 font-medium">${escapeHtml(r.name)}</td>
              <td class="py-2 pr-3">${r.target_throughput ? `<span class="text-primary-600 font-medium">${fmtNum(r.target_throughput,1)}</span>` : '<span class="text-secondary-300">—</span>'}</td>
              <td class="py-2 pr-3"><span class="px-2 py-0.5 rounded-full text-xs ${r.status==='active'?'bg-emerald-50 text-emerald-600':'bg-secondary-100 text-secondary-500'}">${escapeHtml(r.status)}</span></td>
              <td class="py-2 pr-3">
                <div class="flex items-center gap-1.5">
                  <button data-edit="${r.id}" class="p-1.5 rounded-lg hover:bg-secondary-100 text-secondary-500" title="แก้ไข"><i data-lucide="pencil" class="w-4 h-4"></i></button>
                  <button data-del="${r.id}" class="p-1.5 rounded-lg hover:bg-red-50 text-red-500" title="ลบ"><i data-lucide="trash-2" class="w-4 h-4"></i></button>
                </div>
              </td>
            </tr>`).join('') : `<tr><td colspan="4" class="py-8 text-center text-secondary-400">ไม่พบข้อมูล</td></tr>`}
        </tbody>
      </table>
      <div class="flex items-center justify-between mt-4 flex-wrap gap-2">
        <p class="text-xs text-secondary-400">ทั้งหมด ${filtered.length} รายการ</p>
        <div class="flex items-center gap-1.5">
          <button id="factories-prev-btn" class="px-3 py-1.5 rounded-lg text-xs font-medium bg-white border border-secondary-200 text-secondary-600 hover:bg-secondary-50 disabled:opacity-40" ${_factoriesPage<=1?'disabled':''}>ก่อนหน้า</button>
          ${pageButtons.join('')}
          <button id="factories-next-btn" class="px-3 py-1.5 rounded-lg text-xs font-medium bg-white border border-secondary-200 text-secondary-600 hover:bg-secondary-50 disabled:opacity-40" ${_factoriesPage>=totalPages?'disabled':''}>ถัดไป</button>
        </div>
      </div>
    </div>`;
  refreshIcons();
  qsa('[data-edit]', el).forEach(btn => btn.addEventListener('click', () => openFactoryForm(btn.getAttribute('data-edit'))));
  qsa('[data-del]', el).forEach(btn => btn.addEventListener('click', () => confirmDeleteFactory(btn.getAttribute('data-del'))));
  qsa('.page-btn', el).forEach(btn => btn.addEventListener('click', () => { _factoriesPage = Number(btn.getAttribute('data-page')); renderFactoriesTable(); }));
  const prevBtn = document.getElementById('factories-prev-btn');
  if (prevBtn) prevBtn.addEventListener('click', () => { if (_factoriesPage > 1) { _factoriesPage--; renderFactoriesTable(); } });
  const nextBtn = document.getElementById('factories-next-btn');
  if (nextBtn) nextBtn.addEventListener('click', () => { if (_factoriesPage < totalPages) { _factoriesPage++; renderFactoriesTable(); } });
}

function openFactoryForm(id) {
  const editing = id ? _factoriesCache.find(r => r.id === id) : null;
  showModal({
    title: editing ? 'แก้ไขโรงงาน' : 'เพิ่มโรงงาน',
    hideConfirm: true, hideCancel: true,
    bodyHtml: `
      <form id="factory-form" class="space-y-3">
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">ชื่อ *</label>
          <input id="ff-name" required type="text" value="${editing ? escapeHtml(editing.name) : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">Target Throughput (ตัน/ชม.) <span class="text-secondary-400">— ใช้คำนวณ Performance OEE</span></label>
          <input id="ff-target-tp" type="number" step="any" min="0" value="${editing && editing.target_throughput ? editing.target_throughput : ''}" placeholder="เช่น 150 (ตัน/ชม.)" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">สถานะ</label>
          <select id="ff-status" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
            <option value="active" ${(!editing || editing.status==='active')?'selected':''}>active</option>
            <option value="inactive" ${(editing && editing.status==='inactive')?'selected':''}>inactive</option>
          </select>
        </div>
        <button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">${editing ? 'บันทึกการแก้ไข' : 'เพิ่มโรงงาน'}</button>
      </form>`,
  });
  const form = document.getElementById('factory-form');
  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const ffTp = parseFloat(document.getElementById('ff-target-tp').value);
    const payload = {
      name: document.getElementById('ff-name').value.trim(),
      status: document.getElementById('ff-status').value,
      target_throughput: isNaN(ffTp) ? null : ffTp,
    };
    try {
      if (editing) {
        const { error } = await db.from('factories').update(payload).eq('id', editing.id);
        if (error) throw error;
        showToast('แก้ไขข้อมูลสำเร็จ', 'success');
      } else {
        const { error } = await db.from('factories').insert([payload]);
        if (error) throw error;
        showToast('เพิ่มข้อมูลสำเร็จ', 'success');
      }
      closeModal();
      loadFactories();
    } catch (err) {
      console.error(err);
      showToast('เกิดข้อผิดพลาด: ' + (err.message || ''), 'error');
    }
  });
}

function confirmDeleteFactory(id) {
  const row = _factoriesCache.find(r => r.id === id);
  showModal({
    title: 'ยืนยันการลบ',
    bodyHtml: `ต้องการลบโรงงาน "${escapeHtml(row ? row.name : '')}" ใช่หรือไม่?`,
    confirmText: 'ลบ', cancelText: 'ยกเลิก',
    onConfirm: async () => {
      try {
        const { error } = await db.from('factories').delete().eq('id', id);
        if (error) throw error;
        showToast('ลบข้อมูลสำเร็จ', 'success');
        loadFactories();
      } catch (err) {
        console.error(err);
        showToast('ลบไม่สำเร็จ: ' + (err.message || ''), 'error');
      }
    }
  });
}
