let _mWaterSrcCache = [];
const _mWaterSrcFilter = { search: '' };

function renderManageWaterSources(container) {
  container.innerHTML = `
    <div class="space-y-4 fade-in">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <h2 class="text-lg font-semibold text-secondary-800 flex items-center gap-2"><i data-lucide="droplets" class="w-5 h-5 text-primary-600"></i>เพิ่มแหล่งน้ำ</h2>
        <div class="flex items-center gap-2">
          <button id="watersrc-add-btn" class="flex items-center gap-1.5 bg-primary-600 hover:bg-primary-700 text-white text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="plus" class="w-4 h-4"></i>เพิ่ม</button>
          <button id="watersrc-refresh-btn" class="flex items-center gap-1.5 bg-white border border-secondary-200 hover:bg-secondary-50 text-secondary-600 text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="refresh-cw" class="w-4 h-4"></i>Refresh</button>
        </div>
      </div>
      <div class="bg-white rounded-2xl shadow-sm p-4">
        <input id="watersrc-search" type="text" value="${escapeHtml(_mWaterSrcFilter.search)}" placeholder="ค้นหาชื่อแหล่งน้ำ..." class="w-full sm:w-80 border border-secondary-200 rounded-xl px-3 py-2 text-sm">
      </div>
      <div id="watersrc-table-block">${skeletonBlock('h-56')}</div>
    </div>`;
  refreshIcons();
  document.getElementById('watersrc-add-btn').addEventListener('click', () => openWaterSourceForm());
  document.getElementById('watersrc-refresh-btn').addEventListener('click', () => loadManageWaterSources());
  const searchInput = document.getElementById('watersrc-search');
  searchInput.addEventListener('input', () => { _mWaterSrcFilter.search = searchInput.value; renderManageWaterSourcesTable(); });
  loadManageWaterSources();
}

async function loadManageWaterSources() {
  const el = document.getElementById('watersrc-table-block');
  if (el) el.innerHTML = skeletonBlock('h-56');
  try {
    if (!_factoriesCache.length) {
      const { data: fData, error: fError } = await db.from('factories').select('*').order('name', { ascending: true });
      if (fError) throw fError;
      _factoriesCache = fData || [];
    }
    const { data, error } = await db.from('water_sources').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    _mWaterSrcCache = data || [];
    renderManageWaterSourcesTable();
  } catch (err) {
    console.error(err);
    if (el) el.innerHTML = errorBlock();
    refreshIcons();
  }
}

function renderManageWaterSourcesTable() {
  const el = document.getElementById('watersrc-table-block');
  if (!el) return;
  const kw = _mWaterSrcFilter.search.trim().toLowerCase();
  const rows = _mWaterSrcCache.filter(r => !kw || (r.name || '').toLowerCase().includes(kw));
  el.innerHTML = `
    <div class="bg-white rounded-2xl shadow-sm p-5 overflow-x-auto">
      <table class="w-full text-sm">
        <thead><tr class="text-left text-secondary-400 border-b border-secondary-100">
          <th class="py-2 pr-3">ลำดับ</th><th class="py-2 pr-3">ชื่อ</th><th class="py-2 pr-3">โรงงาน</th><th class="py-2 pr-3">สถานะ</th><th class="py-2 pr-3">จัดการ</th>
        </tr></thead>
        <tbody>
          ${rows.length ? rows.map((r,i) => `
            <tr class="border-b border-secondary-50 hover:bg-secondary-50">
              <td class="py-2 pr-3">${i+1}</td>
              <td class="py-2 pr-3 font-medium">${escapeHtml(r.name)}</td>
              <td class="py-2 pr-3 text-secondary-500">${escapeHtml((_factoriesCache.find(f => f.id === r.factory_id) || {}).name || '-')}</td>
              <td class="py-2 pr-3"><span class="px-2 py-0.5 rounded-full text-xs ${r.status==='active'?'bg-emerald-50 text-emerald-600':'bg-secondary-100 text-secondary-500'}">${escapeHtml(r.status)}</span></td>
              <td class="py-2 pr-3">
                <div class="flex items-center gap-1.5">
                  <button data-edit="${r.id}" class="p-1.5 rounded-lg hover:bg-secondary-100 text-secondary-500" title="แก้ไข"><i data-lucide="pencil" class="w-4 h-4"></i></button>
                  <button data-del="${r.id}" class="p-1.5 rounded-lg hover:bg-red-50 text-red-500" title="ลบ"><i data-lucide="trash-2" class="w-4 h-4"></i></button>
                </div>
              </td>
            </tr>`).join('') : `<tr><td colspan="5" class="py-8 text-center text-secondary-400">ไม่พบข้อมูล</td></tr>`}
        </tbody>
      </table>
    </div>`;
  refreshIcons();
  qsa('[data-edit]', el).forEach(btn => btn.addEventListener('click', () => openWaterSourceEditForm(btn.getAttribute('data-edit'))));
  qsa('[data-del]', el).forEach(btn => btn.addEventListener('click', () => confirmDeleteWaterSource(btn.getAttribute('data-del'))));
}

function waterSourceFormHtml(row) {
  row = row || {};
  return `
    <div>
      <label class="block text-xs font-medium text-secondary-500 mb-1">ชื่อ *</label>
      <input id="wsf-name" required type="text" value="${escapeHtml(row.name || '')}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
    </div>
    <div>
      <label class="block text-xs font-medium text-secondary-500 mb-1">โรงงาน</label>
      <select id="wsf-factory" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        <option value="">- ไม่ระบุ -</option>
        ${_factoriesCache.map(f => `<option value="${f.id}" ${row.factory_id===f.id?'selected':''}>${escapeHtml(f.name)}</option>`).join('')}
      </select>
    </div>
    <div>
      <label class="block text-xs font-medium text-secondary-500 mb-1">สถานะ</label>
      <select id="wsf-status" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        <option value="active" ${(!row.status || row.status==='active')?'selected':''}>active</option>
        <option value="inactive" ${row.status==='inactive'?'selected':''}>inactive</option>
      </select>
    </div>`;
}

function openWaterSourceForm() {
  showModal({
    title: 'เพิ่มแหล่งน้ำ',
    hideConfirm: true, hideCancel: true,
    bodyHtml: `<form id="watersrc-form" class="space-y-3">${waterSourceFormHtml()}<button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">เพิ่มแหล่งน้ำ</button></form>`,
  });
  refreshIcons();
  const form = document.getElementById('watersrc-form');
  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const payload = {
      name: document.getElementById('wsf-name').value.trim(),
      factory_id: document.getElementById('wsf-factory').value || null,
      status: document.getElementById('wsf-status').value,
    };
    try {
      const { error } = await db.from('water_sources').insert([payload]);
      if (error) throw error;
      showToast('เพิ่มข้อมูลสำเร็จ', 'success');
      _mWaterSources = null; // invalidate cache
      closeModal();
      loadManageWaterSources();
    } catch (err) {
      console.error(err);
      showToast('เกิดข้อผิดพลาด: ' + (err.message || ''), 'error');
    }
  });
}

function openWaterSourceEditForm(id) {
  const editing = _mWaterSrcCache.find(r => r.id === id);
  if (!editing) return;
  showModal({
    title: 'แก้ไขแหล่งน้ำ',
    hideConfirm: true, hideCancel: true,
    bodyHtml: `<form id="watersrc-edit-form" class="space-y-3">${waterSourceFormHtml(editing)}<button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">บันทึกการแก้ไข</button></form>`,
  });
  refreshIcons();
  const form = document.getElementById('watersrc-edit-form');
  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const payload = {
      name: document.getElementById('wsf-name').value.trim(),
      factory_id: document.getElementById('wsf-factory').value || null,
      status: document.getElementById('wsf-status').value,
    };
    try {
      const { error } = await db.from('water_sources').update(payload).eq('id', editing.id);
      if (error) throw error;
      showToast('แก้ไขข้อมูลสำเร็จ', 'success');
      _mWaterSources = null; // invalidate cache
      closeModal();
      loadManageWaterSources();
    } catch (err) {
      console.error(err);
      showToast('เกิดข้อผิดพลาด: ' + (err.message || ''), 'error');
    }
  });
}

function confirmDeleteWaterSource(id) {
  const row = _mWaterSrcCache.find(r => r.id === id);
  showModal({
    title: 'ยืนยันการลบ',
    bodyHtml: `ต้องการลบแหล่งน้ำ "${escapeHtml(row ? row.name : '')}" ใช่หรือไม่?`,
    confirmText: 'ลบ', cancelText: 'ยกเลิก',
    onConfirm: async () => {
      try {
        const { error } = await db.from('water_sources').delete().eq('id', id);
        if (error) throw error;
        showToast('ลบข้อมูลสำเร็จ', 'success');
        _mWaterSources = null; // invalidate cache
        loadManageWaterSources();
      } catch (err) {
        console.error(err);
        showToast('ลบไม่สำเร็จ: ' + (err.message || ''), 'error');
      }
    }
  });
}
