// SECTION 22: MANAGE — จัดการผู้ใช้ (app_users) — admin only
// =====================================================================
let _usersCache = [];
let _usersSearch = '';
let _usersStatusFilter = 'all';

function renderManageUsers(container) {
  container.innerHTML = `
    <div class="space-y-4 fade-in">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <h2 class="text-lg font-semibold text-secondary-800 flex items-center gap-2"><i data-lucide="users" class="w-5 h-5 text-primary-600"></i>จัดการผู้ใช้</h2>
        <div class="flex items-center gap-2">
          <button id="users-add-btn" class="flex items-center gap-1.5 bg-primary-600 hover:bg-primary-700 text-white text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="plus" class="w-4 h-4"></i>เพิ่ม</button>
          <button id="users-refresh-btn" class="flex items-center gap-1.5 bg-white border border-secondary-200 hover:bg-secondary-50 text-secondary-600 text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="refresh-cw" class="w-4 h-4"></i>Refresh</button>
        </div>
      </div>
      <div class="bg-white rounded-2xl shadow-sm p-4 flex flex-wrap items-center gap-2">
        <input id="users-search" type="text" value="${escapeHtml(_usersSearch)}" placeholder="ค้นหา username / ชื่อ / แผนก / ตำแหน่ง..." class="flex-1 min-w-[220px] border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        <select id="users-status-filter" class="border border-secondary-200 rounded-xl px-3 py-2 text-sm">
          <option value="all" ${_usersStatusFilter==='all'?'selected':''}>ทุกสถานะ</option>
          <option value="pending" ${_usersStatusFilter==='pending'?'selected':''}>pending</option>
          <option value="active" ${_usersStatusFilter==='active'?'selected':''}>active</option>
          <option value="inactive" ${_usersStatusFilter==='inactive'?'selected':''}>inactive</option>
          <option value="rejected" ${_usersStatusFilter==='rejected'?'selected':''}>rejected</option>
        </select>
      </div>
      <div id="users-table-block">${skeletonBlock('h-56')}</div>
    </div>`;
  refreshIcons();
  document.getElementById('users-add-btn').addEventListener('click', () => openUserForm());
  document.getElementById('users-refresh-btn').addEventListener('click', () => loadUsers());
  const searchInput = document.getElementById('users-search');
  searchInput.addEventListener('input', () => { _usersSearch = searchInput.value; renderUsersTable(); });
  const statusSel = document.getElementById('users-status-filter');
  statusSel.addEventListener('change', () => { _usersStatusFilter = statusSel.value; renderUsersTable(); });
  loadUsers();
}

async function loadUsers() {
  const el = document.getElementById('users-table-block');
  if (el) el.innerHTML = skeletonBlock('h-56');
  try {
    const { data, error } = await db.from('app_users').select('*').order('created_at', { ascending: false });
    if (error) throw error;
    _usersCache = data || [];
    renderUsersTable();
  } catch (err) {
    console.error(err);
    if (el) el.innerHTML = errorBlock();
    refreshIcons();
  }
}

function userStatusBadgeClass(status) {
  const map = { active: 'bg-emerald-50 text-emerald-600', pending: 'bg-amber-50 text-amber-600', inactive: 'bg-secondary-100 text-secondary-500', rejected: 'bg-red-50 text-red-600' };
  return map[status] || 'bg-secondary-100 text-secondary-500';
}

function renderUsersTable() {
  const el = document.getElementById('users-table-block');
  if (!el) return;
  const kw = _usersSearch.trim().toLowerCase();
  const rows = _usersCache.filter(r => {
    if (_usersStatusFilter !== 'all' && r.status !== _usersStatusFilter) return false;
    if (!kw) return true;
    return [r.username, r.full_name, r.department, r.position].some(v => (v || '').toLowerCase().includes(kw));
  });
  el.innerHTML = `
    <div class="bg-white rounded-2xl shadow-sm p-5 overflow-x-auto">
      <table class="w-full text-sm">
        <thead><tr class="text-left text-secondary-400 border-b border-secondary-100">
          <th class="py-2 pr-3">Username</th><th class="py-2 pr-3">ชื่อ-สกุล</th><th class="py-2 pr-3">เบอร์</th><th class="py-2 pr-3">ตำแหน่ง</th><th class="py-2 pr-3">บทบาท</th><th class="py-2 pr-3">แผนก</th><th class="py-2 pr-3">สถานะ</th><th class="py-2 pr-3">จัดการ</th>
        </tr></thead>
        <tbody>
          ${rows.length ? rows.map(r => `
            <tr class="border-b border-secondary-50 hover:bg-secondary-50">
              <td class="py-2 pr-3 font-medium">${escapeHtml(r.username)}</td>
              <td class="py-2 pr-3">${escapeHtml(r.full_name || '-')}</td>
              <td class="py-2 pr-3">${escapeHtml(r.phone || '-')}</td>
              <td class="py-2 pr-3">${escapeHtml(r.position || '-')}</td>
              <td class="py-2 pr-3">${escapeHtml(roleLabel(r.role) || r.role || '-')}</td>
              <td class="py-2 pr-3">${escapeHtml(r.department || '-')}</td>
              <td class="py-2 pr-3"><span class="px-2 py-0.5 rounded-full text-xs ${userStatusBadgeClass(r.status)}">${escapeHtml(r.status)}</span></td>
              <td class="py-2 pr-3">
                <div class="flex items-center gap-1.5">
                  <button data-edit="${r.id}" class="p-1.5 rounded-lg hover:bg-secondary-100 text-secondary-500" title="แก้ไข"><i data-lucide="pencil" class="w-4 h-4"></i></button>
                  <button data-del="${r.id}" class="p-1.5 rounded-lg hover:bg-red-50 text-red-500" title="ลบ"><i data-lucide="trash-2" class="w-4 h-4"></i></button>
                </div>
              </td>
            </tr>`).join('') : `<tr><td colspan="8" class="py-8 text-center text-secondary-400">ไม่พบข้อมูล</td></tr>`}
        </tbody>
      </table>
    </div>`;
  refreshIcons();
  qsa('[data-edit]', el).forEach(btn => btn.addEventListener('click', () => openUserForm(btn.getAttribute('data-edit'))));
  qsa('[data-del]', el).forEach(btn => btn.addEventListener('click', () => confirmDeleteUser(btn.getAttribute('data-del'))));
}

async function openUserForm(id) {
  const editing = id ? _usersCache.find(r => r.id === id) : null;
  // ดึง roles จาก DB แทน hardcode
  let rolesData = [];
  try {
    const { data } = await db.from('roles').select('name, label').order('sort_order');
    rolesData = data || [];
  } catch (_) {}
  const roles = rolesData.length ? rolesData.map(r => r.name) : ['admin','managing_md','manager','supervisor','operator','clerk'];
  const roleLabel = (name) => (rolesData.find(r => r.name === name) || {}).label || name;
  const depts = ['CDE','Propel','Sanon1','Sanon2','all'];
  const statuses = ['pending','active','inactive','rejected'];
  showModal({
    title: editing ? 'แก้ไขผู้ใช้' : 'เพิ่มผู้ใช้',
    hideConfirm: true, hideCancel: true,
    bodyHtml: `
      <form id="user-form" class="space-y-3 max-h-[65vh] overflow-y-auto pr-1">
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">Username *</label>
          <input id="uf-username" required type="text" value="${editing ? escapeHtml(editing.username) : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">Password ${editing ? '(เว้นว่าง = ไม่เปลี่ยน)' : '*'}</label>
          <input id="uf-password" ${editing ? '' : 'required'} type="text" placeholder="${editing ? 'เว้นว่างเพื่อไม่เปลี่ยน' : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">ชื่อ-สกุล</label>
          <input id="uf-fullname" type="text" value="${editing ? escapeHtml(editing.full_name || '') : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">เบอร์</label>
          <input id="uf-phone" type="text" value="${editing ? escapeHtml(editing.phone || '') : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">ตำแหน่ง</label>
          <input id="uf-position" type="text" value="${editing ? escapeHtml(editing.position || '') : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">บทบาท</label>
          <select id="uf-role" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
            ${roles.map(r => `<option value="${r}" ${editing && editing.role===r ? 'selected':''}>${escapeHtml(roleLabel(r))} (${r})</option>`).join('')}
          </select>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">สถานะ</label>
          <select id="uf-status" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
            ${statuses.map(s => `<option value="${s}" ${editing ? (editing.status===s?'selected':'') : (s==='pending'?'selected':'')}>${s}</option>`).join('')}
          </select>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">กลุ่มงาน/แผนก</label>
          <select id="uf-department" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
            ${depts.map(d => `<option value="${d}" ${editing && editing.department===d ? 'selected':''}>${d}</option>`).join('')}
          </select>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">หมายเหตุอนุมัติ</label>
          <textarea id="uf-note" rows="2" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">${editing ? escapeHtml(editing.approval_note || '') : ''}</textarea>
        </div>
        <button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">${editing ? 'บันทึกการแก้ไข' : 'เพิ่มผู้ใช้'}</button>
      </form>`,
  });
  const form = document.getElementById('user-form');
  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const payload = {
      username: document.getElementById('uf-username').value.trim(),
      full_name: document.getElementById('uf-fullname').value.trim() || null,
      phone: document.getElementById('uf-phone').value.trim() || null,
      position: document.getElementById('uf-position').value.trim() || null,
      role: document.getElementById('uf-role').value,
      status: document.getElementById('uf-status').value,
      department: document.getElementById('uf-department').value,
      approval_note: document.getElementById('uf-note').value.trim() || null,
    };
    const pwd = document.getElementById('uf-password').value;
    if (pwd) payload.password = pwd;
    try {
      if (editing) {
        const { error } = await db.from('app_users').update(payload).eq('id', editing.id);
        if (error) throw error;
        showToast('แก้ไขข้อมูลสำเร็จ', 'success');
      } else {
        if (!pwd) { showToast('กรุณากรอกรหัสผ่าน', 'error'); return; }
        const { error } = await db.from('app_users').insert([payload]);
        if (error) throw error;
        showToast('เพิ่มผู้ใช้สำเร็จ', 'success');
      }
      closeModal();
      loadUsers();
    } catch (err) {
      console.error(err);
      showToast('เกิดข้อผิดพลาด: ' + (err.message || ''), 'error');
    }
  });
}

function confirmDeleteUser(id) {
  const row = _usersCache.find(r => r.id === id);
  showModal({
    title: 'ยืนยันการลบ',
    bodyHtml: `ต้องการลบผู้ใช้ "${escapeHtml(row ? row.username : '')}" ใช่หรือไม่?`,
    confirmText: 'ลบ', cancelText: 'ยกเลิก',
    onConfirm: async () => {
      try {
        const { error } = await db.from('app_users').delete().eq('id', id);
        if (error) throw error;
        showToast('ลบข้อมูลสำเร็จ', 'success');
        loadUsers();
      } catch (err) {
        console.error(err);
        showToast('ลบไม่สำเร็จ: ' + (err.message || ''), 'error');
      }
    }
  });
}
