let _mDroneCache = [];
let _mDroneFactories = null;
const _mDroneFilter = { search: '', month: new Date().getMonth()+1, year: new Date().getFullYear(), factoryId: 'all', _initialized: false };

function renderManageDroneStock(container) {
  container.innerHTML = `
    <div class="space-y-4 fade-in">
      <div class="flex flex-wrap items-center justify-between gap-3">
        <h2 class="text-lg font-semibold text-secondary-800 flex items-center gap-2"><i data-lucide="plane" class="w-5 h-5 text-primary-600"></i>สต็อคหินคงเหลือ</h2>
        <div class="flex items-center gap-2 flex-wrap">
          <button id="drone-m-add-btn" class="flex items-center gap-1.5 bg-primary-600 hover:bg-primary-700 text-white text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="plus" class="w-4 h-4"></i>เพิ่ม</button>
          <label class="flex items-center gap-1.5 bg-white border border-secondary-200 hover:bg-secondary-50 text-secondary-600 text-sm font-medium px-3 py-2 rounded-xl transition cursor-pointer">
            <i data-lucide="upload" class="w-4 h-4"></i>นำเข้า Excel/CSV
            <input id="drone-m-import-input" type="file" accept=".xlsx,.xls,.csv" class="hidden">
          </label>
          <button id="drone-m-export-btn" class="flex items-center gap-1.5 bg-white border border-secondary-200 hover:bg-secondary-50 text-secondary-600 text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="download" class="w-4 h-4"></i>Export Excel</button>
          <button id="drone-m-refresh-btn" class="flex items-center gap-1.5 bg-white border border-secondary-200 hover:bg-secondary-50 text-secondary-600 text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="refresh-cw" class="w-4 h-4"></i>Refresh</button>
        </div>
      </div>
      <div class="bg-white rounded-2xl shadow-sm p-4 flex flex-wrap items-center gap-2">
        <input id="drone-m-search" type="text" placeholder="ค้นหาชนิดหิน..." class="flex-1 min-w-[180px] border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        <select id="drone-m-month" class="border border-secondary-200 rounded-xl px-3 py-2 text-sm">
          ${Array.from({length:12},(_, i) => i+1).map(m => `<option value="${m}" ${m===_mDroneFilter.month?'selected':''}>${monthNameTH(m)}</option>`).join('')}
        </select>
        <select id="drone-m-year" class="border border-secondary-200 rounded-xl px-3 py-2 text-sm">
          ${Array.from({length:5},(_, i) => new Date().getFullYear()-i).map(y => `<option value="${y}" ${y===_mDroneFilter.year?'selected':''}>${y}</option>`).join('')}
        </select>
        <select id="drone-m-factory" class="border border-secondary-200 rounded-xl px-3 py-2 text-sm"><option value="all">ทุกโรงงาน</option></select>
      </div>
      <div id="drone-m-table-block">${skeletonBlock('h-56')}</div>
    </div>`;
  refreshIcons();
  document.getElementById('drone-m-add-btn').addEventListener('click', () => openDroneStockForm());
  document.getElementById('drone-m-refresh-btn').addEventListener('click', () => loadManageDroneStock());
  document.getElementById('drone-m-export-btn').addEventListener('click', exportDroneStockExcel);
  document.getElementById('drone-m-import-input').addEventListener('change', importDroneStockExcel);
  document.getElementById('drone-m-search').addEventListener('input', (e) => { _mDroneFilter.search = e.target.value; renderManageDroneStockTable(); });
  document.getElementById('drone-m-month').addEventListener('change', (e) => { _mDroneFilter.month = Number(e.target.value); loadManageDroneStock(); });
  document.getElementById('drone-m-year').addEventListener('change', (e) => { _mDroneFilter.year = Number(e.target.value); loadManageDroneStock(); });

  loadDroneStockFactoriesCache().then(() => {
    const sel = document.getElementById('drone-m-factory');
    if (sel) {
      sel.innerHTML = `<option value="all">ทุกโรงงาน</option>` + _mDroneFactories.map(f => `<option value="${f.id}">${escapeHtml(f.name)}</option>`).join('');
      sel.addEventListener('change', (e) => { _mDroneFilter.factoryId = e.target.value; loadManageDroneStock(); });
    }
    loadManageDroneStock();
  });
}

async function loadDroneStockFactoriesCache() {
  if (_mDroneFactories) return;
  try {
    const { data, error } = await db.from('factories').select('id, name').eq('status','active');
    if (error) throw error;
    _mDroneFactories = data || [];
  } catch (err) {
    console.error(err);
    _mDroneFactories = [];
  }
}

async function loadDroneStockMaterialsCache() {
  if (window._droneMaterialsCache) return;
  try {
    const { data, error } = await db.from('material_types').select('*').eq('status','active');
    if (error) throw error;
    window._droneMaterialsCache = data || [];
  } catch (err) {
    console.error(err);
    window._droneMaterialsCache = [];
  }
}

async function loadManageDroneStock() {
  const el = document.getElementById('drone-m-table-block');
  if (el) el.innerHTML = skeletonBlock('h-56');
  if (!_mDroneFilter._initialized) {
    _mDroneFilter._initialized = true;
    const { data: latest } = await db.from('drone_stock')
      .select('stock_year, stock_month')
      .order('stock_year', { ascending: false })
      .order('stock_month', { ascending: false })
      .limit(1);
    if (latest && latest.length) {
      _mDroneFilter.year = latest[0].stock_year;
      _mDroneFilter.month = latest[0].stock_month;
      const mSel = document.getElementById('drone-m-month');
      const ySel = document.getElementById('drone-m-year');
      if (mSel) mSel.value = _mDroneFilter.month;
      if (ySel) ySel.value = _mDroneFilter.year;
    }
  }
  try {
    let query = db.from('drone_stock').select('*, factories(name)').eq('stock_month', _mDroneFilter.month).eq('stock_year', _mDroneFilter.year);
    if (_mDroneFilter.factoryId !== 'all') query = query.eq('factory_id', _mDroneFilter.factoryId);
    const { data, error } = await query.order('created_at', { ascending: false });
    if (error) throw error;
    _mDroneCache = data || [];
    renderManageDroneStockTable();
  } catch (err) {
    console.error(err);
    if (el) el.innerHTML = errorBlock();
    refreshIcons();
  }
}

function renderManageDroneStockTable() {
  const el = document.getElementById('drone-m-table-block');
  if (!el) return;
  const kw = _mDroneFilter.search.trim().toLowerCase();
  const rows = _mDroneCache.filter(r => !kw || (r.stone_type || '').toLowerCase().includes(kw));
  el.innerHTML = `
    <div class="bg-white rounded-2xl shadow-sm p-5 overflow-x-auto">
      <table class="w-full text-sm">
        <thead><tr class="text-left text-secondary-400 border-b border-secondary-100">
          <th class="py-2 pr-3">ชนิดหิน</th><th class="py-2 pr-3">ลบ.ม.</th><th class="py-2 pr-3">ถพ.</th><th class="py-2 pr-3">จำนวนตัน</th><th class="py-2 pr-3">โรงงาน</th><th class="py-2 pr-3">จัดการ</th>
        </tr></thead>
        <tbody>
          ${rows.length ? rows.map(r => `
            <tr class="border-b border-secondary-50 hover:bg-secondary-50">
              <td class="py-2 pr-3 font-medium">${escapeHtml(r.stone_type || '-')}</td>
              <td class="py-2 pr-3">${fmtNum(r.volume_cum,2)}</td>
              <td class="py-2 pr-3">${fmtNum(r.bulk_density,2)}</td>
              <td class="py-2 pr-3">${fmtNum(r.ton_amount,2)}</td>
              <td class="py-2 pr-3">${escapeHtml(r.factories ? r.factories.name : '-')}</td>
              <td class="py-2 pr-3">
                <div class="flex items-center gap-1.5">
                  <button data-edit="${r.id}" class="p-1.5 rounded-lg hover:bg-secondary-100 text-secondary-500" title="แก้ไข"><i data-lucide="pencil" class="w-4 h-4"></i></button>
                  <button data-del="${r.id}" class="p-1.5 rounded-lg hover:bg-red-50 text-red-500" title="ลบ"><i data-lucide="trash-2" class="w-4 h-4"></i></button>
                </div>
              </td>
            </tr>`).join('') : `<tr><td colspan="6" class="py-8 text-center text-secondary-400">ไม่พบข้อมูล</td></tr>`}
        </tbody>
      </table>
    </div>`;
  refreshIcons();
  qsa('[data-edit]', el).forEach(btn => btn.addEventListener('click', () => openDroneStockForm(btn.getAttribute('data-edit'))));
  qsa('[data-del]', el).forEach(btn => btn.addEventListener('click', () => confirmDeleteDroneStock(btn.getAttribute('data-del'))));
}

function openDroneStockForm(id) {
  const editing = id ? _mDroneCache.find(r => r.id === id) : null;
  showModal({
    title: editing ? 'แก้ไขสต็อคหิน' : 'เพิ่มสต็อคหิน',
    hideConfirm: true, hideCancel: true,
    bodyHtml: `
      <form id="drone-stock-form" class="space-y-3 max-h-[65vh] overflow-y-auto pr-1">
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">ชนิดหิน *</label>
          <select id="ds-stone-type" required class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
            <option value="">เลือกชนิดหิน...</option>
          </select>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">โรงงาน</label>
          <select id="ds-factory" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
            ${(_mDroneFactories||[]).map(f => `<option value="${f.id}" ${editing && editing.factory_id===f.id ? 'selected':''}>${escapeHtml(f.name)}</option>`).join('')}
          </select>
        </div>
        <div class="grid grid-cols-2 gap-2">
          <div>
            <label class="block text-xs font-medium text-secondary-500 mb-1">เดือน</label>
            <select id="ds-month" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
              ${Array.from({length:12},(_, i) => i+1).map(m => `<option value="${m}" ${editing ? (editing.stock_month===m?'selected':'') : (m===_mDroneFilter.month?'selected':'')}>${monthNameTH(m)}</option>`).join('')}
            </select>
          </div>
          <div>
            <label class="block text-xs font-medium text-secondary-500 mb-1">ปี</label>
            <select id="ds-year" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
              ${Array.from({length:5},(_, i) => new Date().getFullYear()-i).map(y => `<option value="${y}" ${editing ? (editing.stock_year===y?'selected':'') : (y===_mDroneFilter.year?'selected':'')}>${y}</option>`).join('')}
            </select>
          </div>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">หน่วย</label>
          <input id="ds-unit" type="text" value="${editing ? escapeHtml(editing.unit || 'ตัน') : 'ตัน'}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div class="grid grid-cols-2 gap-2">
          <div>
            <label class="block text-xs font-medium text-secondary-500 mb-1">ปริมาตร (ลบ.ม.)</label>
            <input id="ds-volume" type="number" step="any" value="${editing ? (editing.volume_cum ?? '') : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
          </div>
          <div>
            <label class="block text-xs font-medium text-secondary-500 mb-1">ถพ.(ค่าความถ่วงจำเพาะ)</label>
            <input id="ds-density" type="number" step="any" value="${editing ? (editing.bulk_density ?? '') : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
          </div>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">จำนวนตัน (คำนวณอัตโนมัติ = ลบ.ม. × ถพ.)</label>
          <input id="ds-ton" type="number" step="any" readonly value="${editing ? (editing.ton_amount ?? '') : ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm bg-secondary-50">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">สถานะ</label>
          <select id="ds-status" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
            <option value="active" ${(!editing || editing.status==='active')?'selected':''}>active</option>
            <option value="inactive" ${(editing && editing.status==='inactive')?'selected':''}>inactive</option>
          </select>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">หมายเหตุ</label>
          <textarea id="ds-note" rows="2" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">${editing ? escapeHtml(editing.note || '') : ''}</textarea>
        </div>
        <button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">${editing ? 'บันทึกการแก้ไข' : 'เพิ่มสต็อค'}</button>
      </form>`,
  });
  const recompute = () => {
    const vol = Number(document.getElementById('ds-volume').value) || 0;
    const den = Number(document.getElementById('ds-density').value) || 0;
    document.getElementById('ds-ton').value = (vol * den) || '';
  };
  document.getElementById('ds-volume').addEventListener('input', recompute);
  document.getElementById('ds-density').addEventListener('input', recompute);

  const populateStoneTypeOptions = (factoryId, selectedName) => {
    const sel = document.getElementById('ds-stone-type');
    if (!sel) return;
    const opts = (window._droneMaterialsCache || []).filter(m => m.factory_id === factoryId);
    sel.innerHTML = `<option value="">เลือกชนิดหิน...</option>` + opts.map(m => `<option value="${escapeHtml(m.name)}" ${m.name===selectedName?'selected':''}>${escapeHtml(m.name)}</option>`).join('');
  };
  const applyBulkDensityFromMaterial = (factoryId) => {
    const sel = document.getElementById('ds-stone-type');
    const denInput = document.getElementById('ds-density');
    if (!sel || !denInput) return;
    const mat = (window._droneMaterialsCache || []).find(m => m.factory_id === factoryId && m.name === sel.value);
    if (mat && mat.bulk_density != null) {
      denInput.value = mat.bulk_density;
      recompute();
    }
  };
  loadDroneStockMaterialsCache().then(() => {
    const factorySel = document.getElementById('ds-factory');
    const curFactoryId = factorySel ? factorySel.value : null;
    populateStoneTypeOptions(curFactoryId, editing ? editing.stone_type : '');
  });
  document.getElementById('ds-factory').addEventListener('change', (e) => {
    populateStoneTypeOptions(e.target.value, '');
  });
  document.getElementById('ds-stone-type').addEventListener('change', (e) => {
    const factorySel = document.getElementById('ds-factory');
    applyBulkDensityFromMaterial(factorySel ? factorySel.value : null);
  });

  const form = document.getElementById('drone-stock-form');
  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    const vol = Number(document.getElementById('ds-volume').value) || 0;
    const den = Number(document.getElementById('ds-density').value) || 0;
    const dsFactoryId = document.getElementById('ds-factory').value || null;
    const dsFactoryObj = (_mDroneFactories || []).find(f => f.id === dsFactoryId);
    const payload = {
      stone_type: document.getElementById('ds-stone-type').value.trim(),
      factory_id: dsFactoryId,
      factory_name: dsFactoryObj ? normalizeFactoryName(dsFactoryObj.name) : null,
      stock_month: Number(document.getElementById('ds-month').value),
      stock_year: Number(document.getElementById('ds-year').value),
      unit: document.getElementById('ds-unit').value.trim() || null,
      volume_cum: vol,
      bulk_density: den,
      ton_amount: vol * den,
      status: document.getElementById('ds-status').value,
      note: document.getElementById('ds-note').value.trim() || null,
    };
    try {
      if (editing) {
        const { error } = await db.from('drone_stock').update(payload).eq('id', editing.id);
        if (error) throw error;
        showToast('แก้ไขข้อมูลสำเร็จ', 'success');
      } else {
        const { error } = await db.from('drone_stock').insert([payload]);
        if (error) throw error;
        showToast('เพิ่มข้อมูลสำเร็จ', 'success');
      }
      closeModal();
      loadManageDroneStock();
    } catch (err) {
      console.error(err);
      showToast('เกิดข้อผิดพลาด: ' + (err.message || ''), 'error');
    }
  });
}

function confirmDeleteDroneStock(id) {
  showModal({
    title: 'ยืนยันการลบ',
    bodyHtml: `ต้องการลบรายการสต็อคนี้ใช่หรือไม่?`,
    confirmText: 'ลบ', cancelText: 'ยกเลิก',
    onConfirm: async () => {
      try {
        const { error } = await db.from('drone_stock').delete().eq('id', id);
        if (error) throw error;
        showToast('ลบข้อมูลสำเร็จ', 'success');
        loadManageDroneStock();
      } catch (err) {
        console.error(err);
        showToast('ลบไม่สำเร็จ: ' + (err.message || ''), 'error');
      }
    }
  });
}

function exportDroneStockExcel() {
  if (!_mDroneCache.length) { showToast('ไม่มีข้อมูลให้ export', 'warning'); return; }
  const rows = _mDroneCache.map(r => ({
    'factory_name': r.factory_name || (r.factories ? normalizeFactoryName(r.factories.name) : ''),
    'ชนิดหิน': r.stone_type || '', 'ลบ.ม.': r.volume_cum || 0, 'ถพ.': r.bulk_density || 0,
    'จำนวนตัน': r.ton_amount || 0, 'หน่วย': r.unit || '',
    'สถานะ': r.status || '', 'หมายเหตุ': r.note || '',
  }));
  const ws = XLSX.utils.json_to_sheet(rows);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'DroneStock');
  XLSX.writeFile(wb, `drone_stock_${_mDroneFilter.year}_${_mDroneFilter.month}.xlsx`);
}

// helper: อ่านไฟล์ Excel (.xlsx/.xls) หรือ CSV แล้วคืน array of objects (ใช้ SheetJS)
// CSV: ลอง UTF-8 ก่อน ถ้ามี replacement char (ภาษาไทย Windows บันทึกเป็น TIS-620/windows-874) ให้ fallback อัตโนมัติ
async function readFileToJson(file) {
  const isCsv = file.name.toLowerCase().endsWith('.csv');
  if (isCsv) {
    const buffer = await file.arrayBuffer();
    let text = new TextDecoder('utf-8', { fatal: false }).decode(buffer);
    if (text.includes('�')) {
      try { text = new TextDecoder('windows-874').decode(buffer); } catch(_) {}
    }
    // raw:true ป้องกัน SheetJS แปลง "1/6/69" เป็น date object ก่อนส่งให้ normalizeDateStr
    const wb = XLSX.read(text, { type: 'string', raw: true });
    const ws = wb.Sheets[wb.SheetNames[0]];
    return XLSX.utils.sheet_to_json(ws, { defval: '', raw: true });
  } else {
    const data = await file.arrayBuffer();
    const wb = XLSX.read(data);
    const ws = wb.Sheets[wb.SheetNames[0]];
    // raw: false → ให้ SheetJS แปลง date serial เป็น string ตาม cell format เดิม (เช่น "1/5/69")
    return XLSX.utils.sheet_to_json(ws, { defval: '', raw: false });
  }
}

// แปลงรูปแบบวันที่หลายแบบให้เป็น YYYY-MM-DD (ค.ศ.)
// รองรับ: 2026-05-31 / 31/5/26 / 31/05/2026 / 2569-05-31 / 31/5/2569 / 31/5/69 (พ.ศ.)
// Logic แปลง พ.ศ. → ค.ศ.:
//   ปี 4 หลัก >= 2500  → ลบ 543  (เช่น 2569 → 2026)
//   ปี 2 หลัก >= 43   → +1957   (เช่น 69 = พ.ศ. 2569 → 2026)
//   ปี 2 หลัก < 43    → +2000   (เช่น 26 = ค.ศ. 2026)
function normalizeDateStr(str) {
  if (!str && str !== 0) return str;
  // Fallback: Excel date serial number (เลขทศนิยม เช่น 25208.000046296296)
  // กรณีนี้เกิดขึ้นเมื่อ SheetJS คืน raw serial แทน string — ใช้ raw:false แล้วปัญหานี้ไม่ควรเกิด
  // แต่เก็บ fallback ไว้กันกรณี edge case (แปลงตรงๆ ไม่ปรับปีไทย เพราะ serial สูญข้อมูล format ไปแล้ว)
  const numStr = String(str).trim();
  if (/^\d+(\.\d+)?$/.test(numStr)) {
    const serial = Number(numStr);
    if (serial > 20000 && serial < 100000) {
      const msec = (serial - 25569) * 86400 * 1000;
      const d = new Date(Math.round(msec));
      return d.toISOString().slice(0, 10);
    }
  }
  const s = String(str).trim();
  // YYYY-MM-DD (รวมกรณี พ.ศ. เช่น 2569-05-01)
  const iso = s.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
  if (iso) {
    let y = Number(iso[1]);
    if (y >= 2500) y -= 543;
    return `${y}-${iso[2].padStart(2,'0')}-${iso[3].padStart(2,'0')}`;
  }
  // DD/MM/YYYY หรือ D/M/YYYY (4-digit year, รวม พ.ศ.)
  const m4 = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (m4) {
    let y = Number(m4[3]);
    if (y >= 2500) y -= 543;
    return `${y}-${m4[2].padStart(2,'0')}-${m4[1].padStart(2,'0')}`;
  }
  // DD/MM/YY หรือ D/M/YY (2-digit year)
  const m2 = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2})$/);
  if (m2) {
    const yy = Number(m2[3]);
    const y = yy >= 43 ? yy + 1957 : yy + 2000;
    return `${y}-${m2[2].padStart(2,'0')}-${m2[1].padStart(2,'0')}`;
  }
  return s;
}

// คาดหวังหัวคอลัมน์ในไฟล์ Excel: factory_name (CDE/Propel/Sanon1/Sanon2), ชนิดหิน, ลบ.ม., ถพ., หน่วย, สถานะ, หมายเหตุ
// โดยจะ resolve factory_name -> factory_id ผ่าน cache _mDroneFactories ที่โหลดไว้แล้ว (รองรับชื่อทั้งแบบมี/ไม่มีเว้นวรรค)
async function importDroneStockExcel(e) {
  const file = e.target.files[0];
  if (!file) return;
  try {
    const json = await readFileToJson(file);
    if (!json.length) { showToast('ไฟล์ไม่มีข้อมูล', 'warning'); return; }
    await loadDroneStockFactoriesCache();
    const notFound = [];
    const rows = json.map((row, i) => {
      // รองรับชื่อ column ทั้งภาษาไทยและอังกฤษ
      const fnameRaw = String(row['factory_name'] || row['โรงงาน'] || '').trim();
      const factory = findFactoryByName(_mDroneFactories, fnameRaw);
      if (fnameRaw && !factory) notFound.push(`แถว ${i+2}: "${fnameRaw}"`);
      const vol = Number(row['volume_cum'] !== '' ? row['volume_cum'] : null) || Number(row['ลบ.ม.']) || 0;
      const den = Number(row['bulk_density'] !== '' ? row['bulk_density'] : null) || Number(row['ถพ.']) || 0;
      const tonFromFile = Number(row['ton_amount'] !== '' ? row['ton_amount'] : null);
      const tonAmt = tonFromFile > 0 ? tonFromFile : (vol * den);
      const stockMonth = Number(row['stock_month']) || _mDroneFilter.month;
      const stockYear = Number(row['stock_year']) || _mDroneFilter.year;
      const unitVal = String(row['unit'] || row['หน่วย'] || '').trim() || 'ตัน';
      const statusVal = String(row['status'] || row['สถานะ'] || '').trim() || 'active';
      const noteVal = String(row['note'] !== undefined ? row['note'] : (row['หมายเหตุ'] || '')).trim() || null;
      return {
        stone_type: String(row['stone_type'] || row['ชนิดหิน'] || '').trim(),
        volume_cum: vol,
        bulk_density: den,
        ton_amount: tonAmt,
        factory_id: factory ? factory.id : null,
        factory_name: normalizeFactoryName(fnameRaw) || null,
        unit: unitVal,
        status: statusVal,
        note: noteVal,
        stock_month: stockMonth,
        stock_year: stockYear,
      };
    });
    if (notFound.length) {
      showToast(`ไม่พบโรงงานตามชื่อที่กรอก: ${notFound.join(', ')}`, 'error');
      return;
    }
    const { error } = await db.from('drone_stock').insert(rows);
    if (error) throw error;
    showToast(`นำเข้าข้อมูลสำเร็จ ${rows.length} รายการ`, 'success');
    e.target.value = '';
    loadManageDroneStock();
  } catch (err) {
    console.error(err);
    showToast('นำเข้าข้อมูลล้มเหลว: ' + (err.message || ''), 'error');
  }
}
