const _mProdState = {}; // plantKey -> { rows, materialsCache, search, rawMaterialFilter, materialFilter, month, year, editingId, distinctRawMaterials, latestRow }
function getMProdState(plantKey) {
  if (!_mProdState[plantKey]) {
    _mProdState[plantKey] = {
      rows: [], materialsCache: null, search: '', rawMaterialFilter: 'all', materialFilter: 'all',
      month: new Date().getMonth()+1, year: new Date().getFullYear(), editingId: null,
      distinctRawMaterials: [], latestRow: null, _initialized: false,
    };
  }
  return _mProdState[plantKey];
}

// โหลด raw_material แบบ distinct (self-referencing ตาราง production_* ของ plant นั้นเอง) และแถวล่าสุด
// (เพื่อ auto-fill ชม.เริ่ม/นาทีเริ่ม/มิเตอร์เริ่ม ของฟอร์ม "เพิ่ม" ใหม่)
async function loadProductionDistinctRawMaterialsAndLatest(plantKey) {
  const cfg = PRODUCTION_PLANT_CONFIG[plantKey];
  const st = getMProdState(plantKey);
  try {
    const { data, error } = await db.from(cfg.table).select('raw_material');
    if (error) throw error;
    const set = new Set();
    (data || []).forEach(r => { if (r.raw_material && String(r.raw_material).trim()) set.add(String(r.raw_material).trim()); });
    st.distinctRawMaterials = Array.from(set);
  } catch (err) {
    console.error(err);
    st.distinctRawMaterials = [];
  }
  try {
    const { data, error } = await db.from(cfg.table).select('*')
      .order('production_date', { ascending: false })
      .order('created_at', { ascending: false })
      .limit(1);
    if (error) throw error;
    st.latestRow = (data && data[0]) || null;
  } catch (err) {
    console.error(err);
    st.latestRow = null;
  }
}

function prodStatusBadgeClass(status) {
  const map = { approved: 'bg-emerald-50 text-emerald-600', pending: 'bg-amber-50 text-amber-600', rejected: 'bg-red-50 text-red-600' };
  return map[status] || 'bg-secondary-100 text-secondary-500';
}

