async function loadProductionMaterialsCache() {
  // ใช้ cache กลางตัวเดียวสำหรับทุก plant (material_types ไม่ขึ้นกับ plant)
  if (window._prodMaterialsCache) {
    Object.values(_mProdState).forEach(s => { s.materialsCache = window._prodMaterialsCache; });
    return;
  }
  try {
    const { data, error } = await db.from('material_types').select('*').eq('status','active');
    if (error) throw error;
    window._prodMaterialsCache = data || [];
  } catch (err) {
    console.error(err);
    window._prodMaterialsCache = [];
  }
  Object.values(_mProdState).forEach(s => { s.materialsCache = window._prodMaterialsCache; });
}

async function loadProductionData(plantKey) {
  const cfg = PRODUCTION_PLANT_CONFIG[plantKey];
  const st = getMProdState(plantKey);
  ['table1','table2','table3'].forEach(t => {
    const el = document.getElementById(`mp-${plantKey}-${t}-block`);
    if (el) el.innerHTML = skeletonBlock('h-56');
  });
  if (!st._initialized) {
    st._initialized = true;
    const { data: latest } = await db.from(cfg.table)
      .select('production_date').order('production_date', { ascending: false }).limit(1);
    if (latest && latest.length) {
      const d = new Date(latest[0].production_date);
      st.month = d.getMonth() + 1;
      st.year = d.getFullYear();
      const mSel = document.getElementById(`mp-${plantKey}-month`);
      const ySel = document.getElementById(`mp-${plantKey}-year`);
      if (mSel) mSel.value = st.month;
      if (ySel) ySel.value = st.year;
    }
  }
  try {
    const from = `${st.year}-${pad2(st.month)}-01`;
    const lastDay = new Date(st.year, st.month, 0).getDate();
    const to = `${st.year}-${pad2(st.month)}-${pad2(lastDay)}`;
    const { data, error } = await db.from(cfg.table).select('*')
      .gte('production_date', from).lte('production_date', to)
      .order('production_date', { ascending: false });
    if (error) throw error;
    st.rows = data || [];
    renderProductionTables(plantKey);
  } catch (err) {
    console.error(err);
    ['table1','table2','table3'].forEach(t => {
      const el = document.getElementById(`mp-${plantKey}-${t}-block`);
      if (el) el.innerHTML = errorBlock();
    });
    refreshIcons();
  }
}

function getFilteredProductionRows(plantKey) {
  const st = getMProdState(plantKey);
  const kw = st.search.trim().toLowerCase();
  return st.rows.filter(r => {
    if (kw && !(r.raw_material || '').toLowerCase().includes(kw)) return false;
    if (st.rawMaterialFilter !== 'all' && (r.raw_material || '') !== st.rawMaterialFilter) return false;
    // หมายเหตุ: production_* ไม่มี FK ไปยัง material_types — ใช้วิธี match แบบ substring
    // ระหว่างชื่อ material_types ที่เลือกกับข้อความ raw_material (best-effort, ไม่ใช่ FK จริง)
    if (st.materialFilter !== 'all' && !(r.raw_material || '').toLowerCase().includes(st.materialFilter.toLowerCase())) return false;
    return true;
  });
}

