function exportLoaderExcel() {
  if (!_mLoaderCache.length) { showToast('ไม่มีข้อมูลให้ export', 'warning'); return; }
  const rows = _mLoaderCache.map(r => ({
    'factory_name': r.factory_name || (r.factories ? normalizeFactoryName(r.factories.name) : ''),
    'วันเดือนปี': r.work_date, 'รถตัก': r.loader_name || '', 'รวมเวลาทำงาน': r.total_work_time || '',
    'รวมชั่วโมงทำงาน': r.total_work_hour || 0, 'ปริมาณชาร์จ(KW)': r.charge_kw || 0, 'ค่าไฟฟ้า(บาท)': r.electric_cost_baht || 0,
    'หมายเหตุ': r.note || '',
  }));
  const ws = XLSX.utils.json_to_sheet(rows);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'ElectricLoader');
  XLSX.writeFile(wb, `electric_loader_export.xlsx`);
}

// แปลง time string (H:MM:SS หรือ HH:MM:SS) → decimal hours (เช่น "6:30:00" → 6.5)
// ถ้าเป็นตัวเลขอยู่แล้วให้คืนค่าเดิม
function timeStrToDecimalHour(val) {
  if (val == null || val === '') return null;
  const s = String(val).trim();
  const m = s.match(/^(\d{1,2}):(\d{2})(?::(\d{2}))?$/);
  if (m) return Number(m[1]) + Number(m[2]) / 60 + (m[3] ? Number(m[3]) / 3600 : 0);
  const n = parseFloat(s);
  return isNaN(n) ? null : n;
}

// คาดหวังหัวคอลัมน์ในไฟล์ CSV/Excel ของ electric_loader:
// factory_name, work_date, loader_name, start_hour, stop_hour,
// machine_hour_start, machine_hour_stop,
// battery_start_pct, battery_remaining_pct, charge_minutes, charge_kw, electric_rate, breakdown_detail, note
// หมายเหตุ: total_work_hour, machine_hour_total, electric_cost_baht คำนวณอัตโนมัติ (ไม่ต้องกรอก)
// start_hour/stop_hour รองรับทั้ง decimal (6.5) และ time string (6:30:00)
async function importLoaderExcel(e) {
  const file = e.target.files[0];
  if (!file) return;
  try {
    const json = await readFileToJson(file);
    if (!json.length) { showToast('ไฟล์ไม่มีข้อมูล', 'warning'); return; }
    await loadLoaderFactoriesCache();
    const status = productionRowStatusForRole();
    const createdBy = currentUser ? currentUser.id : null;
    // ไม่รวม start_hour/stop_hour/total_work_hour/electric_cost_baht — จัดการแยกด้านล่าง
    // electric_cost_baht คำนวณอัตโนมัติ: charge_kw * electric_rate
    const allowedKeys = ['work_date','loader_name','start_time','stop_time','total_work_time','machine_hour_start','machine_hour_stop','hour_meter_offset','battery_start_pct','battery_remaining_pct','charge_minutes','charge_kw','electric_rate','breakdown_detail','note'];
    const notFound = [];
    const rows = json.map((row, i) => {
      const obj = { status, created_by: createdBy };
      const numericLoaderKeys = new Set(['machine_hour_start','machine_hour_stop','hour_meter_offset','battery_start_pct','battery_remaining_pct','charge_minutes','charge_kw','electric_rate']);
      allowedKeys.forEach(k => {
        if (row[k] === undefined) return;
        if (k === 'work_date') { obj[k] = normalizeDateStr(row[k]); return; }
        if (numericLoaderKeys.has(k)) {
          const v = row[k];
          obj[k] = (v === '' || v === null || v === undefined) ? null : (isNaN(Number(v)) ? null : Number(v));
          return;
        }
        obj[k] = row[k];
      });

      // start_hour / stop_hour — รองรับ time string ("6:30:00") และ decimal (6.5)
      const startRaw = String(row['start_hour'] !== undefined ? row['start_hour'] : '').trim();
      const stopRaw  = String(row['stop_hour']  !== undefined ? row['stop_hour']  : '').trim();
      const sh = timeStrToDecimalHour(startRaw);
      const eh = timeStrToDecimalHour(stopRaw);
      if (sh != null) {
        obj.start_hour = sh;
        // ถ้าเป็น time string → เก็บเป็น start_time ด้วย (ถ้ายังไม่มี)
        if (/^\d{1,2}:\d{2}/.test(startRaw) && !obj.start_time) obj.start_time = startRaw;
      }
      if (eh != null) {
        obj.stop_hour = eh;
        if (/^\d{1,2}:\d{2}/.test(stopRaw) && !obj.stop_time) obj.stop_time = stopRaw;
      }

      // machine_hour_total เป็น Generated Column ใน DB (คำนวณอัตโนมัติ) — ไม่ต้อง set

      // auto-คำนวณ electric_cost_baht = charge_kw * electric_rate
      if (obj.charge_kw != null && obj.electric_rate != null) {
        obj.electric_cost_baht = Math.round(obj.charge_kw * obj.electric_rate * 100) / 100;
      }

      // auto-คำนวณ total_work_hour จาก stop_hour - start_hour (รองรับกะข้ามคืน)
      if (sh != null && eh != null) {
        const diff = eh >= sh ? (eh - sh) : (24 + eh - sh);
        obj.total_work_hour = Math.round(diff * 10000) / 10000;
        if (!obj.total_work_time) {
          const hrs = Math.floor(diff);
          const mins = Math.round((diff - hrs) * 60);
          obj.total_work_time = `${hrs} ชม. ${mins} นาที`;
        }
      }
      const fnameRaw = String(row['factory_name'] || row['โรงงาน'] || '').trim();
      const factory = findFactoryByName(_mLoaderFactories, fnameRaw);
      if (fnameRaw && !factory) notFound.push(`แถว ${i+2}: "${fnameRaw}"`);
      obj.factory_id = factory ? factory.id : null;
      obj.factory_name = normalizeFactoryName(fnameRaw) || null;
      return obj;
    });
    if (notFound.length) {
      showToast(`ไม่พบโรงงานตามชื่อที่กรอก: ${notFound.join(', ')}`, 'error');
      return;
    }
    // ป้องกันซ้ำ: ลบ records เดิมในช่วงวันที่+loader เดียวกันก่อน insert
    const dates = [...new Set(rows.map(r => r.work_date).filter(Boolean))];
    const loaders = [...new Set(rows.map(r => r.loader_name).filter(Boolean))];
    const { error: delErr } = await db.from('electric_loader')
      .delete()
      .in('work_date', dates)
      .in('loader_name', loaders);
    if (delErr) throw delErr;
    const { error } = await db.from('electric_loader').insert(rows);
    if (error) throw error;
    showToast(`นำเข้าข้อมูลสำเร็จ ${rows.length} รายการ (แทนที่ข้อมูลเดิมอัตโนมัติ)`, 'success');
    e.target.value = '';
    loadManageLoader();
  } catch (err) {
    console.error(err);
    showToast('นำเข้าข้อมูลล้มเหลว: ' + (err.message || ''), 'error');
  }
}
// =====================================================================
// SECTION 26: MANAGE — ยอดขาย (sales) — รองรับเพิ่มหลายแถวต่อครั้ง
// =====================================================================
let _mSalesCache = [];
let _mSalesFactories = null;
const _mSalesFilter = { search: '', month: new Date().getMonth()+1, year: new Date().getFullYear(), factoryId: 'all', _initialized: false };

// หมายเหตุ normalize: factories table เก็บชื่อ "Sanon 1"/"Sanon 2" (มีเว้นวรรค)
// แต่ sales.factory_code ต้องเป็น 'CDE'|'Propel'|'Sanon1'|'Sanon2' (ไม่มีเว้นวรรค) ตาม check constraint
// จึงต้อง strip ช่องว่างตอนแปลงชื่อโรงงาน -> factory_code
function factoryNameToCode(name) {
  const stripped = (name || '').replace(/\s+/g, '');
  if (['CDE','Propel','Sanon1','Sanon2'].includes(stripped)) return stripped;
  return null;
}

