      sel.innerHTML = `<option value="all">ทุกโรงงาน</option>` + _mSalesFactories.map(f => `<option value="${f.id}">${escapeHtml(f.name)}</option>`).join('');
      sel.addEventListener('change', (e) => { _mSalesFilter.factoryId = e.target.value; loadManageSales(); });
