async function loadSalesFactoriesCache() {
  if (_mSalesFactories) return;
  try {
    const { data, error } = await db.from('factories').select('id, name').eq('status','active');
    if (error) throw error;
    _mSalesFactories = data || [];
  } catch (err) {
    console.error(err);
    _mSalesFactories = [];
  }
}

async function loadSalesMaterialsCache() {
  if (window._salesMaterialsCache) return;
  try {
    const { data, error } = await db.from('material_types').select('*').eq('status','active');
    if (error) throw error;
    window._salesMaterialsCache = data || [];
  } catch (err) {
    console.error(err);
    window._salesMaterialsCache = [];
  }
}

async function loadManageSales() {
  const el = document.getElementById('sales-m-table-block');
  if (el) el.innerHTML = skeletonBlock('h-56');
  if (!_mSalesFilter._initialized) {
    _mSalesFilter._initialized = true;
    const { data: latest } = await db.from('sales')
      .select('sale_date').order('sale_date', { ascending: false }).limit(1);
    if (latest && latest.length) {
      const d = new Date(latest[0].sale_date);
      _mSalesFilter.month = d.getMonth() + 1;
      _mSalesFilter.year = d.getFullYear();
      const mSel = document.getElementById('sales-m-month');
      const ySel = document.getElementById('sales-m-year');
      if (mSel) mSel.value = _mSalesFilter.month;
      if (ySel) ySel.value = _mSalesFilter.year;
    }
  }
  try {
    const from = `${_mSalesFilter.year}-${pad2(_mSalesFilter.month)}-01`;
    const lastDay = new Date(_mSalesFilter.year, _mSalesFilter.month, 0).getDate();
    const to = `${_mSalesFilter.year}-${pad2(_mSalesFilter.month)}-${pad2(lastDay)}`;
    let query = db.from('sales').select('*, factories(name)').gte('sale_date', from).lte('sale_date', to);
    if (_mSalesFilter.factoryId !== 'all') query = query.eq('factory_id', _mSalesFilter.factoryId);
    const { data, error } = await query.order('sale_date', { ascending: false });
    if (error) throw error;
    _mSalesCache = data || [];
    renderManageSalesTable();
  } catch (err) {
    console.error(err);
    if (el) el.innerHTML = errorBlock();
    refreshIcons();
  }
}

