function populateSalesStoneOptions(rowGroup) {
  const factorySel = qs('.sr-factory', rowGroup);
  const stoneSel = qs('.sr-stone', rowGroup);
  if (!factorySel || !stoneSel) return;
  const factoryId = factorySel.value;
  const selectedName = stoneSel.getAttribute('data-selected') || stoneSel.value;
  const opts = (window._salesMaterialsCache || []).filter(m => m.factory_id === factoryId);
  stoneSel.innerHTML = `<option value="">เลือกชนิดหิน...</option>` + opts.map(m => `<option value="${escapeHtml(m.name)}" ${m.name===selectedName?'selected':''}>${escapeHtml(m.name)}</option>`).join('');
}

function bindSalesStoneRow(rowGroup) {
  populateSalesStoneOptions(rowGroup);
  const factorySel = qs('.sr-factory', rowGroup);
  if (factorySel) {
    factorySel.addEventListener('change', () => {
      const stoneSel = qs('.sr-stone', rowGroup);
      if (stoneSel) stoneSel.setAttribute('data-selected', '');
      populateSalesStoneOptions(rowGroup);
    });
  }
}

function openSalesForm() {
  showModal({
    title: 'เพิ่มยอดขาย (รองรับหลายแถว)',
    hideConfirm: true, hideCancel: true,
    bodyHtml: `
      <form id="sales-form" class="space-y-3">
        <div id="sales-rows-container" class="space-y-2 max-h-[50vh] overflow-y-auto pr-1">${salesRowHtml(0)}</div>
        <button type="button" id="sales-add-row-btn" class="flex items-center gap-1.5 text-sm text-primary-600 hover:underline"><i data-lucide="plus" class="w-4 h-4"></i>เพิ่มแถว</button>
        <button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">บันทึกยอดขาย</button>
      </form>`,
  });
  refreshIcons();
  let rowCount = 1;
  const container = document.getElementById('sales-rows-container');
  const bindRemove = () => {
    qsa('.sr-remove-btn', container).forEach(btn => {
      btn.onclick = () => {
        if (qsa('.sales-row-group', container).length <= 1) { showToast('ต้องมีอย่างน้อย 1 แถว', 'warning'); return; }
        btn.closest('.sales-row-group').remove();
      };
    });
  };
  bindRemove();
  loadSalesMaterialsCache().then(() => {
    qsa('.sales-row-group', container).forEach(g => bindSalesStoneRow(g));
  });
  document.getElementById('sales-add-row-btn').addEventListener('click', () => {
    container.insertAdjacentHTML('beforeend', salesRowHtml(rowCount++));
    refreshIcons();
    bindRemove();
    const newGroup = qsa('.sales-row-group', container).slice(-1)[0];
    if (newGroup) bindSalesStoneRow(newGroup);
  });

  document.getElementById('sales-form').addEventListener('submit', async (e) => {
    e.preventDefault();
    const groups = qsa('.sales-row-group', container);
    const rows = [];
    for (const g of groups) {
      const factoryId = qs('.sr-factory', g).value;
      const factory = (_mSalesFactories||[]).find(f => f.id === factoryId);
      const factoryCode = factory ? factoryNameToCode(factory.name) : null;
      rows.push({
        sale_date: qs('.sr-date', g).value,
        factory_id: factoryId || null,
        factory_code: factoryCode,
        factory_name: factoryCode,
        stone_type: qs('.sr-stone', g).value.trim() || null,
        quantity_ton: numOrNull(qs('.sr-qty', g).value),
        price_per_ton: numOrNull(qs('.sr-price', g).value),
        customer_name: qs('.sr-customer', g).value.trim() || null,
        note: qs('.sr-note', g).value.trim() || null,
        created_by: currentUser ? currentUser.id : null,
      });
    }
    try {
      const { error } = await db.from('sales').insert(rows);
      if (error) throw error;
      showToast(`บันทึกยอดขายสำเร็จ ${rows.length} รายการ`, 'success');
      closeModal();
      loadManageSales();
    } catch (err) {
      console.error(err);
      showToast('เกิดข้อผิดพลาด: ' + (err.message || ''), 'error');
    }
  });
}

function openSalesEditForm(id) {
  const editing = _mSalesCache.find(r => r.id === id);
  if (!editing) return;
  showModal({
    title: 'แก้ไขยอดขาย',
    hideConfirm: true, hideCancel: true,
    bodyHtml: `<form id="sales-edit-form" class="space-y-3">${salesRowHtml(0, editing)}
      <button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">บันทึกการแก้ไข</button>
    </form>`,
  });
  refreshIcons();
  const removeBtn = qs('.sr-remove-btn');
  if (removeBtn) removeBtn.classList.add('hidden');
  loadSalesMaterialsCache().then(() => {
    const g = qs('.sales-row-group');
    if (g) bindSalesStoneRow(g);
  });
  document.getElementById('sales-edit-form').addEventListener('submit', async (e) => {
    e.preventDefault();
    const g = qs('.sales-row-group');
    const factoryId = qs('.sr-factory', g).value;
    const factory = (_mSalesFactories||[]).find(f => f.id === factoryId);
    const factoryCodeEdit = factory ? factoryNameToCode(factory.name) : null;
    const payload = {
      sale_date: qs('.sr-date', g).value,
      factory_id: factoryId || null,
      factory_code: factoryCodeEdit,
      factory_name: factoryCodeEdit,
      stone_type: qs('.sr-stone', g).value.trim() || null,
      quantity_ton: numOrNull(qs('.sr-qty', g).value),
      price_per_ton: numOrNull(qs('.sr-price', g).value),
      customer_name: qs('.sr-customer', g).value.trim() || null,
      note: qs('.sr-note', g).value.trim() || null,
    };
    try {
      const { error } = await db.from('sales').update(payload).eq('id', editing.id);
      if (error) throw error;
      showToast('แก้ไขข้อมูลสำเร็จ', 'success');
      closeModal();
      loadManageSales();
    } catch (err) {
      console.error(err);
      showToast('เกิดข้อผิดพลาด: ' + (err.message || ''), 'error');
    }
  });
}

function confirmDeleteSales(id) {
  showModal({
    title: 'ยืนยันการลบ',
    bodyHtml: `ต้องการลบรายการขายนี้ใช่หรือไม่?`,
    confirmText: 'ลบ', cancelText: 'ยกเลิก',
    onConfirm: async () => {
      try {
        const { error } = await db.from('sales').delete().eq('id', id);
        if (error) throw error;
        showToast('ลบข้อมูลสำเร็จ', 'success');
        loadManageSales();
      } catch (err) {
        console.error(err);
        showToast('ลบไม่สำเร็จ: ' + (err.message || ''), 'error');
      }
    }
  });
}

function exportSalesExcel() {
  if (!_mSalesCache.length) { showToast('ไม่มีข้อมูลให้ export', 'warning'); return; }
  const rows = _mSalesCache.map(r => ({
    'factory_name': r.factory_name || r.factory_code || (r.factories ? normalizeFactoryName(r.factories.name) : ''),
    'sale_date': r.sale_date,
    'stone_type': r.stone_type || '',
    'quantity_ton': r.quantity_ton || 0,
    'price_per_ton': r.price_per_ton != null ? r.price_per_ton : '',
    'total_value': r.total_value != null ? r.total_value : '',
    'customer_name': r.customer_name || '',
    'note': r.note || '',
  }));
  const ws = XLSX.utils.json_to_sheet(rows);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Sales');
  XLSX.writeFile(wb, `sales_export.xlsx`);
}

// คาดหวังหัวคอลัมน์: factory_name, sale_date, stone_type, quantity_ton, price_per_ton, customer_name, note
async function importSalesExcel(e) {
  const file = e.target.files[0];
  if (!file) return;
  try {
    const json = await readFileToJson(file);
    if (!json.length) { showToast('ไฟล์ไม่มีข้อมูล', 'warning'); return; }
    await loadSalesFactoriesCache();
    const createdBy = currentUser ? currentUser.id : null;
    const notFound = [];
    const rows = json.map((row, i) => {
      const fnameRaw = String(row['factory_name'] || row['โรงงาน'] || '').trim();
      const factory = findFactoryByName(_mSalesFactories, fnameRaw);
      if (fnameRaw && !factory) notFound.push(`แถว ${i+2}: "${fnameRaw}"`);
      const code = factory ? factoryNameToCode(factory.name) : normalizeFactoryName(fnameRaw);
      const saleDateVal = normalizeDateStr(row['sale_date'] || row['วันที่'] || '');
      const stoneTypeVal = String(row['stone_type'] || row['ชนิดหิน'] || '').trim() || null;
      const qtyVal = Number(row['quantity_ton'] !== '' ? row['quantity_ton'] : null) || Number(row['ปริมาณ(ตัน)']) || 0;
      const priceRaw = row['price_per_ton'] !== undefined ? row['price_per_ton'] : (row['ราคา(บาท/ตัน)'] !== undefined ? row['ราคา(บาท/ตัน)'] : '');
      const priceVal = priceRaw !== '' && priceRaw != null ? Number(priceRaw) || null : null;
      const customerVal = String(row['customer_name'] !== undefined ? row['customer_name'] : (row['ลูกค้า'] || '')).trim() || null;
      const noteVal = String(row['note'] !== '' ? row['note'] : (row['หมายเหตุ'] || '')).trim() || null;
      return {
        sale_date: saleDateVal,
        factory_id: factory ? factory.id : null,
        factory_code: code,
        factory_name: code,
        stone_type: stoneTypeVal,
        quantity_ton: qtyVal,
        price_per_ton: priceVal,
        customer_name: customerVal,
        note: noteVal,
        created_by: createdBy,
      };
    });
    if (notFound.length) {
      showToast(`ไม่พบโรงงานตามชื่อที่กรอก: ${notFound.join(', ')}`, 'error');
      return;
    }
    const { error } = await db.from('sales').insert(rows);
    if (error) throw error;
    showToast(`นำเข้าข้อมูลสำเร็จ ${rows.length} รายการ`, 'success');
    e.target.value = '';
    loadManageSales();
  } catch (err) {
    console.error(err);
    showToast('นำเข้าข้อมูลล้มเหลว: ' + (err.message || ''), 'error');
  }
}
