async function loadWaterAvailableMonths() {
  if (_mWaterAvailableMonths) return;
  try {
    const { data, error } = await db.from('groundwater_usage').select('usage_date').order('usage_date', { ascending: false });
    if (error) throw error;
    const seen = new Set();
    const months = [];
    (data || []).forEach(r => {
      const key = String(r.usage_date).slice(0, 7);
      if (!seen.has(key)) {
        seen.add(key);
        const [y, m] = key.split('-');
        months.push({ year: Number(y), month: Number(m), key });
      }
    });
    _mWaterAvailableMonths = months;
  } catch(e) { _mWaterAvailableMonths = []; }
}

function populateWaterMonthSelect() {
  const sel = document.getElementById('water-m-ym');
  if (!sel || !_mWaterAvailableMonths) return;
  const months = _mWaterAvailableMonths;
  if (!months.length) {
    sel.innerHTML = '<option value="">ไม่มีข้อมูล</option>';
    return;
  }
  sel.innerHTML = months.map(({ year, month, key }) =>
    `<option value="${key}" ${key === _mWaterFilter.ym ? 'selected' : ''}>${monthNameTH(month)} ${year}</option>`
  ).join('');
  // auto-select latest if current ym not in list
  if (!_mWaterFilter.ym || !months.find(m => m.key === _mWaterFilter.ym)) {
    _mWaterFilter.ym = months[0].key;
    sel.value = _mWaterFilter.ym;
  }
}

async function loadManageGroundwater() {
  const el = document.getElementById('water-m-table-block');
  if (el) el.innerHTML = skeletonBlock('h-56');
  try {
    if (!_factoriesCache.length) {
      const { data: fData, error: fError } = await db.from('factories').select('*').order('name', { ascending: true });
      if (fError) throw fError;
      _factoriesCache = fData || [];
    }
    await loadWaterSourcesCacheForUsage();
    await loadWaterAvailableMonths();
    populateWaterMonthSelect();
    if (!_mWaterFilter.ym) { renderManageGroundwaterTable(); return; }
    const [y, m] = _mWaterFilter.ym.split('-').map(Number);
    const from = `${y}-${pad2(m)}-01`;
    const to = `${y}-${pad2(m)}-${pad2(new Date(y, m, 0).getDate())}`;
    const { data, error } = await db.from('groundwater_usage').select('*').gte('usage_date', from).lte('usage_date', to).order('usage_date', { ascending: false });
    if (error) throw error;
    _mWaterCache = data || [];
    renderManageGroundwaterTable();
  } catch (err) {
    console.error(err);
    if (el) el.innerHTML = errorBlock();
    refreshIcons();
  }
}

function renderManageGroundwaterTable() {
  const el = document.getElementById('water-m-table-block');
  if (!el) return;
  const kw = _mWaterFilter.search.trim().toLowerCase();
  const rows = _mWaterCache.filter(r => {
    if (!kw) return true;
    return (r.location || '').toLowerCase().includes(kw) || (r.note || '').toLowerCase().includes(kw);
  });
  el.innerHTML = `
    <div class="bg-white rounded-2xl shadow-sm p-5 overflow-x-auto">
      <table class="w-full text-sm">
        <thead><tr class="text-left text-secondary-400 border-b border-secondary-100">
          <th class="py-2 pr-3">วันที่</th><th class="py-2 pr-3">สถานที่</th><th class="py-2 pr-3">มิเตอร์เริ่ม</th><th class="py-2 pr-3">มิเตอร์สิ้นสุด</th><th class="py-2 pr-3">ใช้น้ำ(ลบ.ม.)</th><th class="py-2 pr-3">หมายเหตุ</th><th class="py-2 pr-3">จัดการ</th>
        </tr></thead>
        <tbody>
          ${rows.length ? rows.map(r => `
            <tr class="border-b border-secondary-50 hover:bg-secondary-50">
              <td class="py-2 pr-3">${fmtDate(r.usage_date)}</td>
              <td class="py-2 pr-3">${escapeHtml(r.location || '-')}</td>
              <td class="py-2 pr-3">${fmtNum(r.meter_start,2)}</td>
              <td class="py-2 pr-3">${fmtNum(r.meter_stop,2)}</td>
              <td class="py-2 pr-3 font-medium">${fmtNum(r.usage_cum,2)}</td>
              <td class="py-2 pr-3 text-secondary-500">${escapeHtml(r.note || '-')}</td>
              <td class="py-2 pr-3">
                <div class="flex items-center gap-1.5">
                  <button data-edit="${r.id}" class="p-1.5 rounded-lg hover:bg-secondary-100 text-secondary-500" title="แก้ไข"><i data-lucide="pencil" class="w-4 h-4"></i></button>
                  <button data-del="${r.id}" class="p-1.5 rounded-lg hover:bg-red-50 text-red-500" title="ลบ"><i data-lucide="trash-2" class="w-4 h-4"></i></button>
                </div>
              </td>
            </tr>`).join('') : `<tr><td colspan="7" class="py-8 text-center text-secondary-400">ไม่พบข้อมูล</td></tr>`}
        </tbody>
      </table>
    </div>`;
  refreshIcons();
  qsa('[data-edit]', el).forEach(btn => btn.addEventListener('click', () => openWaterEditForm(btn.getAttribute('data-edit'))));
  qsa('[data-del]', el).forEach(btn => btn.addEventListener('click', () => confirmDeleteWater(btn.getAttribute('data-del'))));
}

