function openApprovalEditModal(plantKey, rowId) {
  // หาข้อมูล row จาก cache
  const allRows = _approvalsData[plantKey] || [];
  const row = allRows.find(r => String(r.id) === String(rowId));
  if (!row) { showToast('ไม่พบข้อมูลรายการนี้', 'error'); return; }

  const isProduction = isProductionApprovalKey(plantKey);
  const isLoader = plantKey === 'loader';
  const isWater = plantKey === 'water';
  const cfg = isProduction ? PRODUCTION_PLANT_CONFIG[plantKey] : null;

  // สร้าง input fields ตามประเภท
  let fieldsHtml = '';

  if (isProduction) {
    fieldsHtml = `
      <div class="grid grid-cols-2 gap-3">
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">Hour Meter เริ่ม</label>
          <input id="aedit-sh" type="number" step="any" min="0" value="${row.start_hour ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">Hour Meter หยุด</label>
          <input id="aedit-eh" type="number" step="any" min="0" value="${row.stop_hour ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">วัตถุป้อน (ตัน)</label>
          <input id="aedit-feed" type="number" step="any" min="0" value="${row.feed_ton ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">วัตถุดิบ</label>
          <input id="aedit-rawmat" type="text" value="${escapeHtml(row.raw_material || '')}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        ${cfg.productColumns.map((c, i) => `
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">${escapeHtml(c.label)} (ตัน)</label>
          <input id="aedit-pc-${i}" type="number" step="any" min="0" data-colkey="${c.key}" value="${row[c.key] ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm aedit-pc">
        </div>`).join('')}
        <div class="col-span-2">
          <label class="block text-xs font-medium text-secondary-500 mb-1">Breakdown Detail</label>
          <textarea id="aedit-breakdown" rows="2" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">${escapeHtml(row.breakdown_detail || '')}</textarea>
        </div>
        <div class="col-span-2">
          <label class="block text-xs font-medium text-secondary-500 mb-1">หมายเหตุ</label>
          <input id="aedit-note" type="text" value="${escapeHtml(row.note || '')}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
      </div>`;
  } else if (isLoader) {
    fieldsHtml = `
      <div class="grid grid-cols-2 gap-3">
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">Hour Meter เริ่ม</label>
          <input id="aedit-sh" type="number" step="any" value="${row.start_hour ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">Hour Meter หยุด</label>
          <input id="aedit-eh" type="number" step="any" value="${row.stop_hour ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm" oninput="document.getElementById('aedit-cost').value = ((parseFloat(document.getElementById('aedit-kw').value)||0)*(parseFloat(document.getElementById('aedit-rate').value)||0)).toFixed(2)">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">ปริมาณชาร์จ KW</label>
          <input id="aedit-kw" type="number" step="any" value="${row.charge_kw ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm" oninput="document.getElementById('aedit-cost').value = ((parseFloat(this.value)||0)*(parseFloat(document.getElementById('aedit-rate').value)||0)).toFixed(2)">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">อัตราค่าไฟ (บาท/KW)</label>
          <input id="aedit-rate" type="number" step="any" value="${row.electric_rate ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm" oninput="document.getElementById('aedit-cost').value = ((parseFloat(document.getElementById('aedit-kw').value)||0)*(parseFloat(this.value)||0)).toFixed(2)">
        </div>
        <div class="col-span-2">
          <label class="block text-xs font-medium text-secondary-500 mb-1">ค่าไฟรวม (บาท) — คำนวณอัตโนมัติ</label>
          <input id="aedit-cost" type="number" step="any" readonly value="${row.electric_cost_baht ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm bg-secondary-50">
        </div>
        <div class="col-span-2">
          <label class="block text-xs font-medium text-secondary-500 mb-1">Breakdown Detail</label>
          <textarea id="aedit-breakdown" rows="2" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">${escapeHtml(row.breakdown_detail || '')}</textarea>
        </div>
        <div class="col-span-2">
          <label class="block text-xs font-medium text-secondary-500 mb-1">หมายเหตุ</label>
          <input id="aedit-note" type="text" value="${escapeHtml(row.note || '')}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
      </div>`;
  } else if (isWater) {
    fieldsHtml = `
      <div class="grid grid-cols-2 gap-3">
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">มิเตอร์เริ่ม</label>
          <input id="aedit-ms" type="number" step="any" value="${row.meter_start ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm" oninput="const d=parseFloat(document.getElementById('aedit-me').value||0)-parseFloat(this.value||0);document.getElementById('aedit-usage').value=isNaN(d)?'':Math.max(0,d).toFixed(2)">
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">มิเตอร์หยุด</label>
          <input id="aedit-me" type="number" step="any" value="${row.meter_stop ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm" oninput="const d=parseFloat(this.value||0)-parseFloat(document.getElementById('aedit-ms').value||0);document.getElementById('aedit-usage').value=isNaN(d)?'':Math.max(0,d).toFixed(2)">
        </div>
        <div class="col-span-2">
          <label class="block text-xs font-medium text-secondary-500 mb-1">ปริมาณใช้น้ำ (ลบ.ม.) — คำนวณอัตโนมัติ</label>
          <input id="aedit-usage" type="number" step="any" value="${row.usage_cum ?? ''}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm bg-secondary-50" readonly>
        </div>
        <div class="col-span-2">
          <label class="block text-xs font-medium text-secondary-500 mb-1">หมายเหตุ</label>
          <input id="aedit-note" type="text" value="${escapeHtml(row.note || '')}" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
      </div>`;
  }

  const dateLabelHtml = isProduction ? fmtDate(row.production_date)
    : isLoader ? fmtDate(row.work_date)
    : fmtDate(row.usage_date);

  showModal({
    title: `แก้ไขข้อมูล — ${dateLabelHtml}`,
    wide: true,
    bodyHtml: `
      <div class="space-y-4">
        ${fieldsHtml}
        <div class="flex justify-end gap-2 pt-2 border-t border-secondary-100">
          <button id="aedit-save-approve-btn" class="px-4 py-2 rounded-xl bg-emerald-600 text-white text-sm font-medium hover:bg-emerald-700">บันทึก+อนุมัติ</button>
        </div>
      </div>`,
    confirmText: 'บันทึก',
    cancelText: 'ยกเลิก',
    onConfirm: async () => { await _saveApprovalEdit(plantKey, row, cfg, false); }
  });

  // ผูก Save+Approve button (ใน bodyHtml)
  setTimeout(() => {
    const btn = document.getElementById('aedit-save-approve-btn');
    if (btn) btn.addEventListener('click', async () => {
      closeModal(); // ปิด modal ก่อน save+approve
      await _saveApprovalEdit(plantKey, row, cfg, true);
    });
  }, 100);
}

async function _saveApprovalEdit(plantKey, row, cfg, andApprove) {
  const numOrNull2 = v => { const n = parseFloat(v); return isNaN(n) ? null : n; };
  const strOrNull = v => (v && v.trim()) ? v.trim() : null;

  let payload = {};
  const isProduction = isProductionApprovalKey(plantKey);
  const isLoader = plantKey === 'loader';
  const isWater = plantKey === 'water';

  if (isProduction) {
    payload.start_hour = numOrNull2(document.getElementById('aedit-sh')?.value);
    payload.stop_hour = numOrNull2(document.getElementById('aedit-eh')?.value);
    payload.feed_ton = numOrNull2(document.getElementById('aedit-feed')?.value);
    payload.raw_material = strOrNull(document.getElementById('aedit-rawmat')?.value);
    payload.breakdown_detail = strOrNull(document.getElementById('aedit-breakdown')?.value);
    payload.note = strOrNull(document.getElementById('aedit-note')?.value);
    document.querySelectorAll('.aedit-pc').forEach(inp => {
      const k = inp.getAttribute('data-colkey');
      if (k) payload[k] = numOrNull2(inp.value);
    });
  } else if (isLoader) {
    payload.start_hour = numOrNull2(document.getElementById('aedit-sh')?.value);
    payload.stop_hour = numOrNull2(document.getElementById('aedit-eh')?.value);
    payload.charge_kw = numOrNull2(document.getElementById('aedit-kw')?.value);
    payload.electric_rate = numOrNull2(document.getElementById('aedit-rate')?.value);
    if (payload.charge_kw != null && payload.electric_rate != null)
      payload.electric_cost_baht = Math.round(payload.charge_kw * payload.electric_rate * 100) / 100;
    payload.breakdown_detail = strOrNull(document.getElementById('aedit-breakdown')?.value);
    payload.note = strOrNull(document.getElementById('aedit-note')?.value);
  } else if (isWater) {
    payload.meter_start = numOrNull2(document.getElementById('aedit-ms')?.value);
    payload.meter_stop = numOrNull2(document.getElementById('aedit-me')?.value);
    payload.usage_cum = numOrNull2(document.getElementById('aedit-usage')?.value);
    payload.note = strOrNull(document.getElementById('aedit-note')?.value);
  }

  if (andApprove) payload.status = 'approved';

  const table = APPROVAL_TABLE_MAP[plantKey] || `production_${plantKey}`;
  try {
    const { error } = await db.from(table).update(payload).eq('id', row.id);
    if (error) throw error;
    if (andApprove) {
      await db.from('approval_log').insert([{ source_table: table, source_id: row.id, action: 'approved', approver_id: currentUser.id, note: 'แก้ไขและอนุมัติ' }]);
      showToast('บันทึกและอนุมัติสำเร็จ', 'success');
      _approvalsData[plantKey] = (_approvalsData[plantKey] || []).filter(r => r.id !== row.id);
      fetchPendingApprovalCount();
      loadApprovalHistory();
    } else {
      // อัปเดต cache ด้วยค่าใหม่
      const idx = (_approvalsData[plantKey] || []).findIndex(r => r.id === row.id);
      if (idx >= 0) Object.assign(_approvalsData[plantKey][idx], payload);
      showToast('บันทึกข้อมูลสำเร็จ', 'success');
    }
    renderApprovalSections(getApprovalPlantKeysForUser());
  } catch (err) {
    console.error(err);
    showToast('บันทึกไม่สำเร็จ: ' + (err.message || ''), 'error');
  }
}

async function approveProductionRow(plantKey, id) {
  const table = APPROVAL_TABLE_MAP[plantKey] || `production_${plantKey}`;
  try {
    const { error } = await db.from(table).update({ status: 'approved' }).eq('id', id);
    if (error) throw error;
    await db.from('approval_log').insert([{ source_table: table, source_id: id, action: 'approved', approver_id: currentUser.id }]);
    showToast('อนุมัติรายการสำเร็จ', 'success');
    _approvalsData[plantKey] = (_approvalsData[plantKey] || []).filter(r => r.id !== id);
    renderApprovalSections(getApprovalPlantKeysForUser());
    fetchPendingApprovalCount();
    loadApprovalHistory();
  } catch (err) {
    console.error(err);
    showToast('อนุมัติไม่สำเร็จ: ' + (err.message || ''), 'error');
  }
}

function rejectProductionRowPrompt(plantKey, id) {
  showModal({
    title: 'ปฏิเสธรายการ',
    bodyHtml: `
      <div class="space-y-2">
        <label class="block text-xs font-medium text-secondary-500 mb-1">เหตุผลการปฏิเสธ</label>
        <textarea id="reject-reason" rows="3" class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm" placeholder="ระบุเหตุผล..."></textarea>
      </div>`,
    confirmText: 'ปฏิเสธรายการ', cancelText: 'ยกเลิก',
    onConfirm: async () => {
      const reason = document.getElementById('reject-reason') ? document.getElementById('reject-reason').value.trim() : '';
      await rejectProductionRow(plantKey, id, reason);
    }
  });
}

async function rejectProductionRow(plantKey, id, reason) {
  const table = APPROVAL_TABLE_MAP[plantKey] || `production_${plantKey}`;
  try {
    const { error } = await db.from(table).update({ status: 'rejected' }).eq('id', id);
    if (error) throw error;
    await db.from('approval_log').insert([{ source_table: table, source_id: id, action: 'rejected', approver_id: currentUser.id, note: reason || null }]);
    showToast('ปฏิเสธรายการสำเร็จ', 'success');
    _approvalsData[plantKey] = (_approvalsData[plantKey] || []).filter(r => r.id !== id);
    renderApprovalSections(getApprovalPlantKeysForUser());
    fetchPendingApprovalCount();
    loadApprovalHistory();
  } catch (err) {
    console.error(err);
    showToast('ปฏิเสธไม่สำเร็จ: ' + (err.message || ''), 'error');
  }
}

async function loadApprovalHistory() {
  const el = document.getElementById('approvals-history-block');
  if (el) el.innerHTML = skeletonBlock('h-40');
  try {
    const { data, error } = await db.from('approval_log').select('*, app_users(full_name, username)').order('created_at', { ascending: false }).limit(50);
    if (error) throw error;
    _approvalLogHistory = data || [];
    const approverSel = document.getElementById('approvals-approver-filter');
    if (approverSel) {
      const approvers = Array.from(new Map(_approvalLogHistory.filter(r => r.app_users).map(r => [r.approver_id, r.app_users.full_name || r.app_users.username])).entries());
      approverSel.innerHTML = `<option value="all">ทุกผู้อนุมัติ (ประวัติ)</option>` + approvers.map(([id, name]) => `<option value="${id}">${escapeHtml(name)}</option>`).join('');
    }
    renderApprovalHistoryList();
  } catch (err) {
    console.error(err);
    if (el) el.innerHTML = errorBlock();
    refreshIcons();
  }
}

function renderApprovalHistoryList() {
  const el = document.getElementById('approvals-history-block');
  if (!el) return;
  const approverSel = document.getElementById('approvals-approver-filter');
  const approverFilter = approverSel ? approverSel.value : 'all';
  let rows = _approvalLogHistory;
  if (approverFilter !== 'all') rows = rows.filter(r => r.approver_id === approverFilter);

  el.innerHTML = `
    <div class="bg-white rounded-2xl shadow-sm p-5 overflow-x-auto">
      ${rows.length ? `
      <table class="w-full text-sm">
        <thead><tr class="text-left text-secondary-400 border-b border-secondary-100">
          <th class="py-2 pr-3">เวลา</th><th class="py-2 pr-3">ตาราง</th><th class="py-2 pr-3">การกระทำ</th><th class="py-2 pr-3">ผู้อนุมัติ</th><th class="py-2 pr-3">หมายเหตุ</th>
        </tr></thead>
        <tbody>
          ${rows.slice(0,30).map(r => `
            <tr class="border-b border-secondary-50 hover:bg-secondary-50">
              <td class="py-2 pr-3">${fmtDate(r.created_at)}</td>
              <td class="py-2 pr-3">${escapeHtml(r.source_table || '-')}</td>
              <td class="py-2 pr-3"><span class="px-2 py-0.5 rounded-full text-xs ${r.action==='approved'?'bg-emerald-50 text-emerald-600':'bg-red-50 text-red-600'}">${escapeHtml(r.action)}</span></td>
              <td class="py-2 pr-3">${escapeHtml(r.app_users ? (r.app_users.full_name || r.app_users.username) : '-')}</td>
              <td class="py-2 pr-3 text-secondary-500">${escapeHtml(r.note || '-')}</td>
            </tr>`).join('')}
        </tbody>
      </table>` : `<p class="text-center text-secondary-400 text-sm py-6">ไม่มีประวัติการอนุมัติ</p>`}
    </div>`;
  refreshIcons();
}
// =====================================================================
// SECTION 28: MANAGE — ตั้งค่าระบบ (admin only)
// =====================================================================
function renderManageSettings(container) {
  const isAdmin = currentUser && currentUser.role === 'admin';
  container.innerHTML = `
    <div class="space-y-6 fade-in max-w-3xl">
      <h2 class="text-lg font-semibold text-secondary-800 flex items-center gap-2"><i data-lucide="settings" class="w-5 h-5 text-primary-600"></i>ตั้งค่าระบบ</h2>

      ${isAdmin ? `
      <div class="bg-white rounded-2xl shadow-sm p-5">
        <div class="flex items-center justify-between mb-1">
          <h3 class="text-sm font-semibold text-secondary-700 flex items-center gap-2"><i data-lucide="users-round" class="w-4 h-4 text-primary-600"></i>จัดการ Roles & Permissions</h3>
          <button id="btn-add-role" class="flex items-center gap-1.5 bg-primary-600 hover:bg-primary-700 text-white text-xs font-medium px-3 py-1.5 rounded-xl transition"><i data-lucide="plus" class="w-3.5 h-3.5"></i>เพิ่ม Role</button>
        </div>
        <p class="text-xs text-secondary-400 mb-4">กำหนดสิทธิ์ menu ที่แต่ละ Role เข้าถึงได้ — ผู้ใช้จะได้รับสิทธิ์จาก Role อัตโนมัติ</p>
        <div id="roles-list-block" style="max-height:385px;overflow-y:auto;">${skeletonBlock('h-32')}</div>
      </div>

      <div class="bg-white rounded-2xl shadow-sm p-5">
        <h3 class="text-sm font-semibold text-secondary-700 mb-1 flex items-center gap-2"><i data-lucide="shield-check" class="w-4 h-4 text-primary-600"></i>กำหนดสิทธิ์เพิ่มเติมรายบุคคล</h3>
        <p class="text-xs text-secondary-400 mb-4">เพิ่มสิทธิ์เฉพาะบุคคลนอกเหนือจาก Role — ใช้สำหรับ user ที่ต้องดูหลายโรงงาน</p>
        <div class="flex flex-col sm:flex-row sm:items-center gap-2 sm:gap-3 mb-4">
          <label class="text-xs font-medium text-secondary-500">เลือกผู้ใช้</label>
          <select id="perm-user-select" class="border border-secondary-200 rounded-xl px-3 py-2 text-sm w-full sm:flex-1">
            <option value="">— เลือก user —</option>
          </select>
        </div>
        <div id="perm-matrix-block"></div>
      </div>` : ''}

      <div class="bg-white rounded-2xl shadow-sm p-5">
        <h3 class="text-sm font-semibold text-secondary-700 mb-3 flex items-center gap-2"><i data-lucide="key-round" class="w-4 h-4 text-primary-600"></i>เปลี่ยนรหัสผ่านของฉัน</h3>
        <form id="settings-password-form" class="space-y-3">
          <div>
            <label class="block text-xs font-medium text-secondary-500 mb-1">รหัสผ่านปัจจุบัน</label>
            <input id="sp-current" type="password" required class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
          </div>
          <div>
            <label class="block text-xs font-medium text-secondary-500 mb-1">รหัสผ่านใหม่</label>
            <input id="sp-new" type="password" required class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
          </div>
          <div>
            <label class="block text-xs font-medium text-secondary-500 mb-1">ยืนยันรหัสผ่านใหม่</label>
            <input id="sp-confirm" type="password" required class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
          </div>
          <button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">เปลี่ยนรหัสผ่าน</button>
        </form>
      </div>

      <div class="bg-white rounded-2xl shadow-sm p-5">
        <h3 class="text-sm font-semibold text-secondary-700 mb-3 flex items-center gap-2"><i data-lucide="database" class="w-4 h-4 text-primary-600"></i>สถานะการเชื่อมต่อ Supabase</h3>
        <div id="settings-connection-status" class="flex items-center gap-3">${skeletonBlock('h-12')}</div>
        <button id="settings-test-connection-btn" class="mt-3 flex items-center gap-1.5 bg-white border border-secondary-200 hover:bg-secondary-50 text-secondary-600 text-sm font-medium px-3 py-2 rounded-xl transition"><i data-lucide="zap" class="w-4 h-4"></i>ทดสอบการเชื่อมต่อ</button>
      </div>
    </div>`;
  refreshIcons();

  document.getElementById('settings-password-form').addEventListener('submit', async (e) => {
    e.preventDefault();
    const current = document.getElementById('sp-current').value;
    const newPwd = document.getElementById('sp-new').value;
    const confirmPwd = document.getElementById('sp-confirm').value;
    if (current !== currentUser.password) {
      showToast('รหัสผ่านปัจจุบันไม่ถูกต้อง', 'error');
      return;
    }
    if (newPwd !== confirmPwd) {
      showToast('รหัสผ่านใหม่และยืนยันไม่ตรงกัน', 'error');
      return;
    }
    if (!newPwd) {
      showToast('กรุณากรอกรหัสผ่านใหม่', 'error');
      return;
    }
    try {
      const { error } = await db.from('app_users').update({ password: newPwd }).eq('id', currentUser.id);
      if (error) throw error;
      currentUser.password = newPwd;
      showToast('เปลี่ยนรหัสผ่านสำเร็จ', 'success');
      document.getElementById('settings-password-form').reset();
    } catch (err) {
      console.error(err);
      showToast('เปลี่ยนรหัสผ่านไม่สำเร็จ: ' + (err.message || ''), 'error');
    }
  });

  document.getElementById('settings-test-connection-btn').addEventListener('click', testSupabaseConnection);
  testSupabaseConnection();

  // โหลด roles list + permission matrix (admin only)
  if (isAdmin) {
    loadRolesList();
    document.getElementById('btn-add-role').addEventListener('click', () => openRoleForm(null));
    loadPermissionUserList();
    document.getElementById('perm-user-select').addEventListener('change', (e) => {
      const uid = e.target.value;
      if (uid) loadPermissionMatrix(uid);
      else document.getElementById('perm-matrix-block').innerHTML = '';
    });
  }
}

// =====================================================================
// SECTION 28B: ROLES MANAGEMENT (admin)
// =====================================================================
let _rolesCache = [];

async function loadRolesList() {
  const block = document.getElementById('roles-list-block');
  if (!block) return;
  try {
    const { data, error } = await db.from('roles').select('*').order('sort_order');
    if (error) throw error;
    _rolesCache = data || [];
    renderRolesList(block, _rolesCache);
  } catch (err) {
    block.innerHTML = `<p class="text-sm text-red-500">โหลด roles ไม่สำเร็จ: ${err.message}</p>`;
  }
}

function renderRolesList(block, roles) {
  if (!roles.length) {
    block.innerHTML = '<p class="text-sm text-secondary-400 text-center py-4">ยังไม่มี Role</p>';
    return;
  }
  block.innerHTML = `
    <div class="divide-y divide-secondary-100">
      ${roles.map(r => `
        <div class="flex items-center justify-between py-3 gap-3">
          <div class="flex items-center gap-3 min-w-0">
            <div class="flex-shrink-0 w-8 h-8 rounded-full bg-primary-50 flex items-center justify-center">
              <i data-lucide="shield" class="w-4 h-4 text-primary-600"></i>
            </div>
            <div class="min-w-0">
              <p class="text-sm font-medium text-secondary-800">${escapeHtml(r.label)}</p>
              <p class="text-xs text-secondary-400 font-mono">${escapeHtml(r.name)}</p>
            </div>
            ${r.is_system ? `<span class="px-2 py-0.5 rounded-full text-xs bg-secondary-100 text-secondary-500">System</span>` : ''}
          </div>
          <div class="flex items-center gap-2 flex-shrink-0">
            <button onclick="openRolePermissionsMatrix('${r.name}','${escapeHtml(r.label)}')"
              class="flex items-center gap-1 text-xs text-primary-600 hover:text-primary-700 border border-primary-200 hover:border-primary-400 px-2.5 py-1.5 rounded-xl transition">
              <i data-lucide="key-round" class="w-3.5 h-3.5"></i>สิทธิ์
            </button>
            ${!r.is_system ? `
            <button onclick="openRoleForm('${r.id}')"
              class="flex items-center gap-1 text-xs text-secondary-600 hover:text-secondary-800 border border-secondary-200 hover:border-secondary-400 px-2.5 py-1.5 rounded-xl transition">
              <i data-lucide="edit-3" class="w-3.5 h-3.5"></i>แก้ไข
            </button>
            <button onclick="confirmDeleteRole('${r.id}','${escapeHtml(r.name)}')"
              class="flex items-center gap-1 text-xs text-red-500 hover:text-red-700 border border-red-200 hover:border-red-400 px-2.5 py-1.5 rounded-xl transition">
              <i data-lucide="trash-2" class="w-3.5 h-3.5"></i>ลบ
            </button>` : ''}
          </div>
        </div>
      `).join('')}
    </div>`;
  refreshIcons();
}

function openRoleForm(id) {
  const editing = id ? _rolesCache.find(r => r.id === id) : null;
  showModal({
    title: editing ? 'แก้ไข Role' : 'เพิ่ม Role ใหม่',
    hideConfirm: true, hideCancel: true,
    bodyHtml: `
      <form id="role-form" class="space-y-4 mt-1">
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">ชื่อ Role (ภาษาอังกฤษ, ไม่มีเว้นวรรค)</label>
          <input id="rf-name" type="text" value="${editing ? escapeHtml(editing.name) : ''}"
            placeholder="เช่น office, technician, hr"
            class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm font-mono"
            ${editing && editing.is_system ? 'readonly' : ''}>
          <p class="text-xs text-secondary-400 mt-1">ใช้ตัวพิมพ์เล็ก ไม่มีช่องว่าง เช่น office, hr_admin</p>
        </div>
        <div>
          <label class="block text-xs font-medium text-secondary-500 mb-1">ชื่อแสดง (ภาษาไทย)</label>
          <input id="rf-label" type="text" value="${editing ? escapeHtml(editing.label) : ''}"
            placeholder="เช่น พนักงานธุรการ"
            class="w-full border border-secondary-200 rounded-xl px-3 py-2 text-sm">
        </div>
        <button type="submit" class="w-full bg-primary-600 hover:bg-primary-700 text-white font-medium rounded-xl py-2.5 transition">
          ${editing ? 'บันทึกการแก้ไข' : 'เพิ่ม Role'}
        </button>
      </form>`,
  });
  document.getElementById('role-form').addEventListener('submit', async (e) => {
    e.preventDefault();
    const name  = document.getElementById('rf-name').value.trim().toLowerCase().replace(/\s+/g,'_');
    const label = document.getElementById('rf-label').value.trim();
    if (!name || !label) { showToast('กรุณากรอกข้อมูลให้ครบ', 'error'); return; }
    if (!/^[a-z][a-z0-9_]*$/.test(name)) { showToast('ชื่อ Role ใช้ได้เฉพาะ a-z, 0-9, _ และต้องเริ่มด้วยตัวอักษร', 'error'); return; }
    try {
      if (editing) {
        const { error } = await db.from('roles').update({ label }).eq('id', editing.id);
        if (error) throw error;
        showToast('แก้ไข Role สำเร็จ', 'success');
      } else {
        const { error } = await db.from('roles').insert([{ name, label, sort_order: 99 }]);
        if (error) throw error;
        showToast('เพิ่ม Role สำเร็จ', 'success');
      }
      closeModal();
      loadRolesList();
    } catch (err) {
      showToast('เกิดข้อผิดพลาด: ' + (err.message || ''), 'error');
    }
  });
}

async function confirmDeleteRole(id, name) {
  if (!confirm(`ลบ Role "${name}" ?\nผู้ใช้ที่มี Role นี้จะถูก block login`)) return;
  try {
    const { error } = await db.from('roles').delete().eq('id', id);
    if (error) throw error;
    showToast('ลบ Role สำเร็จ', 'success');
    loadRolesList();
  } catch (err) {
    showToast('ลบไม่สำเร็จ: ' + (err.message || ''), 'error');
  }
}

async function openRolePermissionsMatrix(roleName, roleLabel) {
  showModal({
    title: `สิทธิ์ของ Role: ${roleLabel}`,
    wide: true, hideConfirm: true, hideCancel: true,
    bodyHtml: `<div id="role-perm-block">${skeletonBlock('h-48')}</div>`,
  });
  try {
    const { data: perm } = await db.from('role_permissions').select('extra_dashboards, extra_manage').eq('role_name', roleName).maybeSingle();
    const extraDash   = (perm && perm.extra_dashboards) || [];
    const extraManage = (perm && perm.extra_manage)     || [];
    renderPermissionMatrix(
      document.getElementById('role-perm-block'),
      null, extraDash, extraManage, roleName,
      async (dashArr, manageArr) => {
        const { error } = await db.from('role_permissions').upsert(
          { role_name: roleName, extra_dashboards: dashArr, extra_manage: manageArr, updated_at: new Date().toISOString() },
          { onConflict: 'role_name' }
        );
        if (error) throw error;
      }
    );
  } catch (err) {
    document.getElementById('role-perm-block').innerHTML = `<p class="text-sm text-red-500">โหลดไม่สำเร็จ: ${err.message}</p>`;
  }
}

// =====================================================================
// SECTION 29: PERMISSION MATRIX (admin only, ใน manage-settings)
// =====================================================================
async function loadPermissionUserList() {
  const sel = document.getElementById('perm-user-select');
  if (!sel) return;
  try {
    const { data, error } = await db.from('app_users').select('id, full_name, username, role, department').eq('status','active').order('full_name');
    if (error) throw error;
    // แสดง operator ก่อน แล้วตามด้วย role อื่น
    const operators = (data || []).filter(u => u.role === 'operator');
    const others = (data || []).filter(u => u.role !== 'operator');
    const makeOpt = u => `<option value="${u.id}">${escapeHtml(u.full_name || u.username)} (${escapeHtml(u.role)}${u.department ? ' / '+escapeHtml(u.department) : ''})</option>`;
    sel.innerHTML = '<option value="">— เลือก user —</option>' +
      (operators.length ? '<optgroup label="── Operator ──">' + operators.map(makeOpt).join('') + '</optgroup>' : '') +
      (others.length ? '<optgroup label="── Role อื่น ──">' + others.map(makeOpt).join('') + '</optgroup>' : '');
  } catch (err) {
    console.error('loadPermissionUserList', err);
  }
}

async function loadPermissionMatrix(userId) {
  const block = document.getElementById('perm-matrix-block');
  if (!block) return;
  block.innerHTML = `<div class="text-xs text-secondary-400 py-4">กำลังโหลด...</div>`;
  try {
    // โหลด user role เพื่อแสดง UI ที่ถูกต้อง
    const { data: userData } = await db.from('app_users').select('role').eq('id', userId).maybeSingle();
    const userRole = userData ? userData.role : '';
    const { data: perm } = await db.from('user_permissions').select('extra_dashboards, extra_manage').eq('user_id', userId).maybeSingle();
    const extraDash = (perm && perm.extra_dashboards) || [];
    const extraManage = (perm && perm.extra_manage) || [];
    renderPermissionMatrix(block, userId, extraDash, extraManage, userRole);
  } catch (err) {
    block.innerHTML = `<div class="text-xs text-red-500">โหลดไม่สำเร็จ: ${escapeHtml(err.message || '')}</div>`;
  }
}

// saveCallback(dashArr, manageArr) — optional, ถ้าไม่ส่งจะ save ไปที่ user_permissions ของ userId
function renderPermissionMatrix(block, userId, extraDash, extraManage, userRole, saveCallback) {
  const isRoleMode = !userId && typeof saveCallback === 'function';
  const isAdminControlled = !isRoleMode && ['manager','supervisor','operator','clerk'].includes(userRole);
  const noteHtml = isRoleMode
    ? `<div class="mb-3 px-3 py-2 bg-primary-50 border border-primary-200 rounded-xl text-xs text-primary-700 flex items-center gap-2">
        <i data-lucide="users-round" class="w-4 h-4 flex-shrink-0"></i>
        สิทธิ์ระดับ Role — ผู้ใช้ทุกคนที่มี Role นี้จะได้รับสิทธิ์เหล่านี้อัตโนมัติ
       </div>`
    : isAdminControlled
    ? `<div class="mb-3 px-3 py-2 bg-amber-50 border border-amber-200 rounded-xl text-xs text-amber-700 flex items-center gap-2">
        <i data-lucide="shield" class="w-4 h-4 flex-shrink-0"></i>
        ไม่มีสิทธิ์เริ่มต้น — Admin กำหนดทั้งหมด (ยืดหยุ่นข้ามโรงงานได้)
       </div>`
    : `<div class="mb-3 px-3 py-2 bg-blue-50 border border-blue-200 rounded-xl text-xs text-blue-600 flex items-center gap-2">
        <i data-lucide="info" class="w-4 h-4 flex-shrink-0"></i>
        สิทธิ์เพิ่มเติมจากสิทธิ์ตาม Role ปกติ (Managing MD: ดูทุก Dashboard อยู่แล้ว)
       </div>`;

  const templateOpts = PERM_TEMPLATES.map(t =>
    `<option value="${t.id}">${escapeHtml(t.label)}</option>`).join('');

  const dashRows = DASHBOARD_MENUS.map(m => `
    <label class="flex items-center gap-2 py-1.5 cursor-pointer hover:bg-secondary-50 rounded-lg px-2">
      <input type="checkbox" class="perm-dash-cb rounded" value="${m.key}" ${extraDash.includes(m.key) ? 'checked' : ''}>
      <i data-lucide="${m.icon}" class="w-4 h-4 text-secondary-400 flex-shrink-0"></i>
      <span class="text-sm text-secondary-700">${escapeHtml(m.label)}</span>
    </label>`).join('');

  const manageRows = MANAGE_MENUS.filter(m => !m.approvalOnly).map(m => `
    <label class="flex items-center gap-2 py-1.5 cursor-pointer hover:bg-secondary-50 rounded-lg px-2">
      <input type="checkbox" class="perm-manage-cb rounded" value="${m.key}" ${extraManage.includes(m.key) ? 'checked' : ''}>
      <i data-lucide="${m.icon}" class="w-4 h-4 text-secondary-400 flex-shrink-0"></i>
      <span class="text-sm text-secondary-700">${escapeHtml(m.label)}</span>
    </label>`).join('');

  const approveRows = MANAGE_MENUS.filter(m => m.approvalOnly).map(m => `
    <label class="flex items-center gap-2 py-1.5 cursor-pointer hover:bg-secondary-50 rounded-lg px-2">
      <input type="checkbox" class="perm-manage-cb rounded" value="${m.key}" ${extraManage.includes(m.key) ? 'checked' : ''}>
      <i data-lucide="${m.icon}" class="w-4 h-4 text-emerald-400 flex-shrink-0"></i>
      <span class="text-sm text-secondary-700">${escapeHtml(m.label)}</span>
    </label>`).join('');

  block.innerHTML = `
    ${noteHtml}
    <div class="mb-3 flex items-center gap-2 flex-wrap">
      <span class="text-xs font-medium text-secondary-500">Template:</span>
      <select id="perm-template-sel" class="border border-secondary-200 rounded-xl px-3 py-1.5 text-xs">
        <option value="">— เลือก Template —</option>
        ${templateOpts}
      </select>
      <button id="perm-apply-tmpl-btn" class="px-3 py-1.5 rounded-xl bg-secondary-100 hover:bg-secondary-200 text-secondary-700 text-xs font-medium transition">ใช้ Template</button>
      <span class="text-xs text-secondary-400">(เลือกแล้วกด "ใช้ Template" แล้วปรับเพิ่ม/ลดได้)</span>
    </div>
    <div class="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-4">
      <div>
        <p class="text-xs font-semibold text-secondary-500 uppercase tracking-wide mb-2">Dashboard</p>
        <div class="space-y-0.5">${dashRows}</div>
      </div>
      <div>
        <p class="text-xs font-semibold text-secondary-500 uppercase tracking-wide mb-2">จัดการข้อมูล</p>
        <div class="space-y-0.5">${manageRows}</div>
      </div>
    </div>
    <div class="mb-4 border border-emerald-100 rounded-xl p-3 bg-emerald-50/40">
      <p class="text-xs font-semibold text-emerald-600 uppercase tracking-wide mb-1 flex items-center gap-1.5">
        <i data-lucide="check-circle" class="w-3.5 h-3.5"></i>สิทธิ์อนุมัติ (ต้องมี "รออนุมัติ" ด้วย)
      </p>
      <p class="text-[11px] text-emerald-500 mb-2">เลือกโรงงาน/ไลน์ที่ผู้ใช้นี้สามารถอนุมัติข้อมูลได้</p>
      <div class="grid grid-cols-2 sm:grid-cols-3 gap-0.5">${approveRows}</div>
    </div>
    <div class="flex flex-wrap items-center gap-2 sm:gap-3 pt-2 border-t border-secondary-100">
      <button id="perm-save-btn" data-uid="${userId}" class="px-5 py-2 rounded-xl bg-primary-600 hover:bg-primary-700 text-white text-sm font-medium transition flex items-center gap-1.5">
        <i data-lucide="save" class="w-4 h-4"></i>บันทึกสิทธิ์
      </button>
      <button id="perm-clear-btn" data-uid="${userId}" class="px-4 py-2 rounded-xl border border-red-200 hover:bg-red-50 text-red-600 text-xs font-medium transition">
        ยกเลิกสิทธิ์ทั้งหมด
      </button>
      <span id="perm-save-status" class="text-xs text-secondary-400"></span>
    </div>`;
  refreshIcons();

  const doSave = async (clearAll) => {
    const statusEl = block.querySelector('#perm-save-status');
    const dashArr   = clearAll ? [] : Array.from(block.querySelectorAll('.perm-dash-cb:checked')).map(cb => cb.value);
    const manageArr = clearAll ? [] : Array.from(block.querySelectorAll('.perm-manage-cb:checked')).map(cb => cb.value);
    if (clearAll) block.querySelectorAll('input[type=checkbox]').forEach(cb => { cb.checked = false; });
    if (statusEl) statusEl.textContent = 'กำลังบันทึก...';
    try {
      if (saveCallback) {
        await saveCallback(dashArr, manageArr);
      } else {
        await saveUserPermissions(userId, clearAll, dashArr, manageArr);
      }
      if (statusEl) statusEl.textContent = '✓ บันทึกแล้ว';
      showToast('บันทึกสิทธิ์สำเร็จ', 'success');
      setTimeout(() => { if (statusEl) statusEl.textContent = ''; }, 3000);
    } catch (err) {
      console.error('savePermissions', err);
      if (statusEl) statusEl.textContent = 'เกิดข้อผิดพลาด';
      showToast('บันทึกสิทธิ์ไม่สำเร็จ: ' + (err.message || ''), 'error');
    }
  };
  block.querySelector('#perm-save-btn').addEventListener('click', () => doSave(false));
  block.querySelector('#perm-clear-btn').addEventListener('click', () => doSave(true));
  block.querySelector('#perm-apply-tmpl-btn').addEventListener('click', () => {
    const sel = block.querySelector('#perm-template-sel');
    const tmpl = PERM_TEMPLATES.find(t => t.id === sel.value);
    if (!tmpl) { showToast('กรุณาเลือก Template ก่อน', 'warning'); return; }
    block.querySelectorAll('.perm-dash-cb').forEach(cb => { cb.checked = tmpl.dash.includes(cb.value); });
    block.querySelectorAll('.perm-manage-cb').forEach(cb => { cb.checked = tmpl.manage.includes(cb.value); });
    showToast(`ใช้ Template "${tmpl.label}" แล้ว — กด "บันทึกสิทธิ์" เพื่อยืนยัน`, 'info');
  });
}

async function saveUserPermissions(userId, clearAll, extraDash, extraManage) {
  const { error } = await db.from('user_permissions').upsert(
    { user_id: userId, extra_dashboards: extraDash || [], extra_manage: extraManage || [], updated_at: new Date().toISOString() },
    { onConflict: 'user_id' }
  );
  if (error) throw error;
}

async function testSupabaseConnection() {
  const el = document.getElementById('settings-connection-status');
  if (!el) return;
  el.innerHTML = skeletonBlock('h-12');
  const start = performance.now();
  try {
    const { error } = await db.from('factories').select('id', { count: 'exact', head: true });
    if (error) throw error;
    const latency = Math.round(performance.now() - start);
    el.innerHTML = `
      <span class="flex items-center gap-2 px-3 py-2 rounded-xl bg-emerald-50 text-emerald-600 text-sm font-medium">
        <i data-lucide="check-circle-2" class="w-4 h-4"></i>เชื่อมต่อสำเร็จ
      </span>
      <span class="text-xs text-secondary-400">latency ${latency} ms</span>`;
  } catch (err) {
    console.error(err);
    el.innerHTML = `
      <span class="flex items-center gap-2 px-3 py-2 rounded-xl bg-red-50 text-red-600 text-sm font-medium">
        <i data-lucide="x-circle" class="w-4 h-4"></i>เชื่อมต่อล้มเหลว
      </span>
      <span class="text-xs text-secondary-400">${escapeHtml(err.message || '')}</span>`;
  }
  refreshIcons();
}
