async function loadReportFactoriesCache() {
  if (_reportState.factoriesCache) return;
  try {
    const { data, error } = await db.from('factories').select('id, name').eq('status','active');
    if (error) throw error;
    _reportState.factoriesCache = data || [];
  } catch (err) {
    console.error(err);
    _reportState.factoriesCache = [];
  }
}

function renderReportFilters() {
  const el = document.getElementById('report-extra-filters');
  if (!el) return;
  const factOptions = `<option value="all">ทุกโรงงาน</option>` + (_reportState.factoriesCache||[]).map(f => `<option value="${f.id}" ${f.id===_reportState.factoryId?'selected':''}>${escapeHtml(f.name)}</option>`).join('');

  let html = `
    <input id="report-from" type="date" value="${_reportState.from}" class="border border-secondary-200 rounded-xl px-3 py-2 text-sm" title="วันที่เริ่มต้น">
    <input id="report-to" type="date" value="${_reportState.to}" class="border border-secondary-200 rounded-xl px-3 py-2 text-sm" title="วันที่สิ้นสุด">`;

  if (_reportState.type === 'production') {
    html += `
      <div class="flex items-center gap-1 text-xs text-secondary-500">เลือกหน่วยผลิต:
        ${['cde','propel','sanon1','sanon2'].map(p => `
          <label class="flex items-center gap-1 px-2 py-1 border border-secondary-200 rounded-lg cursor-pointer">
            <input type="checkbox" class="report-plant-cb" value="${p}" ${_reportState.prodPlants.includes(p)?'checked':''}> ${APPROVAL_PLANT_LABELS[p]}
          </label>`).join('')}
      </div>`;
  } else if (['drone','sales','loader','loader_daily'].includes(_reportState.type)) {
    html += `<select id="report-factory" class="border border-secondary-200 rounded-xl px-3 py-2 text-sm">${factOptions}</select>`;
  }

  el.innerHTML = html;
  refreshIcons();
  const fromInput = document.getElementById('report-from');
  const toInput = document.getElementById('report-to');
  if (fromInput) fromInput.addEventListener('change', (e) => { _reportState.from = e.target.value; loadReportData(); });
  if (toInput) toInput.addEventListener('change', (e) => { _reportState.to = e.target.value; loadReportData(); });
  const factSel = document.getElementById('report-factory');
  if (factSel) factSel.addEventListener('change', (e) => { _reportState.factoryId = e.target.value; loadReportData(); });
  qsa('.report-plant-cb', el).forEach(cb => cb.addEventListener('change', () => {
    _reportState.prodPlants = qsa('.report-plant-cb', el).filter(c => c.checked).map(c => c.value);
    loadReportData();
  }));
}

async function loadReportData() {
  const tableBlock = document.getElementById('report-table-block');
  if (tableBlock) tableBlock.innerHTML = skeletonBlock('h-72');
  try {
    let rows = [];
    if (_reportState.type === 'production') {
      const plants = _reportState.prodPlants.length ? _reportState.prodPlants : ['cde','propel','sanon1','sanon2'];
      const results = await Promise.all(plants.map(p => {
        let q = db.from(`production_${p}`).select('*');
        if (_reportState.from) q = q.gte('production_date', _reportState.from);
        if (_reportState.to) q = q.lte('production_date', _reportState.to);
        return q;
      }));
      plants.forEach((p, i) => {
        if (results[i].error) throw results[i].error;
        (results[i].data || []).forEach(r => rows.push(Object.assign({ _plant: APPROVAL_PLANT_LABELS[p] }, r)));
      });
    } else if (_reportState.type === 'drone') {
      let q = db.from('drone_stock').select('*, factories(name)');
      if (_reportState.factoryId !== 'all') q = q.eq('factory_id', _reportState.factoryId);
      const { data, error } = await q;
      if (error) throw error;
      rows = (data || []).map(r => Object.assign({ _factory: r.factories ? r.factories.name : '' }, r));
    } else if (_reportState.type === 'sales') {
      let q = db.from('sales').select('*, factories(name)');
      if (_reportState.from) q = q.gte('sale_date', _reportState.from);
      if (_reportState.to) q = q.lte('sale_date', _reportState.to);
      if (_reportState.factoryId !== 'all') q = q.eq('factory_id', _reportState.factoryId);
      const { data, error } = await q;
      if (error) throw error;
      rows = (data || []).map(r => Object.assign({ _factory: r.factories ? r.factories.name : '' }, r));
    } else if (_reportState.type === 'loader' || _reportState.type === 'loader_daily') {
      let q = db.from('electric_loader').select('*, factories(name)');
      if (_reportState.from) q = q.gte('work_date', _reportState.from);
      if (_reportState.to) q = q.lte('work_date', _reportState.to);
      if (_reportState.factoryId !== 'all') q = q.eq('factory_id', _reportState.factoryId);
      const { data, error } = await q;
      if (error) throw error;
      rows = (data || []).map(r => Object.assign({ _factory: r.factories ? r.factories.name : '' }, r));
    } else if (_reportState.type === 'water') {
      let q = db.from('groundwater_usage').select('*');
      if (_reportState.from) q = q.gte('usage_date', _reportState.from);
      if (_reportState.to) q = q.lte('usage_date', _reportState.to);
      const { data, error } = await q;
      if (error) throw error;
      rows = data || [];
    }
    _reportState.rows = rows;
    renderReportTable();
  } catch (err) {
    console.error(err);
    if (tableBlock) tableBlock.innerHTML = errorBlock();
    refreshIcons();
  }
}

function applyReportSort(rows) {
  const { col, dir } = _reportState.sortState;
  if (!col) return rows;
  const sorted = rows.slice().sort((a, b) => {
    let va = a[col], vb = b[col];
    if (va === null || va === undefined) va = '';
    if (vb === null || vb === undefined) vb = '';
    if (typeof va === 'number' && typeof vb === 'number') return va - vb;
    const na = Number(va), nb = Number(vb);
    if (!isNaN(na) && !isNaN(nb) && va !== '' && vb !== '') return na - nb;
    return String(va).localeCompare(String(vb), 'th');
  });
  if (dir === 'desc') sorted.reverse();
  return sorted;
}

function _getMH_r(r) {
  if (r.machine_hour_start != null && r.machine_hour_stop != null)
    return Math.max(0, r.machine_hour_stop - r.machine_hour_start);
  if (r.machine_hour_total != null) return Number(r.machine_hour_total) || 0;
  return Number(r.total_work_hour) || 0;
}

function renderLoaderDailyReport() {
  const tableBlock = document.getElementById('report-table-block');
  if (!tableBlock) return;
  const allRows = _reportState.rows;
  if (!allRows.length) {
    tableBlock.innerHTML = `<div class="bg-white rounded-2xl shadow-sm p-5"><p class="text-center text-secondary-400 py-8">ไม่พบข้อมูล</p></div>`;
    return;
  }

  // หา loaders ทั้งหมด (เรียง)
  const loaderNames = [...new Set(allRows.map(r => r.loader_name).filter(Boolean))].sort();

  // กลุ่มข้อมูล: loaderName → { date → {mh, kw, cost} }
  const grouped = {};
  loaderNames.forEach(ln => { grouped[ln] = {}; });
  allRows.forEach(r => {
    const ln = r.loader_name;
    if (!ln) return;
    const dt = r.work_date;
    if (!grouped[ln]) grouped[ln] = {};
    if (!grouped[ln][dt]) grouped[ln][dt] = { mh: 0, kw: 0, cost: 0 };
    grouped[ln][dt].mh   += _getMH_r(r);
    grouped[ln][dt].kw   += Number(r.charge_kw) || 0;
    grouped[ln][dt].cost += Number(r.electric_cost_baht) || 0;
  });

  const fmtN = (v, d=2) => v === 0 ? '-' : v.toLocaleString('th-TH', { minimumFractionDigits: d, maximumFractionDigits: d });
  const fmtDate = (s) => {
    if (!s) return '-';
    const d = new Date(s);
    if (isNaN(d)) return s;
    return d.toLocaleDateString('th-TH', { day:'numeric', month:'short', year:'2-digit' });
  };

  let html = `<div class="space-y-6">`;

  loaderNames.forEach(ln => {
    const byDate = grouped[ln];
    const dates = Object.keys(byDate).sort();
    let totMH = 0, totKW = 0, totCost = 0;
    let bodyRows = '';
    dates.forEach(dt => {
      const { mh, kw, cost } = byDate[dt];
      totMH  += mh;
      totKW  += kw;
      totCost+= cost;
      const kwhr = mh > 0 ? kw / mh : 0;
      bodyRows += `<tr class="border-b border-secondary-50 hover:bg-secondary-50">
        <td class="py-1.5 pr-3">${fmtDate(dt)}</td>
        <td class="py-1.5 pr-3 text-right">${fmtN(mh,2)}</td>
        <td class="py-1.5 pr-3 text-right">${fmtN(kwhr,2)}</td>
        <td class="py-1.5 pr-3 text-right">${fmtN(kw,2)}</td>
        <td class="py-1.5 pr-3 text-right">${fmtN(cost,2)}</td>
      </tr>`;
    });
    const totKWhr = totMH > 0 ? totKW / totMH : 0;
    bodyRows += `<tr class="font-semibold bg-primary-50 border-t-2 border-primary-200">
      <td class="py-2 pr-3">Grand Total</td>
      <td class="py-2 pr-3 text-right">${fmtN(totMH,2)}</td>
      <td class="py-2 pr-3 text-right">${fmtN(totKWhr,2)}</td>
      <td class="py-2 pr-3 text-right">${fmtN(totKW,2)}</td>
      <td class="py-2 pr-3 text-right">${fmtN(totCost,2)}</td>
    </tr>`;

    html += `
      <div class="bg-white rounded-2xl shadow-sm p-5 overflow-x-auto">
        <h4 class="text-base font-semibold text-primary-700 mb-3 flex items-center gap-2">
          <i data-lucide="truck" class="w-4 h-4"></i>${escapeHtml(ln)}
          <span class="text-xs text-secondary-400 font-normal ml-1">${dates.length} วัน</span>
        </h4>
        <table class="w-full text-sm">
          <thead>
            <tr class="text-left text-secondary-400 border-b border-secondary-100 text-xs">
              <th class="py-2 pr-3">วันที่</th>
              <th class="py-2 pr-3 text-right">รวมชั่วโมง</th>
              <th class="py-2 pr-3 text-right">KW/Hr</th>
              <th class="py-2 pr-3 text-right">KW/D</th>
              <th class="py-2 pr-3 text-right">ค่าไฟ(บาท)/วัน</th>
            </tr>
          </thead>
          <tbody>${bodyRows}</tbody>
        </table>
      </div>`;
  });

  html += `</div>`;
  tableBlock.innerHTML = html;
  refreshIcons();
}

function exportLoaderDailyExcel() {
  const allRows = _reportState.rows;
  if (!allRows.length) { showToast('ไม่มีข้อมูลให้ export', 'warning'); return; }
  const loaderNames = [...new Set(allRows.map(r => r.loader_name).filter(Boolean))].sort();
  const grouped = {};
  loaderNames.forEach(ln => { grouped[ln] = {}; });
  allRows.forEach(r => {
    const ln = r.loader_name;
    if (!ln) return;
    const dt = r.work_date;
    if (!grouped[ln]) grouped[ln] = {};
    if (!grouped[ln][dt]) grouped[ln][dt] = { mh: 0, kw: 0, cost: 0 };
    grouped[ln][dt].mh   += _getMH_r(r);
    grouped[ln][dt].kw   += Number(r.charge_kw) || 0;
    grouped[ln][dt].cost += Number(r.electric_cost_baht) || 0;
  });
  const wb = XLSX.utils.book_new();
  loaderNames.forEach(ln => {
    const byDate = grouped[ln];
    const dates = Object.keys(byDate).sort();
    const sheetData = [['วันที่','รวมชั่วโมง','KW/Hr','KW/D','ค่าไฟ(บาท)/วัน']];
    let totMH = 0, totKW = 0, totCost = 0;
    dates.forEach(dt => {
      const { mh, kw, cost } = byDate[dt];
      totMH += mh; totKW += kw; totCost += cost;
      const kwhr = mh > 0 ? kw / mh : 0;
      sheetData.push([dt, mh, kwhr, kw, cost]);
    });
    const totKWhr = totMH > 0 ? totKW / totMH : 0;
    sheetData.push(['Grand Total', totMH, totKWhr, totKW, totCost]);
    const ws = XLSX.utils.aoa_to_sheet(sheetData);
    XLSX.utils.book_append_sheet(wb, ws, ln.slice(0, 31));
  });
  XLSX.writeFile(wb, `loader_daily_${new Date().toISOString().slice(0,10)}.xlsx`);
}

function renderReportTable() {
  const tableBlock = document.getElementById('report-table-block');
  if (!tableBlock) return;
  if (_reportState.type === 'loader_daily') { renderLoaderDailyReport(); return; }
  const rows = applyReportSort(_reportState.rows);
  const cols = _reportState.columns;

  tableBlock.innerHTML = `
    <div class="bg-white rounded-2xl shadow-sm p-5 overflow-x-auto">
      <table class="w-full text-sm" id="report-data-table">
        <thead><tr class="text-left text-secondary-400 border-b border-secondary-100">
          ${cols.map((c, i) => `
            <th draggable="true" data-col-idx="${i}" data-col-key="${c.key}" class="report-th py-2 pr-3 cursor-pointer select-none" title="ลากเพื่อจัดเรียง / คลิกเพื่อ sort">
              <span class="inline-flex items-center gap-1"><i data-lucide="grip-vertical" class="w-3 h-3 text-secondary-300"></i>${escapeHtml(c.label)}
              ${_reportState.sortState.col === c.key ? `<i data-lucide="${_reportState.sortState.dir === 'asc' ? 'arrow-up' : 'arrow-down'}" class="w-3 h-3"></i>` : ''}</span>
            </th>`).join('')}
        </tr></thead>
        <tbody id="report-data-tbody">
          ${rows.length ? rows.map(r => `
            <tr class="border-b border-secondary-50 hover:bg-secondary-50">
              ${cols.map(c => `<td class="py-2 pr-3">${escapeHtml(formatReportCell(r[c.key]))}</td>`).join('')}
            </tr>`).join('') : `<tr><td colspan="${cols.length}" class="py-8 text-center text-secondary-400">ไม่พบข้อมูล</td></tr>`}
        </tbody>
      </table>
      <p class="text-xs text-secondary-400 mt-3">ทั้งหมด ${rows.length} รายการ</p>
    </div>`;
  refreshIcons();
  attachReportTableEvents();
}

function formatReportCell(v) {
  if (v === null || v === undefined) return '-';
  return String(v);
}

function attachReportTableEvents() {
  const ths = qsa('.report-th');
  let dragSrcIdx = null;
  ths.forEach(th => {
    th.addEventListener('click', (e) => {
      // ป้องกัน click trigger ตอนกำลัง drag
      const key = th.getAttribute('data-col-key');
      if (_reportState.sortState.col === key) {
        _reportState.sortState.dir = _reportState.sortState.dir === 'asc' ? 'desc' : 'asc';
      } else {
        _reportState.sortState = { col: key, dir: 'asc' };
      }
      renderReportTable();
    });
    th.addEventListener('dragstart', (e) => {
      dragSrcIdx = Number(th.getAttribute('data-col-idx'));
      e.dataTransfer.effectAllowed = 'move';
    });
    th.addEventListener('dragover', (e) => { e.preventDefault(); });
    th.addEventListener('drop', (e) => {
      e.preventDefault();
      const targetIdx = Number(th.getAttribute('data-col-idx'));
      if (dragSrcIdx === null || dragSrcIdx === targetIdx) return;
      const cols = _reportState.columns;
      const [moved] = cols.splice(dragSrcIdx, 1);
      cols.splice(targetIdx, 0, moved);
      renderReportTable();
    });
  });
}

function csvEscapeField(val) {
  const s = val === null || val === undefined ? '' : String(val);
  if (/[",\n]/.test(s)) {
    return '"' + s.replace(/"/g, '""') + '"';
  }
  return s;
}

function exportReportCsv() {
  if (_reportState.type === 'loader_daily') { exportLoaderDailyExcel(); return; }
  const cols = _reportState.columns;
  const rows = applyReportSort(_reportState.rows);
  if (!rows.length) { showToast('ไม่มีข้อมูลให้ export', 'warning'); return; }
  const headerLine = cols.map(c => csvEscapeField(c.label)).join(',');
  const lines = rows.map(r => cols.map(c => csvEscapeField(r[c.key])).join(','));
  const csvContent = '﻿' + [headerLine].concat(lines).join('\n');
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `report_${_reportState.type}_${new Date().toISOString().slice(0,10)}.csv`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function exportReportExcel() {
  if (_reportState.type === 'loader_daily') { exportLoaderDailyExcel(); return; }
  const cols = _reportState.columns;
  const rows = applyReportSort(_reportState.rows);
  if (!rows.length) { showToast('ไม่มีข้อมูลให้ export', 'warning'); return; }
  const exportRows = rows.map(r => {
    const obj = {};
    cols.forEach(c => { obj[c.label] = r[c.key]; });
    return obj;
  });
  const ws = XLSX.utils.json_to_sheet(exportRows);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Report');
  XLSX.writeFile(wb, `report_${_reportState.type}_${new Date().toISOString().slice(0,10)}.xlsx`);
}

